diffs.replacement:
{
  "name": "BeautyPro-SaaS",
  "description": "专业美业店务管理系统，包含 AI 经营决策支持、高可靠性预约排班及资金流水监控。",
  "requestFramePermissions": [
    "camera"
  ]
}

export type Role = 'admin' | 'staff';

export interface Staff {
  id: string;
  name: string;
  role: string;
  avatar: string;
  password?: string;
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  balance: number;
  createdAt: string;
}

export interface Appointment {
  id: string;
  customerId: string | null;
  customerName: string;
  staffId: string;
  projectName: string;
  startTime: string; // ISO string
  startHour: number; // 8-22
  duration: number;
  status: 'pending' | 'confirmed' | 'completed' | 'cancelled';
}

export interface Transaction {
  id: string;
  type: 'consume' | 'recharge';
  customerId: string | null;
  customerName: string;
  amount: number;
  paymentMethod: 'balance' | 'cash' | 'wechat';
  itemName: string;
  staffId?: string;
  timestamp: string;
}

export interface SystemLog {
  id: string;
  operator: string;
  action: string;
  detail: string;
  timestamp: string;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Root element not found");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeBusinessData = async (data: any) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `分析以下店务经营数据并给出建议：${JSON.stringify(data)}`,
      config: {
        systemInstruction: "你是一个资深的美业经营顾问，请根据提供的数据（流水、预约、会员），分析店内的经营状况（如客单价、技师效率、会员转化），并给出3条具体的优化建议。请使用中文回答，并保持简洁。",
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return "暂时无法进行 AI 分析，请稍后重试。";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles 
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<{role: Role, name: string, id?: string} | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"店长小美","role":"店长","avatar":"1"},{"id":"2","name":"技师阿强","role":"高级技师","avatar":"2"}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- Log Helper ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: Math.random().toString(36).substr(2, 9),
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100)); // Keep last 100 logs
  };

  // --- Statistics ---
  const stats = useMemo(() => {
    const today = new Date().toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === today);
    const income = todayTrans.reduce((sum, t) => t.type === 'recharge' || t.paymentMethod !== 'balance' ? sum + t.amount : sum, 0);
    const balanceCost = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);

    return {
      todayIncome: income,
      todayBalanceCost: balanceCost,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    const last7Days = Array.from({length: 7}, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      return d.toDateString();
    });

    return last7Days.map(date => {
      const dayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === date);
      return {
        name: date.split(' ')[1] + ' ' + date.split(' ')[2],
        income: dayTrans.reduce((sum, t) => t.type === 'recharge' || t.paymentMethod !== 'balance' ? sum + t.amount : sum, 0)
      };
    });
  }, [transactions]);

  // --- Handlers ---
  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    const result = await analyzeBusinessData({ transactions: transactions.slice(-20), customers: customers.length });
    setAiAnalysis(result || "分析失败");
    setIsAnalyzing(false);
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);
    setIsModalOpen(null);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-700 p-12 text-white flex flex-col justify-center">
            <h1 className="text-4xl font-bold mb-4">BeautyPro</h1>
            <p className="text-indigo-100 text-lg">下一代智能美业店务管理系统</p>
            <div className="mt-12 space-y-6">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center"><CheckCircle size={20}/></div>
                <span>智能排班与预约</span>
              </div>
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center"><LayoutDashboard size={20}/></div>
                <span>AI 经营数据看板</span>
              </div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 flex flex-col justify-center bg-white">
            <h2 className="text-2xl font-bold text-slate-800 mb-8">身份验证</h2>
            <div className="space-y-4">
              <button 
                onClick={() => setCurrentUser({ role: 'admin', name: '店长' })}
                className="w-full p-4 border-2 border-slate-100 rounded-2xl flex items-center gap-4 hover:border-indigo-500 transition-all group"
              >
                <div className="w-12 h-12 rounded-xl bg-indigo-50 text-indigo-600 flex items-center justify-center group-hover:bg-indigo-600 group-hover:text-white transition-all"><Settings/></div>
                <div className="text-left">
                  <div className="font-bold text-slate-700">管理端登录</div>
                  <div className="text-sm text-slate-400">查看报表与全店配置</div>
                </div>
              </button>
              <button 
                onClick={() => setCurrentUser({ role: 'staff', name: '张技师', id: '1' })}
                className="w-full p-4 border-2 border-slate-100 rounded-2xl flex items-center gap-4 hover:border-violet-500 transition-all group"
              >
                <div className="w-12 h-12 rounded-xl bg-violet-50 text-violet-600 flex items-center justify-center group-hover:bg-violet-600 group-hover:text-white transition-all"><Calendar/></div>
                <div className="text-left">
                  <div className="font-bold text-slate-700">技师端登录</div>
                  <div className="text-sm text-slate-400">管理个人预约与日程</div>
                </div>
              </button>
            </div>
            <p className="mt-8 text-center text-slate-400 text-sm">默认密码: 123456</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {/* Sidebar */}
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0 transition-all">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white mr-3">
            <Sparkles size={18} />
          </div>
          <span className="hidden md:block font-bold text-slate-800 text-xl tracking-tight">BeautyPro</span>
        </div>

        <nav className="flex-1 py-6 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: '经营看板', adminOnly: true },
            { id: 'appts', icon: Calendar, label: '日程排班', adminOnly: false },
            { id: 'customers', icon: Users, label: '会员管理', adminOnly: false },
            { id: 'finance', icon: History, label: '资金流水', adminOnly: true },
            { id: 'logs', icon: Settings, label: '系统日志', adminOnly: true },
          ].map(item => {
            if (item.adminOnly && currentUser.role !== 'admin') return null;
            return (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center p-3 rounded-xl transition-all ${
                  activeTab === item.id 
                  ? 'bg-indigo-50 text-indigo-700' 
                  : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <item.icon size={20} className="mr-3 shrink-0" />
                <span className="hidden md:block font-medium">{item.label}</span>
              </button>
            );
          })}
        </nav>

        <div className="p-4 border-t">
          <button 
            onClick={() => setCurrentUser(null)}
            className="w-full flex items-center p-3 text-red-500 hover:bg-red-50 rounded-xl transition-all"
          >
            <LogOut size={20} className="mr-3" />
            <span className="hidden md:block font-medium">退出系统</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b flex items-center justify-between px-8 shrink-0">
          <div>
            <h2 className="text-xl font-bold text-slate-800">
              {activeTab === 'dashboard' ? '经营概览' : activeTab === 'appts' ? '日程安排' : '数据管理'}
            </h2>
            <p className="text-sm text-slate-400">欢迎回来, {currentUser.name}</p>
          </div>

          <div className="flex items-center gap-4">
            <button className="p-2 text-slate-400 hover:bg-slate-50 rounded-full relative">
              <Bell size={20} />
              {stats.pendingAppts > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full"></span>}
            </button>
            <button 
              onClick={() => setIsModalOpen('new_appt')}
              className="px-4 py-2 bg-indigo-600 text-white rounded-lg shadow-lg shadow-indigo-200 flex items-center gap-2 text-sm font-semibold hover:bg-indigo-700 transition-all"
            >
              <Plus size={18} /> 新增预约
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scroll">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                  <div className="text-slate-400 text-sm font-medium mb-1">今日营收</div>
                  <div className="text-3xl font-bold text-slate-800">¥ {stats.todayIncome.toLocaleString()}</div>
                  <div className="mt-2 text-xs text-green-500 flex items-center gap-1 font-medium">
                    <CheckCircle size={12}/> 实到资金
                  </div>
                </div>
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                  <div className="text-slate-400 text-sm font-medium mb-1">今日耗卡</div>
                  <div className="text-3xl font-bold text-slate-800">¥ {stats.todayBalanceCost.toLocaleString()}</div>
                  <div className="mt-2 text-xs text-orange-500 flex items-center gap-1 font-medium">
                    <History size={12}/> 余额减少
                  </div>
                </div>
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                  <div className="text-slate-400 text-sm font-medium mb-1">会员总数</div>
                  <div className="text-3xl font-bold text-slate-800">{stats.totalMembers}</div>
                  <div className="mt-2 text-xs text-indigo-500 flex items-center gap-1 font-medium">
                    <Users size={12}/> 档案总计
                  </div>
                </div>
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                  <div className="text-slate-400 text-sm font-medium mb-1">待确认预约</div>
                  <div className="text-3xl font-bold text-pink-600">{stats.pendingAppts}</div>
                  <div className="mt-2 text-xs text-pink-500 flex items-center gap-1 font-medium">
                    <Calendar size={12}/> 需尽快处理
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
                  <div className="flex items-center justify-between mb-8">
                    <h3 className="font-bold text-slate-800 text-lg">营收走势 (7日)</h3>
                  </div>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={chartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                        <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} />
                        <Bar dataKey="income" radius={[6, 6, 0, 0]} barSize={40}>
                          {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={index === 6 ? '#4f46e5' : '#e2e8f0'} />
                          ))}
                        </Bar>
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-gradient-to-br from-slate-900 to-indigo-950 p-8 rounded-3xl text-white shadow-xl relative overflow-hidden">
                  <div className="relative z-10 flex flex-col h-full">
                    <div className="flex items-center gap-2 mb-6">
                      <Sparkles size={20} className="text-indigo-400" />
                      <h3 className="font-bold text-lg">Gemini 经营助手</h3>
                    </div>

                    <div className="flex-1">
                      {isAnalyzing ? (
                        <div className="animate-pulse space-y-4">
                          <div className="h-4 bg-white/10 rounded w-3/4"></div>
                          <div className="h-4 bg-white/10 rounded w-1/2"></div>
                          <div className="h-4 bg-white/10 rounded w-5/6"></div>
                        </div>
                      ) : (
                        <p className="text-slate-300 text-sm leading-relaxed whitespace-pre-wrap">
                          {aiAnalysis || "点击按钮，让 AI 为您分析店内本周的经营效率与会员活跃度。"}
                        </p>
                      )}
                    </div>

                    <button 
                      onClick={handleAiAnalyze}
                      disabled={isAnalyzing}
                      className="mt-8 w-full py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-bold transition-all flex items-center justify-center gap-2"
                    >
                      {isAnalyzing ? "正在深度思考..." : "开始 AI 经营分析"}
                    </button>
                  </div>
                  <div className="absolute -right-20 -bottom-20 w-64 h-64 bg-indigo-500/10 rounded-full blur-3xl"></div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'customers' && (
            <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
              <div className="p-6 border-b flex items-center justify-between">
                <div className="flex items-center bg-slate-50 rounded-xl px-4 py-2 w-96">
                  <Search size={18} className="text-slate-400 mr-2" />
                  <input placeholder="搜索姓名或手机号..." className="bg-transparent border-none outline-none text-sm w-full" />
                </div>
                <button 
                  onClick={() => setIsModalOpen('new_customer')}
                  className="bg-slate-900 text-white px-4 py-2 rounded-xl text-sm font-bold hover:bg-slate-800 flex items-center gap-2"
                >
                  <UserPlus size={18} /> 新增会员
                </button>
              </div>
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                  <tr>
                    <th className="px-8 py-4">会员姓名</th>
                    <th className="px-8 py-4">手机号</th>
                    <th className="px-8 py-4">当前余额</th>
                    <th className="px-8 py-4">创建日期</th>
                    <th className="px-8 py-4 text-right">操作</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {customers.map(c => (
                    <tr key={c.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-8 py-4">
                        <div className="font-bold text-slate-700">{c.name}</div>
                      </td>
                      <td className="px-8 py-4 text-slate-500 font-medium">{c.phone}</td>
                      <td className="px-8 py-4">
                        <span className="text-indigo-600 font-bold tracking-tight">¥ {c.balance.toLocaleString()}</span>
                      </td>
                      <td className="px-8 py-4 text-slate-400 text-sm">
                        {new Date(c.createdAt).toLocaleDateString()}
                      </td>
                      <td className="px-8 py-4 text-right">
                        <button 
                          onClick={() => setIsModalOpen(`recharge_${c.id}`)}
                          className="text-indigo-600 hover:text-indigo-800 font-bold text-sm"
                        >
                          充值
                        </button>
                      </td>
                    </tr>
                  ))}
                  {customers.length === 0 && (
                    <tr>
                      <td colSpan={5} className="py-20 text-center text-slate-400 italic">暂无会员档案</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          )}

          {activeTab === 'appts' && (
             <div className="bg-white rounded-3xl border border-slate-100 shadow-sm flex h-[700px]">
                <div className="w-48 border-r bg-slate-50/50 flex flex-col pt-12">
                   <div className="px-4 mb-4 text-xs font-bold text-slate-400 uppercase">技师列表</div>
                   {staff.map(s => (
                     <div key={s.id} className="p-4 flex flex-col items-center border-b border-slate-100 bg-white mx-2 mb-2 rounded-2xl shadow-sm">
                        <div className="w-12 h-12 bg-indigo-100 rounded-full mb-2 flex items-center justify-center text-indigo-600 font-bold">
                          {s.name[0]}
                        </div>
                        <div className="text-xs font-bold text-slate-700">{s.name}</div>
                        <div className="text-[10px] text-slate-400">{s.role}</div>
                     </div>
                   ))}
                </div>
                <div className="flex-1 overflow-x-auto relative custom-scroll">
                   <div className="sticky top-0 z-20 bg-white border-b flex min-w-[1200px]">
                      {Array.from({length: 15}, (_, i) => (
                        <div key={i} className="flex-1 py-3 text-center text-xs font-bold text-slate-400 border-r border-slate-100">
                          {i + 8}:00
                        </div>
                      ))}
                   </div>
                   <div className="relative min-w-[1200px]">
                      {staff.map(s => (
                        <div key={s.id} className="h-32 border-b border-slate-100 relative group">
                           {Array.from({length: 15}).map((_, i) => (
                             <div key={i} className="absolute h-full border-r border-slate-100" style={{left: `${(i/15)*100}%`, width: `${(1/15)*100}%`}}></div>
                           ))}
                           {appointments.filter(a => a.staffId === s.id).map(a => (
                             <div 
                              key={a.id}
                              className={`absolute top-4 bottom-4 rounded-2xl p-3 shadow-sm border-l-4 overflow-hidden transition-all cursor-pointer hover:scale-[1.02] z-10 ${
                                a.status === 'pending' ? 'bg-amber-50 border-amber-500 text-amber-900' : 
                                a.status === 'confirmed' ? 'bg-indigo-50 border-indigo-500 text-indigo-900' :
                                'bg-green-50 border-green-500 text-green-900 opacity-60'
                              }`}
                              style={{
                                left: `${((a.startHour - 8) / 15) * 100}%`,
                                width: `${(a.duration / 15) * 100}%`
                              }}
                             >
                                <div className="text-xs font-bold truncate">{a.customerName}</div>
                                <div className="text-[10px] opacity-70 truncate">{a.projectName}</div>
                             </div>
                           ))}
                        </div>
                      ))}
                   </div>
                </div>
             </div>
          )}
        </div>
      </main>

      {/* Modals */}
      {isModalOpen === 'new_customer' && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsModalOpen(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-300">
