                  <button key={amt} onClick={() => handleRecharge(isModalOpen.split('_')[1], amt)} className="py-3 border-2 border-slate-100 rounded-xl font-bold text-slate-700 hover:border-indigo-600 hover:text-indigo-600 transition-all">
                    ¥{amt}
                  </button>
