             <div className="flex gap-2">
                <input id="custom-amt" type="number" placeholder="自定义金额" className="flex-1 p-3 bg-slate-50 rounded-xl outline-none" />
                <button 
                  onClick={() => {
                    const amt = parseInt((document.getElementById('custom-amt') as HTMLInputElement).value);
                    if (amt > 0) handleRecharge(isModalOpen.split('_')[1], amt);
                  }}
                  className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold"
                >
                  确认
