             <h3 className="text-2xl font-bold text-slate-800 mb-6">新建预约单</h3>
             <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="col-span-2">
                  <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">选择客户</label>
                  <select id="appt-cust" className="w-full p-4 bg-slate-50 rounded-xl outline-none">
                    {customers.map(c => <option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}
