                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">指定技师</label>
                   <select id="appt-staff" className="w-full p-4 bg-slate-50 rounded-xl outline-none">
                    {staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">项目名称</label>
                   <input id="appt-project" placeholder="如：洗剪吹" className="w-full p-4 bg-slate-50 rounded-xl outline-none" />
                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">开始时间 (点)</label>
                   <input id="appt-hour" type="number" defaultValue={10} min={8} max={21} className="w-full p-4 bg-slate-50 rounded-xl outline-none" />
                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">预计时长 (小时)</label>
                   <input id="appt-duration" type="number" defaultValue={1} min={1} className="w-full p-4 bg-slate-50 rounded-xl outline-none" />
                </div>
             </div>
             <button 
                onClick={() => {
                  const custId = (document.getElementById('appt-cust') as HTMLSelectElement).value;
                  const staffId = (document.getElementById('appt-staff') as HTMLSelectElement).value;
                  const projectName = (document.getElementById('appt-project') as HTMLInputElement).value;
                  const startHour = parseInt((document.getElementById('appt-hour') as HTMLInputElement).value);
                  const duration = parseInt((document.getElementById('appt-duration') as HTMLInputElement).value);

                  const cust = customers.find(c => c.id === custId);
                  const newAppt: Appointment = {
                    id: Math.random().toString(36).substr(2, 9),
                    customerId: custId,
                    customerName: cust?.name || '未知',
                    staffId,
                    projectName,
                    startTime: new Date().toISOString(),
                    startHour,
                    duration,
                    status: 'confirmed'
                  };
                  setAppointments(prev => [...prev, newAppt]);
                  addLog('新建预约', `预约 ${cust?.name} 技师 ${staff.find(s=>s.id===staffId)?.name}`);
                  setIsModalOpen(null);
                }}
                className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-xl shadow-indigo-100"
             >
                提交预约排班
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
