                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">指定技师</label>
                   <select id="appt-staff" className="w-full p-4 bg-slate-50 rounded-xl outline-none border border-slate-100 focus:border-indigo-500 appearance-none text-slate-900">
                    {staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">项目名称</label>
                   <input id="appt-project" placeholder="如：洗剪吹" className="w-full p-4 bg-slate-50 rounded-xl outline-none border border-slate-100 focus:border-indigo-500 text-slate-900" />
                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">开始时间 (点)</label>
                   <input id="appt-hour" type="number" defaultValue={10} min={8} max={21} className="w-full p-4 bg-slate-50 rounded-xl outline-none border border-slate-100 focus:border-indigo-500 text-slate-900" />
                </div>
                <div>
                   <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">预计时长 (小时)</label>
                   <input id="appt-duration" type="number" defaultValue={1} min={1} className="w-full p-4 bg-slate-50 rounded-xl outline-none border border-slate-100 focus:border-indigo-500 text-slate-900" />
                </div>
             </div>
             <button 
                onClick={() => {
                  const custId = (document.getElementById('appt-cust') as HTMLSelectElement).value;
                  const staffId = (document.getElementById('appt-staff') as HTMLSelectElement).value;
                  const projectName = (document.getElementById('appt-project') as HTMLInputElement).value;
                  const startHourStr = (document.getElementById('appt-hour') as HTMLInputElement).value;
                  const durationStr = (document.getElementById('appt-duration') as HTMLInputElement).value;

                  if (!custId || !projectName || !startHourStr || !durationStr) return;

                  const startHour = parseInt(startHourStr);
                  const duration = parseInt(durationStr);
                  const cust = customers.find(c => c.id === custId);
                  const newAppt: Appointment = {
                    id: Math.random().toString(36).substr(2, 9),
                    customerId: custId,
                    customerName: cust?.name || '未知',
                    staffId,
                    projectName,
                    startTime: new Date().toISOString(),
                    startHour,
                    duration,
                    status: 'confirmed'
                  };
                  setAppointments(prev => [...prev, newAppt]);
                  addLog('新建预约', `预约 ${cust?.name} 技师 ${staff.find(s=>s.id===staffId)?.name}`);
                  setIsModalOpen(null);
                }}
                className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-xl shadow-indigo-100 transition-all hover:bg-indigo-700 active:scale-95 mt-4"
             >
                提交预约排班
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type Role = 'admin' | 'staff';

export interface Staff {
  id: string;
  name: string;
  role: string;
  password?: string;
  avatar: string;
  permissions: string[];
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  balance: number;
  remarks: string;
  createdAt: string;
}

export interface Appointment {
  id: string;
  customerId: string | null;
  customerName: string;
  staffId: string;
  projectName: string;
  startTime: string; // ISO string
  startHour: number; // 8-22
  duration: number;
  status: 'pending' | 'confirmed' | 'completed' | 'cancelled';
}

export interface Transaction {
  id: string;
  type: 'consume' | 'recharge';
  customerId: string | null;
  customerName: string;
  amount: number;
  paymentMethod: 'balance' | 'cash' | 'wechat' | 'alipay';
  itemName: string;
  staffId?: string;
  timestamp: string;
}

export interface SystemLog {
  id: string;
  operator: string;
  action: string;
  detail: string;
  timestamp: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- Helpers ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.includes(searchTerm) || c.phone.includes(searchTerm)
    );
  }, [customers, searchTerm]);

  const stats = useMemo(() => {
    const todayStr = new Date().toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const income = todayTrans.reduce((sum, t) => t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);

    return {
      todayIncome: income,
      todayConsumption: consumption,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'confirmed').length
    };
  }, [transactions, customers, appointments]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) {
      setCurrentUser(found);
      addLog('登录系统', '账号密码校验成功');
    } else {
      alert('账号或密码错误');
    }
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员钱包充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash') => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) {
      alert('余额不足');
      return;
    }

    if (method === 'balance') {
      setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    }

    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'consume',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: method,
      itemName,
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('客户消费', `${cust?.name} 消费 ${itemName} ¥${amount}`);
    setIsModalOpen(null);
  };

  const deleteAppt = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    addLog('取消预约', `删除单号: ${id}`);
    setSelectedAppt(null);
  };

  const handleAddStaff = (e: React.FormEvent) => {
    e.preventDefault();
    const name = (document.getElementById('s-name') as HTMLInputElement).value;
    const pass = (document.getElementById('s-pass') as HTMLInputElement).value;
    const role = (document.getElementById('s-role') as HTMLSelectElement).value;
    if (!name || !pass) return;

    setStaff(prev => [...prev, {
      id: `S-${Date.now()}`,
      name,
      password: pass,
      role,
      avatar: name[0].toUpperCase(),
      permissions: role === '管理员' ? ['all'] : ['view']
    }]);
    addLog('增加员工', `新技师: ${name}`);
    setIsModalOpen(null);
  };

  // --- Monthly Calendar Logic ---
  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const days = [];
    for (let i = 0; i < firstDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(new Date(year, month, i));
    return days;
  }, [selectedDate]);

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能店务，从此触手可及。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 预约排班</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 会员档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 权限管控</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 flex flex-col justify-center bg-white">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">内部登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <div>
                <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">账号</label>
                <input id="login-user" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none transition-all text-slate-900" placeholder="admin" />
              </div>
              <div>
                <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">密码</label>
                <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none transition-all text-slate-900" placeholder="••••••" />
              </div>
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold hover:shadow-xl hover:bg-black transition-all">确认进入系统</button>
            </form>
            <div className="mt-8 text-center text-slate-400 text-xs">默认账号: admin 密码: admin</div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0">
        <div className="h-20 flex items-center px-6 border-b shrink-0">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 tracking-tighter uppercase">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: '概览看板', admin: false },
            { id: 'appts', icon: Calendar, label: '日程预约', admin: false },
            { id: 'customers', icon: Users, label: '会员中心', admin: false },
            { id: 'finance', icon: History, label: '财务报表', admin: false },
            { id: 'staff', icon: ShieldCheck, label: '技师管理', admin: true },
            { id: 'logs', icon: Settings, label: '审计日志', admin: true },
          ].map(item => {
            if (item.admin && currentUser.role !== '管理员') return null;
            return (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`w-full flex items-center p-4 rounded-2xl transition-all ${
                  activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <item.icon size={22} className="mr-3" />
                <span className="hidden md:block font-bold">{item.label}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl transition-all font-bold">
            <LogOut size={22} className="mr-3" /> <span className="hidden md:block">安全退出</span>
          </button>
        </div>
      </aside>

      {/* Main content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-4">
            <h2 className="text-xl font-black text-slate-800 uppercase tracking-wide">
              {activeTab === 'dashboard' ? 'Overview' : activeTab.toUpperCase()}
            </h2>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex flex-col text-right">
              <span className="text-sm font-bold text-slate-800">{currentUser.name}</span>
              <span className="text-[10px] text-slate-400 font-bold uppercase">{currentUser.role}</span>
            </div>
            <button onClick={() => setIsModalOpen('new_appt')} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2">
              <Plus size={18} /> <span className="hidden sm:inline">新预约</span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scroll">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                  <p className="text-slate-400 text-xs font-black uppercase mb-1">今日实收</p>
                  <h3 className="text-3xl font-black text-slate-900">¥{stats.todayIncome.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1 text-[10px] text-green-500 font-bold uppercase"><ArrowUpCircle size={14}/> 现金/微信收入</div>
                </div>
                <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                  <p className="text-slate-400 text-xs font-black uppercase mb-1">今日耗卡</p>
                  <h3 className="text-3xl font-black text-slate-900">¥{stats.todayConsumption.toLocaleString()}</h3>
                  <div className="mt-4 flex items-center gap-1 text-[10px] text-indigo-500 font-bold uppercase"><CreditCard size={14}/> 会员余额消耗</div>
                </div>
                <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                  <p className="text-slate-400 text-xs font-black uppercase mb-1">活跃会员</p>
                  <h3 className="text-3xl font-black text-slate-900">{stats.totalMembers}</h3>
                  <div className="mt-4 flex items-center gap-1 text-[10px] text-slate-400 font-bold uppercase"><Users size={14}/> 累计注册量</div>
                </div>
                <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                  <p className="text-slate-400 text-xs font-black uppercase mb-1">待确认订单</p>
                  <h3 className="text-3xl font-black text-pink-600">{stats.pendingAppts}</h3>
                  <div className="mt-4 flex items-center gap-1 text-[10px] text-pink-500 font-bold uppercase"><Bell size={14}/> 需尽快回访</div>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                   <h4 className="font-black text-slate-800 mb-8 uppercase tracking-widest text-sm">营收趋势</h4>
                   <div className="h-80">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={chartData}>
                          <CartesianGrid vertical={false} stroke="#f1f5f9" strokeDasharray="3 3" />
                          <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} dy={10} />
                          <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                          <Tooltip contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}} />
                          <Bar dataKey="income" radius={[10, 10, 0, 0]} barSize={40}>
                            {chartData.map((_, i) => <Cell key={`c-${i}`} fill={i === 6 ? '#4f46e5' : '#e2e8f0'} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                   </div>
                </div>
                <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="relative z-10 h-full flex flex-col">
                    <div className="flex items-center gap-3 mb-6"><Sparkles className="text-indigo-400" /> <h3 className="font-bold">AI 经营洞察</h3></div>
                    <div className="flex-1 text-slate-300 text-sm leading-relaxed whitespace-pre-wrap">
                      {isAnalyzing ? "深度扫描流水中..." : aiAnalysis || "我是您的经营助手。点击下方按钮，我将分析您店内的技师效率与会员留存，并提供针对性的营销策略。"}
                    </div>
                    <button onClick={handleAiAnalyze} disabled={isAnalyzing} className="mt-8 py-4 bg-indigo-600 hover:bg-indigo-500 transition-all rounded-2xl font-black uppercase text-xs tracking-widest">
                      {isAnalyzing ? "正在深度思考..." : "开启 AI 经营诊断"}
                    </button>
                  </div>
                  <div className="absolute -right-20 -bottom-20 w-64 h-64 bg-indigo-500/20 rounded-full blur-[100px]"></div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'appts' && (
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full animate-in slide-in-from-bottom-8 duration-500">
              <div className="p-6 border-b flex items-center justify-between shrink-0">
                <div className="flex items-center gap-2 bg-slate-100 p-1.5 rounded-xl">
                  <button onClick={() => setViewMode('day')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'day' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>日排班表</button>
                  <button onClick={() => setViewMode('month')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'month' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>月日历视图</button>
                </div>
                <div className="flex items-center gap-4">
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() - 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronLeft size={20}/></button>
                  <span className="font-black text-slate-800">{selectedDate.getFullYear()}年 {selectedDate.getMonth() + 1}月</span>
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() + 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronRight size={20}/></button>
                </div>
              </div>

              <div className="flex-1 overflow-auto custom-scroll p-6">
                {viewMode === 'day' ? (
                  <div className="flex h-full min-w-[1200px]">
                    <div className="w-48 sticky left-0 bg-white z-20 pr-4 space-y-3">
                      <div className="text-[10px] font-black text-slate-400 uppercase pl-4 mb-4">技师排班</div>
                      {staff.map(s => (
                        <div key={s.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-3">
                          <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center font-bold text-indigo-600 shadow-sm">{s.avatar}</div>
                          <div><div className="text-xs font-bold text-slate-800">{s.name}</div><div className="text-[10px] text-slate-400">{s.role}</div></div>
                        </div>
                      ))}
                    </div>
                    <div className="flex-1 relative">
                      <div className="flex sticky top-0 bg-white z-10 border-b mb-4">
                        {Array.from({length: 15}, (_, i) => <div key={i} className="flex-1 py-2 text-center text-[10px] font-bold text-slate-400 border-r">{i + 8}:00</div>)}
                      </div>
                      {staff.map(s => (
                        <div key={s.id} className="h-28 border-b border-slate-50 relative group">
                          {Array.from({length: 15}).map((_, i) => <div key={i} className="absolute h-full border-r border-slate-100/50" style={{left: `${(i/15)*100}%`}}></div>)}
                          {appointments.filter(a => a.staffId === s.id && new Date(a.startTime).toDateString() === selectedDate.toDateString()).map(a => (
                            <div 
                              key={a.id} 
