                        <div className="text-xs font-bold text-indigo-500 uppercase tracking-widest mb-4">{s.role}</div>
                        <div className="pt-6 border-t border-slate-50 flex items-center justify-between text-[10px] font-black text-slate-400 uppercase">
                          <span>状态: 在职</span>
                          <span>权限: {s.permissions.join(',')}</span>
                        </div>
                     </div>
                   ))}
                </div>
             </div>
          )}

          {/* FINANCE and LOGS sections would follow similar logic as before, just enhanced UI */}
          {(activeTab === 'finance' || activeTab === 'logs') && (
             <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in duration-500">
                <table className="w-full text-left">
                   <thead className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      <tr>
                        {activeTab === 'finance' ? (
                          <>
                            <th className="px-8 py-5">单号/类型</th>
                            <th className="px-8 py-5">关联人</th>
                            <th className="px-8 py-5">金额</th>
                            <th className="px-8 py-5">方式</th>
                            <th className="px-8 py-5 text-right">时间</th>
                          </>
                        ) : (
                          <>
                            <th className="px-8 py-5">操作人</th>
                            <th className="px-8 py-5">动作</th>
                            <th className="px-8 py-5">详情</th>
                            <th className="px-8 py-5 text-right">时间</th>
                          </>
                        )}
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100 text-sm">
                      {activeTab === 'finance' ? transactions.map(t => (
                        <tr key={t.id}>
                           <td className="px-8 py-5">
                              <div className="text-[10px] font-mono text-slate-400 mb-1">{t.id}</div>
                              <span className={`text-[10px] font-black px-2 py-0.5 rounded-md uppercase ${t.type === 'recharge' ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'}`}>{t.type === 'recharge' ? '充值' : '消费'}</span>
                           </td>
                           <td className="px-8 py-5 font-bold text-slate-800">{t.customerName}</td>
                           <td className={`px-8 py-5 font-black ${t.type === 'recharge' ? 'text-green-600' : 'text-slate-800'}`}>{t.type === 'recharge' ? '+' : '-'} ¥{t.amount.toLocaleString()}</td>
                           <td className="px-8 py-5 text-slate-400">{t.paymentMethod}</td>
                           <td className="px-8 py-5 text-right text-[10px] text-slate-400">{new Date(t.timestamp).toLocaleString()}</td>
                        </tr>
                      )) : logs.map(l => (
                        <tr key={l.id}>
                          <td className="px-8 py-5 font-bold text-slate-800">{l.operator}</td>
                          <td className="px-8 py-5 text-indigo-600 font-black uppercase text-xs">{l.action}</td>
                          <td className="px-8 py-5 text-slate-500 text-xs">{l.detail}</td>
                          <td className="px-8 py-5 text-right text-[10px] text-slate-400">{new Date(l.timestamp).toLocaleString()}</td>
                        </tr>
                      ))}
                   </tbody>
                </table>
             </div>
          )}
        </div>
      </main>

      {/* Modals - Common Container */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md" onClick={() => setIsModalOpen(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-lg rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-300 overflow-hidden">
            {isModalOpen === 'new_customer' && (
              <div className="space-y-6">
                <h3 className="text-3xl font-black text-slate-800 mb-8">新会员建档</h3>
                <input id="nc-name" placeholder="客户姓名" className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-transparent focus:border-indigo-500 text-slate-900" />
                <input id="nc-phone" placeholder="手机号" className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-transparent focus:border-indigo-500 text-slate-900" />
                <textarea id="nc-remarks" placeholder="客户备注（如皮肤状况、服务偏好）" className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-transparent focus:border-indigo-500 h-32 text-slate-900" />
                <button 
                  onClick={() => {
                    const n = (document.getElementById('nc-name') as HTMLInputElement).value;
                    const p = (document.getElementById('nc-phone') as HTMLInputElement).value;
                    const r = (document.getElementById('nc-remarks') as HTMLTextAreaElement).value;
                    if (!n || !p) return;
                    setCustomers(prev => [...prev, { id: `C-${Date.now()}`, name: n, phone: p, balance: 0, remarks: r, createdAt: new Date().toISOString() }]);
                    addLog('新建会员', `档案已生成: ${n}`);
                    setIsModalOpen(null);
                  }}
                  className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-black transition-all"
                >保存档案</button>
              </div>
            )}

            {isModalOpen?.startsWith('consume_') && (
              <div className="space-y-6">
                <h3 className="text-3xl font-black text-slate-800 mb-8">消费核销</h3>
                <input id="cons-item" placeholder="服务项目/商品名称" className="w-full p-5 bg-slate-50 rounded-2xl outline-none text-slate-900" />
                <input id="cons-amt" type="number" placeholder="消费金额" className="w-full p-5 bg-slate-50 rounded-2xl outline-none text-slate-900" />
                <div className="flex gap-4">
                  <button onClick={() => {
                    const i = (document.getElementById('cons-item') as HTMLInputElement).value;
                    const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                    if (i && a > 0) handleConsume(isModalOpen.split('_')[1], a, i, 'balance');
                  }} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase">余额扣减</button>
                  <button onClick={() => {
                    const i = (document.getElementById('cons-item') as HTMLInputElement).value;
                    const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                    if (i && a > 0) handleConsume(isModalOpen.split('_')[1], a, i, 'cash');
                  }} className="flex-1 py-5 bg-slate-200 text-slate-800 rounded-2xl font-black text-xs uppercase">现金支付</button>
                </div>
              </div>
            )}

            {isModalOpen === 'new_staff' && (
              <form onSubmit={handleAddStaff} className="space-y-6">
                <h3 className="text-3xl font-black text-slate-800 mb-8">新增团队成员</h3>
                <input id="s-name" placeholder="技师账号/姓名" required className="w-full p-5 bg-slate-50 rounded-2xl outline-none text-slate-900" />
                <input id="s-pass" type="password" placeholder="设置初始密码" required className="w-full p-5 bg-slate-50 rounded-2xl outline-none text-slate-900" />
                <select id="s-role" className="w-full p-5 bg-slate-50 rounded-2xl outline-none text-slate-900">
                  <option>技师</option>
                  <option>管理员</option>
                  <option>前台</option>
                </select>
                <button type="submit" className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest">确认添加</button>
              </form>
            )}

            {isModalOpen === 'new_appt' && (
              <div className="space-y-6">
                 <h3 className="text-3xl font-black text-slate-800 mb-8">预约排班单</h3>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="col-span-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">选择客户</label>
                       <select id="apt-c" className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900">
                          {customers.map(c => <option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}
                       </select>
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">指定技师</label>
                       <select id="apt-s" className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900">
                          {staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                       </select>
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">项目</label>
                       <input id="apt-p" placeholder="如：烫染" className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900" />
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">开始小时 (8-22)</label>
                       <input id="apt-h" type="number" defaultValue={10} className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900" />
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-2 block">时长 (小时)</label>
                       <input id="apt-d" type="number" defaultValue={1} className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900" />
                    </div>
                 </div>
                 <button onClick={() => {
                   const cId = (document.getElementById('apt-c') as HTMLSelectElement).value;
                   const sId = (document.getElementById('apt-s') as HTMLSelectElement).value;
                   const prj = (document.getElementById('apt-p') as HTMLInputElement).value;
                   const hour = parseInt((document.getElementById('apt-h') as HTMLInputElement).value);
                   const dur = parseInt((document.getElementById('apt-d') as HTMLInputElement).value);

                   const c = customers.find(x => x.id === cId);
                   const newA: Appointment = {
                     id: `APT-${Date.now()}`,
                     customerId: cId,
                     customerName: c?.name || '未知',
                     staffId: sId,
                     projectName: prj,
                     startTime: selectedDate.toISOString(),
                     startHour: hour,
                     duration: dur,
                     status: 'confirmed'
                   };
                   setAppointments(prev => [...prev, newA]);
                   addLog('新建预约', `${c?.name} 预约了 ${prj}`);
                   setIsModalOpen(null);
                 }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest mt-4">提交预约</button>
              </div>
            )}

            {isModalOpen?.startsWith('recharge_') && (
              <div className="space-y-6">
                <h3 className="text-3xl font-black text-slate-800 mb-2">钱包充值</h3>
                <p className="text-slate-400 text-xs mb-8 uppercase font-bold tracking-widest">请录入实收到账金额</p>
                <div className="grid grid-cols-2 gap-4">
                  {[300, 500, 1000, 2000, 5000, 10000].map(v => (
                    <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v)} className="py-4 border-2 border-slate-100 rounded-2xl font-black text-slate-700 hover:border-indigo-600 hover:text-indigo-600 transition-all">¥{v}</button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Appointment Detail Modal */}
      {selectedAppt && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md" onClick={() => setSelectedAppt(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl overflow-hidden">
             <div className="flex justify-between items-start mb-8">
               <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600"><Info size={24}/></div>
               <button onClick={() => setSelectedAppt(null)} className="text-slate-300 hover:text-slate-500"><X size={24}/></button>
             </div>
             <h4 className="text-2xl font-black text-slate-800 mb-2">{selectedAppt.customerName}</h4>
             <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest mb-8">{selectedAppt.projectName}</p>

             <div className="space-y-4 mb-10">
                <div className="flex justify-between text-xs font-bold"><span className="text-slate-400 uppercase">服务技师</span><span className="text-slate-800">{staff.find(s=>s.id===selectedAppt.staffId)?.name}</span></div>
                <div className="flex justify-between text-xs font-bold"><span className="text-slate-400 uppercase">预约日期</span><span className="text-slate-800">{new Date(selectedAppt.startTime).toLocaleDateString()}</span></div>
                <div className="flex justify-between text-xs font-bold"><span className="text-slate-400 uppercase">时段</span><span className="text-slate-800">{selectedAppt.startHour}:00 - {selectedAppt.startHour + selectedAppt.duration}:00</span></div>
             </div>

             <button onClick={() => deleteAppt(selectedAppt.id)} className="w-full py-4 bg-red-50 text-red-600 rounded-2xl font-black text-xs uppercase hover:bg-red-600 hover:text-white transition-all">取消并删除预约</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type Role = 'admin' | 'staff';

export interface Staff {
  id: string;
  name: string;
  role: string;
  password?: string;
  avatar: string;
  permissions: string[];
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  balance: number;
  remarks: string;
  createdAt: string;
}

export interface Appointment {
  id: string;
  customerId: string | null;
  customerName: string;
  staffId: string;
  projectName: string;
  startTime: string; // ISO string
  startHour: number; // 8-22
  duration: number;
  status: 'pending' | 'confirmed' | 'completed' | 'cancelled';
}

export interface Transaction {
  id: string;
  type: 'consume' | 'recharge';
  customerId: string | null;
  customerName: string;
  amount: number;
  paymentMethod: 'balance' | 'cash' | 'wechat' | 'alipay';
  itemName: string;
  staffId?: string;
  timestamp: string;
}

export interface SystemLog {
  id: string;
  operator: string;
  action: string;
  detail: string;
  timestamp: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  // Finance Filters
  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- Helpers ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.includes(searchTerm) || c.phone.includes(searchTerm)
    );
  }, [customers, searchTerm]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      return tDate >= start && tDate <= end;
    });
  }, [transactions, financeStartDate, financeEndDate]);

  const stats = useMemo(() => {
    const todayStr = new Date().toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const income = todayTrans.reduce((sum, t) => t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);

    return {
      todayIncome: income,
      todayConsumption: consumption,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return {
        name: `${d.getMonth() + 1}/${d.getDate()}`,
        income
      };
    });
  }, [transactions]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) {
      setCurrentUser(found);
      addLog('登录系统', '账号密码校验成功');
    } else {
      alert('账号或密码错误');
    }
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员钱包充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) {
      alert('余额不足');
      return;
    }

    if (method === 'balance') {
      setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    }

    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'consume',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: method,
      itemName,
      timestamp: new Date().toISOString()
    };

    if (apptId) {
      setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    }

    setTransactions(prev => [trans, ...prev]);
    addLog('客户结算', `${cust?.name} 消费 ${itemName} ¥${amount}`);
    setIsModalOpen(null);
    setSelectedAppt(null);
  };

  const updateApptStatus = (id: string, status: Appointment['status']) => {
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a));
    addLog('更新预约', `预约 ${id} 状态更新为 ${status}`);
    if (status === 'completed') {
      const appt = appointments.find(a => a.id === id);
      if (appt) {
        setIsModalOpen(`consume_${appt.customerId}`);
      }
    }
  };

  const deleteAppt = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    addLog('删除预约', `删除单号: ${id}`);
    setSelectedAppt(null);
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const summary = {
        stats,
        totalCustomers: customers.length,
        totalTransactions: transactions.length,
        recentTransactions: transactions.slice(0, 10),
        appointments: appointments.slice(0, 10)
      };
      const result = await analyzeBusinessData(summary);
      setAiAnalysis(result);
    } catch (error) {
      setAiAnalysis("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Calendar Helpers ---
  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const days = [];
    for (let i = 0; i < firstDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(new Date(year, month, i));
    return days;
  }, [selectedDate]);

  const onMonthDayClick = (date: Date) => {
    setSelectedDate(new Date(date));
    setViewMode('day');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能美业，一站式经营解决方案。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 智能排班</div>
