                     addLog('新建预约', `已提交待确认预约`);
                     setIsModalOpen(null);
                   }
                 }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest mt-4 shadow-xl">提交预约申请</button>
              </div>
            )}

            {isModalOpen?.startsWith('recharge_') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800 mb-8">会员充值</h3>
                <div className="grid grid-cols-2 gap-4">
                  {[500, 1000, 2000, 5000].map(v => (
                    <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v)} className="py-5 border-2 border-slate-100 rounded-2xl font-black text-slate-700 hover:border-indigo-600 hover:text-indigo-600 transition-all">¥{v}</button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Appointment Detail Sidebar/Modal */}
      {selectedAppt && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md" onClick={() => setSelectedAppt(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-start mb-8">
               <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600"><Info size={24}/></div>
               <button onClick={() => setSelectedAppt(null)} className="text-slate-300 hover:text-slate-500 transition-all"><X size={24}/></button>
             </div>
             <div className="mb-8">
               <h4 className="text-2xl font-black text-slate-800">{selectedAppt.customerName}</h4>
               <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest">{selectedAppt.projectName}</p>
             </div>

             <div className="space-y-6 mb-10">
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">服务进度</span><span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : selectedAppt.status === 'confirmed' ? 'bg-indigo-100 text-indigo-600' : 'bg-green-100 text-green-600'}`}>{selectedAppt.status}</span></div>
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">预约时间</span><span className="text-xs font-bold text-slate-800">{selectedAppt.startHour}:00 ({selectedAppt.duration}h)</span></div>
             </div>

             <div className="space-y-3">
                {selectedAppt.status === 'pending' && (
                  <button onClick={() => updateApptStatus(selectedAppt.id, 'confirmed')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2"><CheckCircle size={16}/> 确认预约并锁位</button>
                )}
                {selectedAppt.status === 'confirmed' && (
                  <button onClick={() => updateApptStatus(selectedAppt.id, 'completed')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg flex items-center justify-center gap-2"><PlayCircle size={16}/> 服务完成并结算</button>
                )}
                {selectedAppt.status === 'completed' && (
                   <div className="p-4 bg-green-50 text-green-600 text-center rounded-2xl text-[10px] font-black uppercase tracking-widest">服务已核销结算</div>
                )}
                <button onClick={() => deleteAppt(selectedAppt.id)} className="w-full py-4 text-red-400 hover:text-red-600 font-bold text-xs uppercase tracking-widest transition-all">作废预约单</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  // Finance Filters
  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- Helpers ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.includes(searchTerm) || c.phone.includes(searchTerm)
    );
  }, [customers, searchTerm]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      return tDate >= start && tDate <= end;
    });
  }, [transactions, financeStartDate, financeEndDate]);

  const stats = useMemo(() => {
    const todayStr = new Date().toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const income = todayTrans.reduce((sum, t) => t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);

    return {
      todayIncome: income,
      todayConsumption: consumption,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return {
        name: `${d.getMonth() + 1}/${d.getDate()}`,
        income
      };
    });
  }, [transactions]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) {
      setCurrentUser(found);
      addLog('登录系统', '账号密码校验成功');
    } else {
      alert('账号或密码错误');
    }
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员钱包充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) {
      alert('余额不足');
      return;
    }

    if (method === 'balance') {
      setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    }

    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'consume',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: method,
      itemName,
      timestamp: new Date().toISOString()
    };

    if (apptId) {
      setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    }

    setTransactions(prev => [trans, ...prev]);
    addLog('客户结算', `${cust?.name} 消费 ${itemName} ¥${amount}`);
    setIsModalOpen(null);
    setSelectedAppt(null);
  };

  const updateApptStatus = (id: string, status: Appointment['status']) => {
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a));
    addLog('更新预约', `预约 ${id} 状态更新为 ${status}`);

    if (status === 'completed') {
      const appt = appointments.find(a => a.id === id);
      if (appt) {
        setIsModalOpen(`consume_${appt.customerId}`);
      }
    } else {
      // For status like 'confirmed', close the detail view
      setSelectedAppt(null);
    }
  };

  const deleteAppt = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    addLog('删除预约', `删除单号: ${id}`);
    setSelectedAppt(null);
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const summary = {
        stats,
        totalCustomers: customers.length,
        totalTransactions: transactions.length,
        recentTransactions: transactions.slice(0, 10),
        appointments: appointments.slice(0, 10)
      };
      const result = await analyzeBusinessData(summary);
      setAiAnalysis(result);
    } catch (error) {
      setAiAnalysis("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // --- Calendar Helpers ---
  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const days = [];
    for (let i = 0; i < firstDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(new Date(year, month, i));
    return days;
  }, [selectedDate]);

  const onMonthDayClick = (date: Date) => {
    setSelectedDate(new Date(date));
    setViewMode('day');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能美业，一站式经营解决方案。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 智能排班</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 会员档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 财务审计</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 flex flex-col justify-center bg-white">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">管理员/员工登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <input id="login-user" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="账号 (admin)" />
              <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="密码 (admin)" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold">登录系统</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      {/* Sidebar */}
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 tracking-tighter uppercase">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: '概览', admin: false },
            { id: 'appts', icon: Calendar, label: '排班/预约', admin: false },
            { id: 'customers', icon: Users, label: '会员管理', admin: false },
            { id: 'finance', icon: History, label: '财务报表', admin: false },
            { id: 'staff', icon: ShieldCheck, label: '员工管理', admin: true },
            { id: 'logs', icon: Settings, label: '操作日志', admin: true },
          ].map(item => {
            if (item.admin && currentUser.role !== '管理员') return null;
            return (
              <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center p-4 rounded-2xl transition-all ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
                <item.icon size={22} className="mr-3" /> <span className="hidden md:block font-bold">{item.label}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all"><LogOut size={22} className="mr-3" /> <span className="hidden md:block">退出</span></button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-widest">
            {activeTab === 'staff' ? '员工管理' : activeTab.toUpperCase()}
          </h2>
          <div className="flex items-center gap-6">
            <div className="text-right"><div className="text-sm font-bold text-slate-800">{currentUser.name}</div><div className="text-[10px] text-slate-400 font-bold uppercase">{currentUser.role}</div></div>
            <button onClick={() => setIsModalOpen('new_appt')} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg hover:bg-indigo-700 transition-all flex items-center gap-2"><Plus size={18} /> <span>新预约</span></button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scroll">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                  { label: '今日实收', val: `¥${stats.todayIncome}`, icon: ArrowUpCircle, color: 'text-green-500' },
                  { label: '今日耗卡', val: `¥${stats.todayConsumption}`, icon: CreditCard, color: 'text-indigo-500' },
                  { label: '会员总数', val: stats.totalMembers, icon: Users, color: 'text-slate-500' },
                  { label: '待处理预约', val: stats.pendingAppts, icon: Bell, color: 'text-pink-500' }
                ].map((s, i) => (
                  <div key={i} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                    <p className="text-slate-400 text-[10px] font-black uppercase mb-1">{s.label}</p>
                    <h3 className="text-3xl font-black text-slate-900">{s.val}</h3>
                    <div className={`mt-4 flex items-center gap-1 text-[10px] ${s.color} font-bold uppercase`}><s.icon size={14}/> 实时监控</div>
                  </div>
                ))}
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                   <h4 className="font-black text-slate-800 mb-8 uppercase tracking-widest text-sm">营收趋势</h4>
                   <div className="h-80"><ResponsiveContainer><BarChart data={chartData}><CartesianGrid vertical={false} strokeDasharray="3 3"/><XAxis dataKey="name"/><YAxis/><Tooltip/><Bar dataKey="income" radius={[10, 10, 0, 0]} fill="#4f46e5" barSize={35}/></BarChart></ResponsiveContainer></div>
                </div>
                <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="relative z-10 h-full flex flex-col">
                    <div className="flex items-center gap-3 mb-6"><Sparkles className="text-indigo-400" /> <h3 className="font-bold">AI 顾问建议</h3></div>
                    <div className="flex-1 text-slate-300 text-sm leading-relaxed whitespace-pre-wrap">{isAnalyzing ? "正在生成经营策略..." : aiAnalysis || "点击下方按钮分析本周运营效率及客源分布。"}</div>
                    <button onClick={handleAiAnalyze} disabled={isAnalyzing} className="mt-8 py-4 bg-indigo-600 hover:bg-indigo-500 transition-all rounded-2xl font-black uppercase text-xs tracking-widest">生成经营诊断</button>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'appts' && (
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full animate-in slide-in-from-bottom-8">
              <div className="p-6 border-b flex items-center justify-between">
                <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setViewMode('day')} className={`px-4 py-2 rounded-lg text-sm font-bold ${viewMode === 'day' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>日视图</button>
                  <button onClick={() => setViewMode('month')} className={`px-4 py-2 rounded-lg text-sm font-bold ${viewMode === 'month' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>月历</button>
                </div>
                <div className="flex items-center gap-4">
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() - 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronLeft/></button>
                  <span className="font-black text-slate-800 uppercase tracking-tighter">{selectedDate.getFullYear()}年 {selectedDate.getMonth() + 1}月</span>
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() + 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronRight/></button>
                </div>
              </div>

              <div className="flex-1 overflow-auto custom-scroll p-6">
                {viewMode === 'day' ? (
                  <div className="min-w-[1300px]">
                    {/* Time Axis Header */}
                    <div className="flex ml-48 border-b mb-4">
                      {Array.from({length: 15}, (_, i) => (
                        <div key={i} className="flex-1 py-2 text-center text-[10px] font-black text-slate-400 uppercase border-r last:border-r-0">
                          {i + 8}:00
                        </div>
                      ))}
                    </div>
                    {/* Staff Rows */}
                    {staff.map(s => (
                      <div key={s.id} className="flex items-center h-28 border-b border-slate-50 group">
                        <div className="w-48 sticky left-0 bg-white z-10 pr-6 flex items-center gap-3">
                          <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center font-black text-indigo-600 border border-indigo-100">{s.avatar}</div>
                          <div><div className="text-xs font-bold text-slate-800">{s.name}</div><div className="text-[10px] text-slate-400">{s.role}</div></div>
                        </div>
                        <div className="flex-1 relative h-full flex">
                          {Array.from({length: 15}).map((_, i) => <div key={i} className="flex-1 border-r border-slate-100/50 h-full"></div>)}
                          {appointments.filter(a => a.staffId === s.id && new Date(a.startTime).toDateString() === selectedDate.toDateString()).map(a => (
                            <div 
                              key={a.id} 
                              onClick={() => setSelectedAppt(a)}
                              className={`absolute top-4 bottom-4 rounded-xl p-3 shadow-sm cursor-pointer hover:scale-[1.02] transition-all border-l-4 overflow-hidden ${
                                a.status === 'pending' ? 'bg-amber-50 border-amber-500' : a.status === 'confirmed' ? 'bg-indigo-50 border-indigo-500' : 'bg-green-50 border-green-500'
                              }`}
                              style={{ left: `${((a.startHour - 8) / 15) * 100}%`, width: `${(a.duration / 15) * 100}%` }}
                            >
