                          {staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                       </select>
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">服务项目</label>
                       <input id="apt-p" placeholder="洗剪吹" className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900 border border-slate-100" />
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">预约小时 (8-22)</label>
                       <input id="apt-h" type="number" defaultValue={10} className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900 border border-slate-100" />
                    </div>
                    <div>
                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">预计耗时 (h)</label>
                       <input id="apt-d" type="number" defaultValue={1} className="w-full p-4 bg-slate-50 rounded-xl outline-none text-slate-900 border border-slate-100" />
                    </div>
                 </div>
                 <button onClick={() => {
                   let cId = "";
                   let cName = "";
                   if (isQuickAddCustomer) {
                     const n = (document.getElementById('apt-nc-name') as HTMLInputElement).value;
                     const p = (document.getElementById('apt-nc-phone') as HTMLInputElement).value;
                     if (!n || !p) { alert("请填写客户资料"); return; }
                     cId = `C-${Date.now()}`;
                     cName = n;
                     setCustomers(prev => [...prev, { id: cId, name: n, phone: p, balance: 0, remarks: '快速建档', createdAt: new Date().toISOString() }]);
                     addLog('快速建档', `预约流程中新建客户: ${n}`);
                   } else {
                     cId = (document.getElementById('apt-c') as HTMLSelectElement).value;
                     cName = customers.find(x => x.id === cId)?.name || '';
                   }

                   const sId = (document.getElementById('apt-s') as HTMLSelectElement).value;
                   const prj = (document.getElementById('apt-p') as HTMLInputElement).value;
                   const hour = parseInt((document.getElementById('apt-h') as HTMLInputElement).value);
                   const dur = parseInt((document.getElementById('apt-d') as HTMLInputElement).value);

                   if (cId && sId && prj) {
                     setAppointments(prev => [...prev, { 
                       id: `APT-${Date.now()}`, 
                       customerId: cId, 
                       customerName: cName, 
                       staffId: sId, 
                       projectName: prj, 
                       startTime: selectedDate.toISOString(), 
                       startHour: hour, 
                       duration: dur, 
                       status: 'pending' 
                     }]);
                     addLog('新建预约', `预约 ${prj} 已提交，待员工确认`);
                     setIsModalOpen(null);
                   }
                 }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest mt-4 shadow-xl">完成预约登记</button>
              </div>
            )}

            {isModalOpen?.startsWith('recharge_') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800 mb-8">账户资金注入</h3>
                <div className="grid grid-cols-2 gap-4">
                  {[500, 1000, 2000, 5000].map(v => (
                    <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v, isModalOpen.endsWith('_fromConsume'))} className="py-5 border-2 border-slate-100 rounded-2xl font-black text-slate-700 hover:border-indigo-600 hover:text-indigo-600 transition-all">¥{v}</button>
                  ))}
                </div>
                <div className="pt-4 border-t border-slate-100">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-2">手动输入金额</p>
                  <div className="flex gap-2">
                    <input id="custom-recharge" type="number" placeholder="¥ 0.00" className="flex-1 p-4 bg-slate-50 rounded-2xl outline-none text-slate-900 border border-slate-100" />
                    <button onClick={() => {
                      const val = parseInt((document.getElementById('custom-recharge') as HTMLInputElement).value);
                      if (val > 0) handleRecharge(isModalOpen.split('_')[1], val, isModalOpen.endsWith('_fromConsume'));
                    }} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">充值确认</button>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Appointment Detail Drawer/Modal */}
      {selectedAppt && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md" onClick={() => setSelectedAppt(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-start mb-8">
               <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600"><Info size={24}/></div>
               <button onClick={() => setSelectedAppt(null)} className="text-slate-300 hover:text-slate-500 transition-all"><X size={24}/></button>
             </div>
             <div className="mb-8">
               <h4 className="text-2xl font-black text-slate-800">{selectedAppt.customerName}</h4>
               <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest">{selectedAppt.projectName}</p>
             </div>

             <div className="space-y-6 mb-10">
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">预约状态</span><span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : selectedAppt.status === 'confirmed' ? 'bg-indigo-100 text-indigo-600' : 'bg-green-100 text-green-600'}`}>{selectedAppt.status === 'pending' ? '等待技师确认' : selectedAppt.status}</span></div>
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">服务时间</span><span className="text-xs font-bold text-slate-800">{selectedAppt.startHour}:00 ({selectedAppt.duration}h)</span></div>
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">执行员工</span><span className="text-xs font-bold text-slate-800">{staff.find(s=>s.id === selectedAppt.staffId)?.name}</span></div>
             </div>

             <div className="space-y-3">
                {selectedAppt.status === 'pending' && (
                  <button onClick={() => updateApptStatus(selectedAppt.id, 'confirmed')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2 transition-all hover:bg-indigo-700"><CheckCircle size={16}/> 确认并受理预约</button>
                )}
                {selectedAppt.status === 'confirmed' && (
                  <button onClick={() => updateApptStatus(selectedAppt.id, 'completed')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg flex items-center justify-center gap-2 transition-all hover:bg-black"><PlayCircle size={16}/> 服务完成结账</button>
                )}
                {selectedAppt.status === 'completed' && (
                   <div className="p-4 bg-green-50 text-green-600 text-center rounded-2xl text-[10px] font-black uppercase tracking-widest">已完成历史订单</div>
                )}
                <button onClick={() => deleteAppt(selectedAppt.id)} className="w-full py-4 text-red-400 hover:text-red-600 font-bold text-xs uppercase tracking-widest transition-all">作废预约信息</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  // Finance & Log Filters
  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [logStartDate, setLogStartDate] = useState('');
  const [logEndDate, setLogEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [viewingCustomerProfile, setViewingCustomerProfile] = useState<Customer | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- Helpers ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.includes(searchTerm) || c.phone.includes(searchTerm)
    );
  }, [customers, searchTerm]);

  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const currentMonth = today.getMonth();
    const currentYear = today.getFullYear();

    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const monthTrans = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const todayConsumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);

    // Monthly revenue: Actual money coming in (Cash Consume + Recharge)
    const monthlyRevenue = monthTrans.reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    return {
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayTotal: cashIncome + rechargeIncome,
      todayConsumption: todayConsumption,
      monthlyRevenue: monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length
    };
  }, [transactions, customers, appointments]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      return tDate >= start && tDate <= end;
    });
  }, [transactions, financeStartDate, financeEndDate]);

  const financeSummary = useMemo(() => {
    const cash = filteredTransactions.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const recharge = filteredTransactions.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consume = filteredTransactions.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);
    return { cash, recharge, consume };
  }, [filteredTransactions]);

  const filteredLogs = useMemo(() => {
    return logs.filter(l => {
      const lDate = new Date(l.timestamp).getTime();
      const start = logStartDate ? new Date(logStartDate).getTime() : 0;
      const end = logEndDate ? new Date(logEndDate).setHours(23, 59, 59, 999) : Infinity;
      return lDate >= start && lDate <= end;
    });
  }, [logs, logStartDate, logEndDate]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return {
        name: `${d.getMonth() + 1}/${d.getDate()}`,
        income
      };
    });
  }, [transactions]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) {
      setCurrentUser(found);
      addLog('登录系统', '账号密码校验成功');
    } else {
      alert('账号或密码错误');
    }
  };

  const handleRecharge = (custId: string, amount: number, returnToConsume: boolean = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员钱包充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);

    if (returnToConsume) {
      setIsModalOpen(`consume_${custId}`);
    } else {
      setIsModalOpen(null);
    }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) {
      alert('余额不足，请先充值');
      return;
    }

    if (method === 'balance') {
      setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    }

    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'consume',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: method,
      itemName,
      timestamp: new Date().toISOString()
    };

    if (apptId) {
      setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    }

    setTransactions(prev => [trans, ...prev]);
    addLog('客户结算', `${cust?.name} 消费 ${itemName} ¥${amount}`);
    setIsModalOpen(null);
    setSelectedAppt(null);
  };

  const updateApptStatus = (id: string, status: Appointment['status']) => {
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a));
    addLog('更新预约', `预约 ${id} 状态更新为 ${status}`);

    if (status === 'completed') {
      const appt = appointments.find(a => a.id === id);
      if (appt) {
        setIsModalOpen(`consume_${appt.customerId}`);
      }
    } else if (status === 'confirmed') {
      setSelectedAppt(null);
      setIsModalOpen(null);
    }
  };

  const deleteAppt = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    addLog('删除预约', `删除单号: ${id}`);
    setSelectedAppt(null);
    setIsModalOpen(null);
  };

  const exportTransactionsToCSV = () => {
    const headers = ["单号", "类型", "客户", "项目", "金额", "时间"];
    const csvContent = [
      headers.join(","),
      ...filteredTransactions.map(t => [
        t.id,
        t.type === 'recharge' ? '充值' : '结算',
        t.customerName,
        t.itemName,
        t.amount,
        new Date(t.timestamp).toLocaleString()
      ].join(","))
    ].join("\n");

    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `财务报表_${new Date().toLocaleDateString()}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const summary = {
        stats,
        totalCustomers: customers.length,
        totalTransactions: transactions.length,
        recentTransactions: transactions.slice(0, 10),
        appointments: appointments.slice(0, 10)
      };
      const result = await analyzeBusinessData(summary);
      setAiAnalysis(result);
    } catch (error) {
      setAiAnalysis("分析失败，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const onMonthDayClick = (date: Date) => {
    setSelectedDate(new Date(date));
    setViewMode('day');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能美业，一站式经营解决方案。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 智能排班</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 会员档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 财务审计</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 flex flex-col justify-center bg-white">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">管理员/员工登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <input id="login-user" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="账号 (admin)" />
              <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="密码 (admin)" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold transition-all hover:bg-black">进入工作台</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      {/* Sidebar */}
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0 transition-all duration-300">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3 shadow-lg shadow-indigo-100"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 tracking-tighter uppercase">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: '概览', admin: false },
            { id: 'appts', icon: Calendar, label: '排班/预约', admin: false },
            { id: 'customers', icon: Users, label: '会员管理', admin: false },
            { id: 'finance', icon: History, label: '财务报表', admin: false },
            { id: 'staff', icon: ShieldCheck, label: '员工管理', admin: true },
            { id: 'logs', icon: Settings, label: '操作日志', admin: true },
          ].map(item => {
            if (item.admin && currentUser.role !== '管理员') return null;
            return (
              <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center p-4 rounded-2xl transition-all ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
                <item.icon size={22} className="mr-3" /> <span className="hidden md:block font-bold">{item.label}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all"><LogOut size={22} className="mr-3" /> <span className="hidden md:block">退出系统</span></button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-widest">
            {activeTab === 'staff' ? '员工管理' : activeTab === 'logs' ? '操作日志' : activeTab.toUpperCase()}
          </h2>
          <div className="flex items-center gap-6">
            <div className="relative group cursor-pointer" onClick={() => setActiveTab('appts')}>
               {stats.pendingAppts > 0 && <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
               <Bell className="text-slate-400 group-hover:text-indigo-600 transition-all" size={20} />
