                    <h3 className="text-3xl font-black text-slate-900">{s.val}</h3>
                    <div className={`mt-4 text-[9px] ${s.color} font-bold uppercase bg-slate-50 py-1 px-2 rounded-lg inline-block`}>{s.desc}</div>
                  </div>
