              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                   <div className="flex justify-between items-center mb-8">
                      <h4 className="font-black text-slate-800 uppercase tracking-widest text-sm">营收趋势分析 (过去7天)</h4>
                   </div>
                   <div className="h-80"><ResponsiveContainer><BarChart data={chartData}><CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f1f5f9"/><XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 700}}/><YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 700}}/><Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}/><Bar dataKey="income" radius={[10, 10, 0, 0]} fill="#4f46e5" barSize={35}/></BarChart></ResponsiveContainer></div>
                </div>
                <div className="bg-slate-900 rounded-[2.5rem] p-8 text-white flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="relative z-10 h-full flex flex-col">
                    <div className="flex items-center gap-3 mb-6"><Sparkles className="text-indigo-400" /> <h3 className="font-bold">AI 顾问决策支持</h3></div>
                    <div className="flex-1 text-slate-300 text-sm leading-relaxed whitespace-pre-wrap">{isAnalyzing ? "正在进行深度多维数据分析..." : aiAnalysis || "我是您的 BeautyPro 助手。点击下方按钮，我将为您深度剖析店内运营效能，并根据实时预约与财务数据为您制定增长策略。"}</div>
                    <button onClick={handleAiAnalyze} disabled={isAnalyzing} className="mt-8 py-4 bg-indigo-600 hover:bg-indigo-500 transition-all rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-500/20">一键生成经营诊断</button>
                  </div>
                  <div className="absolute -right-20 -bottom-20 w-80 h-80 bg-indigo-500/10 rounded-full blur-[100px]"></div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'appts' && (
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full animate-in slide-in-from-bottom-8">
              <div className="p-6 border-b flex items-center justify-between">
                <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setViewMode('day')} className={`px-4 py-2 rounded-lg text-sm font-bold ${viewMode === 'day' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>日排班表</button>
                  <button onClick={() => setViewMode('month')} className={`px-4 py-2 rounded-lg text-sm font-bold ${viewMode === 'month' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>月历总览</button>
                </div>
                <div className="flex items-center gap-4 text-xs font-black text-slate-400 uppercase">
                  <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-amber-400"></span> 待技师确认</div>
                  <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-indigo-500"></span> 服务中</div>
                </div>
                <div className="flex items-center gap-4">
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() - 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronLeft/></button>
                  <span className="font-black text-slate-800 uppercase tracking-tighter">{selectedDate.getFullYear()}年 {selectedDate.getMonth() + 1}月</span>
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() + 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronRight/></button>
