                  <button onClick={() => setIsModalOpen(`recharge_${isModalOpen.split('_')[1]}_fromConsume`)} className="text-indigo-600 text-[10px] font-black uppercase flex items-center gap-1 hover:underline"><PlusCircle size={14}/> 充值余额</button>
                </div>
                <div className="p-6 bg-indigo-50 rounded-[2rem]">
