                  <button onClick={() => {
                    const i = (document.getElementById('cons-item') as HTMLInputElement).value;
                    const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                    if (i && a >= 0) handleConsume(isModalOpen.split('_')[1], a, i, 'cash', selectedAppt?.id);
