                </div>
              </div>
            )}

            {isModalOpen === 'new_appt' && (
              <div className="space-y-6">
                 <h3 className="text-2xl font-black text-slate-800">创建预约排班</h3>
                 <div className="flex gap-2 p-1 bg-slate-100 rounded-xl mb-4">
                    <button onClick={() => setIsQuickAddCustomer(false)} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${!isQuickAddCustomer ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>选择既有会员</button>
                    <button onClick={() => setIsQuickAddCustomer(true)} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${isQuickAddCustomer ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>极速新建</button>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="col-span-2">
                       {isQuickAddCustomer ? (
                         <div className="flex gap-2"><input id="apt-nc-name" placeholder="客户姓名" className="flex-1 p-4 bg-slate-50 rounded-xl border" /><input id="apt-nc-phone" placeholder="手机号" className="flex-1 p-4 bg-slate-50 rounded-xl border" /></div>
                       ) : (
                         <select id="apt-c" className="w-full p-4 bg-slate-50 rounded-xl border border-slate-100">{customers.map(c => <option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}</select>
                       )}
                    </div>
                    <div><label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">指派技师</label><select id="apt-s" className="w-full p-4 bg-slate-50 rounded-xl border">{staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select></div>
                    <div><label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">服务项目</label><input id="apt-p" placeholder="洗剪吹等" className="w-full p-4 bg-slate-50 rounded-xl border" /></div>
                    <div><label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">时段 (8-22)</label><input id="apt-h" type="number" defaultValue={10} className="w-full p-4 bg-slate-50 rounded-xl border" /></div>
                    <div><label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">时长 (h)</label><input id="apt-d" type="number" defaultValue={1} className="w-full p-4 bg-slate-50 rounded-xl border" /></div>
                 </div>
                 <button onClick={() => {
                   let cId = ""; let cName = "";
                   if (isQuickAddCustomer) {
                     const n = (document.getElementById('apt-nc-name') as HTMLInputElement).value; const p = (document.getElementById('apt-nc-phone') as HTMLInputElement).value;
                     if (!n || !p) { alert("请补全信息"); return; }
                     cId = `C-${Date.now()}`; cName = n;
                     setCustomers(prev => [...prev, { id: cId, name: n, phone: p, balance: 0, remarks: '预约时极速建档', createdAt: new Date().toISOString() }]);
                   } else { cId = (document.getElementById('apt-c') as HTMLSelectElement).value; cName = customers.find(x => x.id === cId)?.name || ''; }
                   const sId = (document.getElementById('apt-s') as HTMLSelectElement).value; const prj = (document.getElementById('apt-p') as HTMLInputElement).value;
                   const hour = parseInt((document.getElementById('apt-h') as HTMLInputElement).value); const dur = parseInt((document.getElementById('apt-d') as HTMLInputElement).value);
                   if (cId && sId && prj) { setAppointments(prev => [...prev, { id: `APT-${Date.now()}`, customerId: cId, customerName: cName, staffId: sId, projectName: prj, startTime: selectedDate.toISOString(), startHour: hour, duration: dur, status: 'pending' }]); setIsModalOpen(null); }
                 }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs mt-4 shadow-xl transition-all">提交预约录入</button>
              </div>
            )}

            {isModalOpen?.startsWith('recharge_') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800 mb-8">账户资金充值</h3>
                <div className="grid grid-cols-2 gap-4">
                  {[500, 1000, 2000, 5000].map(v => (<button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v, isModalOpen.endsWith('_fromConsume'))} className="py-5 border-2 border-slate-100 rounded-2xl font-black text-slate-700 hover:border-indigo-600 hover:text-indigo-600 transition-all">¥{v}</button>))}
                </div>
                <div className="pt-4 border-t border-slate-100">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-2">手动输入金额</p>
                  <div className="flex gap-2">
                    <input id="custom-recharge" type="number" placeholder="¥ 0.00" className="flex-1 p-4 bg-slate-50 rounded-2xl border" />
                    <button onClick={() => { const val = parseInt((document.getElementById('custom-recharge') as HTMLInputElement).value); if (val > 0) handleRecharge(isModalOpen.split('_')[1], val, isModalOpen.endsWith('_fromConsume')); }} className="px-6 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">确认</button>
                  </div>
                </div>
              </div>
            )}

            {(isModalOpen === 'new_staff' || isModalOpen === 'edit_staff') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800">{isModalOpen === 'edit_staff' ? '编辑员工' : '新成员登记'}</h3>
                <input id="st-name" placeholder="姓名" defaultValue={editingTarget?.name || ""} className="w-full p-4 bg-slate-50 rounded-2xl border transition-all" />
                <input id="st-role" placeholder="职位" defaultValue={editingTarget?.role || ""} className="w-full p-4 bg-slate-50 rounded-2xl border transition-all" />
                <input id="st-pass" type="password" placeholder="设置登录密码" className="w-full p-4 bg-slate-50 rounded-2xl border transition-all" />
                <button onClick={() => {
                   const n = (document.getElementById('st-name') as HTMLInputElement).value; const r = (document.getElementById('st-role') as HTMLInputElement).value;
                   const p = (document.getElementById('st-pass') as HTMLInputElement).value;
                   if (n && r) {
                     if (isModalOpen === 'edit_staff' && editingTarget) { setStaff(prev => prev.map(s => s.id === editingTarget.id ? { ...s, name: n, role: r, password: p || s.password } : s)); } 
                     else if (p) { setStaff(prev => [...prev, { id: `S-${Date.now()}`, name: n, role: r, password: p, avatar: n[0].toUpperCase(), permissions: ['view'] }]); }
                     setIsModalOpen(null); setEditingTarget(null);
                   }
                }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs shadow-xl transition-all">确认保存</button>
              </div>
            )}
          </div>
        </div>
      )}

      {selectedAppt && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md" onClick={() => setSelectedAppt(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-start mb-8"><div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600"><Info size={24}/></div><button onClick={() => setSelectedAppt(null)} className="text-slate-300 hover:text-slate-500 transition-all"><X size={24}/></button></div>
             <div className="mb-8"><h4 className="text-2xl font-black text-slate-800">{selectedAppt.customerName}</h4><p className="text-xs font-bold text-indigo-500 uppercase tracking-widest">{selectedAppt.projectName}</p></div>
             <div className="space-y-6 mb-10">
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase">状态</span><span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : selectedAppt.status === 'confirmed' ? 'bg-indigo-100 text-indigo-600' : 'bg-green-100 text-green-600'}`}>{selectedAppt.status === 'pending' ? '等待确认' : selectedAppt.status}</span></div>
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase">时间段</span><span className="text-xs font-bold text-slate-800">{selectedAppt.startHour}:00 ({selectedAppt.duration}h)</span></div>
             </div>
             <div className="space-y-3">
                {selectedAppt.status === 'pending' && ( <button onClick={() => updateApptStatus(selectedAppt.id, 'confirmed')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-indigo-100 flex items-center justify-center gap-2"><CheckCircle size={16}/> 确认核位并受理</button> )}
                {selectedAppt.status === 'confirmed' && ( <button onClick={() => updateApptStatus(selectedAppt.id, 'completed')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase shadow-lg flex items-center justify-center gap-2 transition-all hover:bg-black"><PlayCircle size={16}/> 服务完成并结算</button> )}
                <button onClick={() => deleteAppt(selectedAppt.id)} className="w-full py-4 text-red-400 hover:text-red-600 font-bold text-xs uppercase transition-all">作废预约</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  // Finance & Log Filters
  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [logStartDate, setLogStartDate] = useState('');
  const [logEndDate, setLogEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [viewingCustomerProfile, setViewingCustomerProfile] = useState<Customer | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- Helpers ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.includes(searchTerm) || c.phone.includes(searchTerm)
    );
  }, [customers, searchTerm]);

  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const currentMonth = today.getMonth();
    const currentYear = today.getFullYear();

    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const monthTrans = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const todayConsumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);

    // 实收 = 现金消费 + 充值收入
    const todayTotalActual = cashIncome + rechargeIncome;

    // 本月应收 (实收累计)
    const monthlyRevenue = monthTrans.reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    const todayApptsCount = appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length;

    return {
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayTotal: todayTotalActual,
      todayConsumption: todayConsumption,
      monthlyRevenue: monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts: todayApptsCount
    };
  }, [transactions, customers, appointments]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      return tDate >= start && tDate <= end;
    });
  }, [transactions, financeStartDate, financeEndDate]);

  const financeSummary = useMemo(() => {
    const cash = filteredTransactions.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const recharge = filteredTransactions.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consume = filteredTransactions.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);
    return { cash, recharge, consume, totalActual: cash + recharge };
  }, [filteredTransactions]);

  // Fix: Added filteredLogs memo to handle log filtering by date
  const filteredLogs = useMemo(() => {
    return logs.filter(l => {
      const lDate = new Date(l.timestamp).getTime();
      const start = logStartDate ? new Date(logStartDate).getTime() : 0;
      const end = logEndDate ? new Date(logEndDate).setHours(23, 59, 59, 999) : Infinity;
      return lDate >= start && lDate <= end;
    });
  }, [logs, logStartDate, logEndDate]);

  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDay = new Date(year, month, 1);
    const startingDay = firstDay.getDay(); 
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const days: (Date | null)[] = [];
    for (let i = 0; i < startingDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(new Date(year, month, i));
    return days;
  }, [selectedDate]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return {
        name: `${d.getMonth() + 1}/${d.getDate()}`,
        income
      };
    });
  }, [transactions]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) {
      setCurrentUser(found);
      addLog('登录系统', '账号密码校验成功');
    } else {
      alert('账号或密码错误');
    }
  };

  const handleRecharge = (custId: string, amount: number, returnToConsume: boolean = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员钱包充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);
    if (returnToConsume) {
      setIsModalOpen(`consume_${custId}`);
    } else {
      setIsModalOpen(null);
    }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) {
      alert('余额不足，请先充值');
      return;
    }
    if (method === 'balance') {
      setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    }
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'consume',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: method,
      itemName,
      timestamp: new Date().toISOString()
    };
    if (apptId) {
      setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    }
    setTransactions(prev => [trans, ...prev]);
    addLog('客户结算', `${cust?.name} 消费 ${itemName} ¥${amount}`);
    setIsModalOpen(null);
    setSelectedAppt(null);
  };

  const updateApptStatus = (id: string, status: Appointment['status']) => {
    setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a));
    addLog('更新预约', `预约 ${id} 状态更新为 ${status}`);
    if (status === 'completed') {
      const appt = appointments.find(a => a.id === id);
      if (appt) setIsModalOpen(`consume_${appt.customerId}`);
    } else if (status === 'confirmed') {
      setSelectedAppt(null);
      setIsModalOpen(null);
    }
  };

  const deleteAppt = (id: string) => {
    setAppointments(prev => prev.filter(a => a.id !== id));
    addLog('删除预约', `删除单号: ${id}`);
    setSelectedAppt(null);
    setIsModalOpen(null);
  };

  const exportTransactionsToCSV = () => {
    const headers = ["单号", "类型", "客户", "项目", "金额", "时间"];
    const csvContent = [
      headers.join(","),
      ...filteredTransactions.map(t => [t.id, t.type === 'recharge' ? '充值' : '结算', t.customerName, t.itemName, t.amount, new Date(t.timestamp).toLocaleString()].join(","))
    ].join("\n");
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `财务明细_${new Date().toLocaleDateString()}.csv`);
    link.click();
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const summary = { stats, customers: customers.length, transCount: transactions.length };
      const result = await analyzeBusinessData(summary);
      setAiAnalysis(result);
    } catch (e) {
      setAiAnalysis("分析服务暂不可用。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const onMonthDayClick = (date: Date) => {
    setSelectedDate(new Date(date));
    setViewMode('day');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
