                  </div>
                </div>
              </div>
            )}

            {(isModalOpen === 'new_staff' || isModalOpen === 'edit_staff') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800">{isModalOpen === 'edit_staff' ? '修改员工' : '入职登记'}</h3>
                <div className="space-y-4">
                  <input id="st-name" placeholder="姓名" defaultValue={editingTarget?.name || ""} className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500" />
                  <input id="st-role" placeholder="职位 (发型师/美容师等)" defaultValue={editingTarget?.role || ""} className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500" />
                  <input id="st-pass" type="password" placeholder="设置初始登录密码" className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500" />
                </div>
                <button onClick={() => {
                   const n = (document.getElementById('st-name') as HTMLInputElement).value; const r = (document.getElementById('st-role') as HTMLInputElement).value;
                   const p = (document.getElementById('st-pass') as HTMLInputElement).value;
                   if (n && r) {
                     if (isModalOpen === 'edit_staff' && editingTarget) { setStaff(prev => prev.map(s => s.id === editingTarget.id ? { ...s, name: n, role: r, password: p || s.password } : s)); } 
