  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const App: React.FC = () => {
  // --- State ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  // Finance & Log Filters
  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');
  const [logStartDate, setLogStartDate] = useState('');
  const [logEndDate, setLogEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [viewingCustomerProfile, setViewingCustomerProfile] = useState<Customer | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- Persistence ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // 点击外部关闭通知
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- Helpers ---
  const addLog = (action: string, detail: string) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString()
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.includes(searchTerm) || c.phone.includes(searchTerm)
    );
  }, [customers, searchTerm]);

  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const currentMonth = today.getMonth();
    const currentYear = today.getFullYear();

    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const monthTrans = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    });

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const todayConsumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);
    const todayTotalActual = cashIncome + rechargeIncome;
    const monthlyRevenue = monthTrans.reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
    const todayApptsCount = appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length;

    return {
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayTotal: todayTotalActual,
      todayConsumption: todayConsumption,
      monthlyRevenue: monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts: todayApptsCount,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;

      const typeMatches = 
        activeFinanceFilter === 'all' ? true :
        activeFinanceFilter === 'recharge' ? t.type === 'recharge' :
        activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') :
        activeFinanceFilter === 'cash' ? (t.type === 'consume' && t.paymentMethod !== 'balance') : true;

      return tDate >= start && tDate <= end && typeMatches;
    });
  }, [transactions, financeStartDate, financeEndDate, activeFinanceFilter]);

  const financeSummary = useMemo(() => {
    const baseTrans = transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      return tDate >= start && tDate <= end;
    });

    const cash = baseTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const recharge = baseTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consume = baseTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod === 'balance') ? sum + t.amount : sum, 0);
    return { cash, recharge, consume, totalActual: cash + recharge };
  }, [transactions, financeStartDate, financeEndDate]);

  const filteredLogs = useMemo(() => {
    return logs.filter(l => {
      const lDate = new Date(l.timestamp).getTime();
      const start = logStartDate ? new Date(logStartDate).getTime() : 0;
      const end = logEndDate ? new Date(logEndDate).setHours(23, 59, 59, 999) : Infinity;
      return lDate >= start && lDate <= end;
    });
  }, [logs, logStartDate, logEndDate]);

  const calendarDays = useMemo(() => {
    const year = selectedDate.getFullYear();
    const month = selectedDate.getMonth();
    const firstDay = new Date(year, month, 1);
    const startingDay = firstDay.getDay(); 
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const days: (Date | null)[] = [];
    for (let i = 0; i < startingDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(new Date(year, month, i));
    return days;
  }, [selectedDate]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return {
        name: `${d.getMonth() + 1}/${d.getDate()}`,
        income
      };
    });
  }, [transactions]);

  // --- Actions ---
  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) {
      setCurrentUser(found);
      addLog('登录系统', '账号密码校验成功');
    } else { alert('账号或密码错误'); }
  };

  const handleRecharge = (custId: string, amount: number, returnToConsume: boolean = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'recharge',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: 'cash',
      itemName: '会员钱包充值',
      timestamp: new Date().toISOString()
    };
    setTransactions(prev => [trans, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`);
    if (returnToConsume) { 
      const currentModalId = isModalOpen || '';
      const parts = currentModalId.split('_');
      const apptId = parts.length > 3 ? parts[3] : ''; 
      setIsModalOpen(`consume_${custId}${apptId ? `_appt_${apptId}` : ''}`); 
    } else { 
      setIsModalOpen(null); 
    }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) {
      alert('余额不足，请先充值');
      return;
    }
    if (method === 'balance') {
      setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    }
    const trans: Transaction = {
      id: `TRX-${Date.now()}`,
      type: 'consume',
      customerId: custId,
      customerName: cust?.name || '未知',
      amount,
      paymentMethod: method,
      itemName,
      timestamp: new Date().toISOString()
    };

    if (apptId) {
      setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    }

    setTransactions(prev => [trans, ...prev]);
    addLog('客户结算', `${cust?.name} 消费 ${itemName} ¥${amount}`);

    setIsModalOpen(null);
    setSelectedAppt(null);
    setPrefillData(null);
  };

  const updateApptStatus = (id: string, status: Appointment['status']) => {
    if (status !== 'completed') {
      setAppointments(prev => prev.map(a => a.id === id ? { ...a, status } : a));
      addLog('更新预约', `预约 ${id} 状态更新为 ${status}`);
    }

    if (status === 'completed') {
      const appt = appointments.find(a => a.id === id);
      if (appt) {
        setSelectedAppt(null);
        setTimeout(() => {
          setIsModalOpen(`consume_${appt.customerId}_appt_${appt.id}`);
        }, 50);
      }
    } else if (status === 'confirmed') {
      setSelectedAppt(null);
      setIsModalOpen(null);
    }
  };

  const deleteAppt = (id: string) => {
    if (confirm('确定要作废这条预约吗？')) {
      setAppointments(prev => prev.filter(a => a.id !== id));
      addLog('删除预约', `删除了预约单: ${id}`);
      setSelectedAppt(null);
    }
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const data = {
        transactions: transactions.slice(0, 50),
        appointments: appointments.slice(0, 50),
        customersCount: customers.length,
        revenue: stats.monthlyRevenue,
        pendingAppts: stats.pendingAppts
      };
      const result = await analyzeBusinessData(data);
      setAiAnalysis(result);
      addLog('AI 诊断', '生成了经营建议报告');
    } catch (e) {
      console.error(e);
      setAiAnalysis("AI 分析遇到了点问题，请稍后重试。");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const navigateToFinance = (filter: typeof activeFinanceFilter) => {
    setActiveTab('finance');
    setActiveFinanceFilter(filter);
    setFinanceStartDate('');
    setFinanceEndDate('');
  };

  const exportTransactionsToCSV = () => {
    const headers = ["单号", "业务", "支付方式", "客户", "项目", "金额", "时间"];
    const csvContent = [
      headers.join(","),
      ...filteredTransactions.map(t => [
        t.id, 
        t.type === 'recharge' ? '充值' : '结算', 
        t.paymentMethod === 'balance' ? '余额' : '现金',
        t.customerName, 
        t.itemName, 
        t.amount, 
        new Date(t.timestamp).toLocaleString()
      ].join(","))
    ].join("\n");
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `财务对账单_${new Date().toLocaleDateString()}.csv`);
    link.click();
  };

  const onMonthDayClick = (date: Date) => {
    setSelectedDate(new Date(date));
    setViewMode('day');
  };

  const handleScheduleClick = (e: React.MouseEvent<HTMLDivElement>, staffId: string) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const ratio = x / rect.width;
    const hour = Math.floor(ratio * 15) + 8; 

    setPrefillData({ staffId, hour });
    setIsModalOpen('new_appt');
    setIsQuickAddCustomer(false);
  };

  const handleNotificationClick = (appt: Appointment) => {
    setActiveTab('appts');
    setSelectedDate(new Date(appt.startTime));
    setSelectedAppt(appt);
    setShowNotifications(false);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能店务，数据驱动经营。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 预约提醒</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 消费档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 财务对账</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 bg-white flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">管理员登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <input id="login-user" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="账号 (admin)" />
              <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="密码 (admin)" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold transition-all hover:bg-black">立即进入</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0 transition-all">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3 shadow-lg shadow-indigo-100"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 tracking-tighter uppercase">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: '概览', admin: false },
            { id: 'appts', icon: Calendar, label: '排班/预约', admin: false },
            { id: 'customers', icon: Users, label: '会员管理', admin: false },
            { id: 'finance', icon: History, label: '财务报表', admin: false },
            { id: 'staff', icon: ShieldCheck, label: '员工管理', admin: true },
            { id: 'logs', icon: Settings, label: '操作日志', admin: true },
          ].map(item => {
            if (item.admin && currentUser.role !== '管理员') return null;
            return (
              <button key={item.id} onClick={() => { setActiveTab(item.id); if(item.id === 'finance') setActiveFinanceFilter('all'); }} className={`w-full flex items-center p-4 rounded-2xl transition-all ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
                <item.icon size={22} className="mr-3" /> <span className="hidden md:block font-bold">{item.label}</span>
              </button>
            );
          })}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all"><LogOut size={22} className="mr-3" /> <span className="hidden md:block">退出系统</span></button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0 relative">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-widest">{activeTab === 'finance' ? '财务收支详情' : activeTab.toUpperCase()}</h2>
          <div className="flex items-center gap-6">
            {/* 通知中心 */}
            <div className="relative" ref={notificationRef}>
              <div 
                className="relative group cursor-pointer p-2 hover:bg-slate-50 rounded-xl transition-all" 
                onClick={() => setShowNotifications(!showNotifications)}
              >
                 {stats.pendingAppts > 0 && <span className="absolute top-1 right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-white animate-pulse z-10"></span>}
                 <Bell className={`${showNotifications ? 'text-indigo-600' : 'text-slate-400'} group-hover:text-indigo-600 transition-all`} size={20} />
              </div>

              {/* 通知面板 */}
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden z-[120] animate-in slide-in-from-top-2 duration-200">
                  <div className="p-5 border-b flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest">待确认预约动态</h4>
                    <span className="text-[10px] font-bold bg-indigo-100 text-indigo-600 px-2 py-0.5 rounded-full">{stats.pendingAppts} 条</span>
                  </div>
                  <div className="max-h-96 overflow-y-auto custom-scroll">
                    {stats.allPendingAppts.length > 0 ? (
                      stats.allPendingAppts.map(appt => (
                        <div 
                          key={appt.id} 
                          onClick={() => handleNotificationClick(appt)}
                          className="p-5 border-b border-slate-50 hover:bg-indigo-50/30 cursor-pointer transition-all flex items-start gap-4 group"
                        >
                          <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600 group-hover:bg-indigo-600 group-hover:text-white transition-all shrink-0">
                            <Clock size={18}/>
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex justify-between items-center mb-1">
                              <p className="text-sm font-black text-slate-800 truncate">{appt.customerName}</p>
                              <p className="text-[10px] font-bold text-slate-400">{appt.startHour}:00</p>
                            </div>
                            <p className="text-xs text-slate-500 truncate mb-2">{appt.projectName}</p>
                            <div className="flex items-center gap-1.5 text-[9px] font-black text-indigo-500 uppercase">
                               <Info size={10}/> 点击处理此预约
                            </div>
                          </div>
                        </div>
                      ))
                    ) : (
                      <div className="py-12 text-center">
                        <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-200">
                          <Bell size={32}/>
                        </div>
                        <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">目前没有新消息</p>
                      </div>
                    )}
                  </div>
                  {stats.pendingAppts > 0 && (
                    <div className="p-4 bg-slate-50/50 text-center">
                      <button 
                        onClick={() => { setActiveTab('appts'); setShowNotifications(false); }}
                        className="text-[10px] font-black text-indigo-600 uppercase hover:underline"
                      >
                        查看排班表全部动态
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>

            <div className="text-right">
              <div className="text-sm font-bold text-slate-800">{currentUser.name}</div>
              <div className="text-[10px] text-slate-400 font-bold uppercase">{currentUser.role}</div>
            </div>
            <button onClick={() => { setIsModalOpen('new_appt'); setPrefillData(null); setIsQuickAddCustomer(false); }} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg hover:bg-indigo-700 transition-all flex items-center gap-2"><Plus size={18} /> <span>新预约</span></button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scroll">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                  { label: '今日实收', val: `¥${stats.todayTotal.toLocaleString()}`, icon: ArrowUpCircle, color: 'text-indigo-600', filter: 'all' },
                  { label: '今日现金', val: `¥${stats.todayCash.toLocaleString()}`, icon: Banknote, color: 'text-green-500', filter: 'cash' },
                  { label: '今日充值', val: `¥${stats.todayRecharge.toLocaleString()}`, icon: Wallet, color: 'text-blue-500', filter: 'recharge' },
                  { label: '今日耗卡', val: `¥${stats.todayConsumption.toLocaleString()}`, icon: CreditCard, color: 'text-amber-500', filter: 'consume' },
                  { label: '本月应收', val: `¥${stats.monthlyRevenue.toLocaleString()}`, icon: ReceiptText, color: 'text-purple-600', filter: 'all' },
                  { label: '待确定预约', val: stats.pendingAppts, icon: Bell, color: 'text-pink-500', tab: 'appts' },
                  { label: '今日预约', val: stats.todayAppts, icon: Calendar, color: 'text-slate-600', tab: 'appts' },
                  { label: '会员总数', val: stats.totalMembers, icon: Users, color: 'text-emerald-500', tab: 'customers' },
                ].map((s, i) => (
                  <div 
                    key={i} 
                    onClick={() => { if(s.tab) setActiveTab(s.tab); else navigateToFinance(s.filter as any); }}
