                      <input id="cons-amt" type="number" placeholder="请输入金额" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-500 outline-none text-slate-900 transition-all" />
                   </div>
                </div>
                <div className="flex gap-4 pt-4">
                  <button onClick={() => {
                    const i = (document.getElementById('cons-item') as HTMLInputElement).value;
                    const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                    const parts = isModalOpen.split('_');
                    const apptId = parts.length > 3 ? parts[3] : undefined;
                    if (i && a >= 0) handleConsume(parts[1], a, i, 'balance', apptId);
                  }} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100 transition-all hover:bg-indigo-700">卡耗(余额支付)</button>
                  <button onClick={() => {
                    const i = (document.getElementById('cons-item') as HTMLInputElement).value;
                    const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                    const parts = isModalOpen.split('_');
                    const apptId = parts.length > 3 ? parts[3] : undefined;
                    if (i && a >= 0) handleConsume(parts[1], a, i, 'cash', apptId);
                  }} className="flex-1 py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase transition-all hover:bg-black">现金/微信全额</button>
