                    <button onClick={() => setIsQuickAddCustomer(false)} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${!isQuickAddCustomer ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>选择既有会员</button>
                    <button onClick={() => setIsQuickAddCustomer(true)} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${isQuickAddCustomer ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>极速新建资料</button>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <div className="col-span-2">
                       {isQuickAddCustomer ? (
                         <div className="flex gap-2">
                           <input id="apt-nc-name" placeholder="客户姓名" className="flex-1 p-4 bg-slate-50 rounded-xl border focus:border-indigo-500 outline-none text-slate-900" />
                           <input id="apt-nc-phone" placeholder="手机号" className="flex-1 p-4 bg-slate-50 rounded-xl border focus:border-indigo-500 outline-none text-slate-900" />
                         </div>
                       ) : (
                         <select id="apt-c" className="w-full p-4 bg-slate-50 rounded-xl border outline-none text-slate-900">
                           {customers.map(c => <option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}
