            { id: 'customers', icon: Users, label: '会员管理', admin: false },
            { id: 'finance', icon: History, label: '财务报表', admin: false },
            { id: 'staff', icon: ShieldCheck, label: '员工管理', admin: true },
            { id: 'logs', icon: Settings, label: '操作日志', admin: true },
          ].map(item => {
