              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                  { label: '今日实收', val: `¥${stats.todayTotal.toLocaleString()}`, icon: ArrowUpCircle, color: 'text-indigo-600', filter: 'all' },
                  { label: '今日现金', val: `¥${stats.todayCash.toLocaleString()}`, icon: Banknote, color: 'text-green-500', filter: 'cash' },
