                       <input id="apt-h" type="number" min="8" max="22" defaultValue={prefillData?.hour || 10} className="w-full p-4 bg-slate-50 rounded-xl border-2 border-transparent focus:border-indigo-500 outline-none text-slate-900 font-bold transition-all" />
                    </div>

                    <div className="space-y-1">
                       <label className="text-[10px] font-black text-slate-400 uppercase">预计时长 (h)</label>
                       <input id="apt-d" type="number" min="1" max="5" defaultValue={1} className="w-full p-4 bg-slate-50 rounded-xl border-2 border-transparent focus:border-indigo-500 outline-none text-slate-900 font-bold transition-all" />
                    </div>
                 </div>

                 <button onClick={() => {
                   let finalCustomerId = "";
                   let finalCustomerName = "";

                   // 极速建档逻辑
                   if (isQuickAddCustomer) {
                     const n = (document.getElementById('apt-nc-name') as HTMLInputElement).value;
                     const p = (document.getElementById('apt-nc-phone') as HTMLInputElement).value;
                     if (!n || !p) {
                       alert("姓名和手机号是极速建档的必填项");
                       return;
                     }
                     const newCustId = `C-${Date.now()}`;
                     const newCustomer: Customer = {
                        id: newCustId,
                        name: n,
                        phone: p,
                        balance: 0,
                        remarks: '极速建档预约',
                        createdAt: new Date().toISOString()
                     };
                     setCustomers(prev => [...prev, newCustomer]);
                     addLog('新增会员', `极速建档成功: ${n}`, { type: 'add_customer', targetId: newCustId });
                     finalCustomerId = newCustId;
                     finalCustomerName = n;
                   } else {
                     finalCustomerId = (document.getElementById('apt-c') as HTMLSelectElement).value; 
                     finalCustomerName = customers.find(x => x.id === finalCustomerId)?.name || '';
                     if (!finalCustomerId) {
                       alert("请选择一个有效的会员");
                       return;
                     }
                   }

                   const sId = (document.getElementById('apt-s') as HTMLSelectElement).value; 
                   const prj = (document.getElementById('apt-p') as HTMLInputElement).value;
                   const hour = parseInt((document.getElementById('apt-h') as HTMLInputElement).value); 
                   const dur = parseInt((document.getElementById('apt-d') as HTMLInputElement).value);
                   const apptId = `APT-${Date.now()}`;

                   if (prj && sId) { 
                     setAppointments(prev => [...prev, { 
                        id: apptId, 
                        customerId: finalCustomerId, 
                        customerName: finalCustomerName, 
                        staffId: sId, 
                        projectName: prj, 
                        startTime: selectedDate.toISOString(), 
                        startHour: hour, 
                        duration: dur, 
                        status: 'pending' 
                     }]); 
                     setIsModalOpen(null); 
                     setPrefillData(null); 
                     addLog('新建预约', `预约 ${prj} 提交成功`, { type: 'add_appt', targetId: apptId }); 
                   } else {
                     alert("请填写服务项目并指派技师");
                   }
                 }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs mt-4 shadow-xl transition-all hover:bg-black flex items-center justify-center gap-2">
                   <CheckCircle size={16}/> 确认提交并派单
                 </button>
              </div>
            )}

            {isModalOpen?.startsWith('recharge_') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800 mb-8">会员账户充值</h3>
                <div className="grid grid-cols-2 gap-4">
                  {[500, 1000, 2000, 5000].map(v => (<button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v, isModalOpen.endsWith('_fromConsume'))} className="py-5 border-2 border-slate-100 rounded-2xl font-black text-slate-700 hover:border-indigo-600 hover:text-indigo-600 transition-all">¥{v}</button>))}
                </div>
              </div>
            )}

            {(isModalOpen === 'new_staff' || isModalOpen === 'edit_staff') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800">{isModalOpen === 'edit_staff' ? '修改员工档案' : '入职登记'}</h3>
                <div className="space-y-5">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase">员工姓名</label>
                    <input id="st-name" placeholder="姓名" defaultValue={editingTarget?.name || ""} className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500" />
                  </div>
                  <div className="space-y-1">
                    <div className="flex justify-between items-center mb-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase">所属岗位 (Role)</label>
                      <button 
                        onClick={() => setIsCustomRole(!isCustomRole)}
                        className="text-[10px] font-black text-indigo-600 uppercase flex items-center gap-1 hover:underline"
                      >
                        {isCustomRole ? <ChevronDown size={12}/> : <PlusSquare size={12}/>}
                        {isCustomRole ? "选择预设岗位" : "使用自定义岗位"}
                      </button>
                    </div>
                    {isCustomRole ? (
                      <input id="st-role-custom" placeholder="请输入自定义岗位名称" defaultValue={editingTarget?.role || ""} className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500" />
                    ) : (
                      <select id="st-role-select" defaultValue={editingTarget?.role || "技师"} className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500">
                        {PRESET_ROLES.map(role => <option key={role} value={role}>{role}</option>)}
                      </select>
                    )}
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase">登录密码</label>
                    <input id="st-pass" type="password" placeholder={isModalOpen === 'edit_staff' ? "留空则不修改密码" : "设置初始登录密码"} className="w-full p-4 bg-slate-50 rounded-2xl border outline-none text-slate-900 transition-all focus:border-indigo-500" />
                  </div>
                  <div className="space-y-3 pt-4 border-t border-slate-100">
                    <div className="flex items-center gap-2 mb-2">
                       <Shield size={14} className="text-indigo-500"/>
                       <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">系统功能访问权限</label>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                       {AVAILABLE_PERMISSIONS.map(perm => (
                         <div 
                           key={perm.id} 
                           onClick={() => togglePermission(perm.id)}
                           className={`flex items-center gap-3 p-3 rounded-2xl border-2 transition-all cursor-pointer ${
                             staffPermissions.includes(perm.id) 
                             ? 'bg-indigo-50 border-indigo-200 text-indigo-700' 
                             : 'bg-white border-slate-50 text-slate-400 hover:border-slate-200'
                           }`}
                         >
                            <perm.icon size={16}/>
                            <span className="text-xs font-bold">{perm.label}</span>
                            {staffPermissions.includes(perm.id) && <CheckCircle size={14} className="ml-auto text-indigo-600"/>}
                         </div>
                       ))}
                    </div>
                  </div>
                </div>
                <button onClick={() => {
                   const n = (document.getElementById('st-name') as HTMLInputElement).value; 
                   const r = isCustomRole 
                    ? (document.getElementById('st-role-custom') as HTMLInputElement).value 
                    : (document.getElementById('st-role-select') as HTMLSelectElement).value;
                   const p = (document.getElementById('st-pass') as HTMLInputElement).value;

                   if (n && r) {
                     if (isModalOpen === 'edit_staff' && editingTarget) { 
                       setStaff(prev => prev.map(s => s.id === editingTarget.id ? { ...s, name: n, role: r, password: p || s.password, permissions: staffPermissions } : s)); 
                       addLog('修改员工', `档案更新: ${n} (${r})`);
                     } 
                     else if (p) { 
                       setStaff(prev => [...prev, { 
                         id: `S-${Date.now()}`, 
                         name: n, 
                         role: r, 
                         password: p, 
                         avatar: n[0].toUpperCase(), 
                         permissions: staffPermissions 
                       }]); 
                       addLog('入职登记', `新成员入职: ${n} (${r})`);
                     } else {
                       alert("请设置登录密码");
                       return;
                     }
                     setIsModalOpen(null); setEditingTarget(null); setStaffPermissions([]);
                   }
                }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs shadow-xl transition-all hover:bg-black mt-4">确认保存员工信息</button>
              </div>
            )}
          </div>
        </div>
      )}

      {selectedAppt && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md" onClick={() => setSelectedAppt(null)}></div>
          <div className="relative z-10 bg-white w-full max-w-sm rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95">
             <div className="flex justify-between items-start mb-8"><div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600"><Info size={24}/></div><button onClick={() => setSelectedAppt(null)} className="text-slate-300 hover:text-slate-500 transition-all"><X size={24}/></button></div>
             <div className="mb-8"><h4 className="text-2xl font-black text-slate-800">{selectedAppt.customerName}</h4><p className="text-xs font-bold text-indigo-500 uppercase tracking-widest">{selectedAppt.projectName}</p></div>
             <div className="space-y-6 mb-10">
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase">预约状态</span><span className={`text-[10px] font-black px-2 py-0.5 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : selectedAppt.status === 'confirmed' ? 'bg-indigo-100 text-indigo-600' : 'bg-green-100 text-green-600'}`}>{selectedAppt.status === 'pending' ? '待技师确认' : selectedAppt.status === 'confirmed' ? '正在受理' : '已完成'}</span></div>
                <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-400 uppercase">预约时段</span><span className="text-xs font-bold text-slate-800">{selectedAppt.startHour}:00 ({selectedAppt.duration}h)</span></div>
             </div>
             <div className="space-y-3">
                {selectedAppt.status === 'pending' && ( <button onClick={() => updateApptStatus(selectedAppt.id, 'confirmed')} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-indigo-100 flex items-center justify-center gap-2"><CheckCircle size={16}/> 确认排单并开始</button> )}
                {selectedAppt.status === 'confirmed' && ( <button onClick={() => updateApptStatus(selectedAppt.id, 'completed')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase shadow-lg flex items-center justify-center gap-2 transition-all hover:bg-black"><PlayCircle size={16}/> 服务完成去结算</button> )}
                <button onClick={() => deleteAppt(selectedAppt.id)} className="w-full py-4 text-red-400 hover:text-red-600 font-bold text-xs uppercase transition-all">作废该笔预约</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, TrendingUp, Zap
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班/预约', icon: Calendar },
  { id: 'customers', label: '会员管理', icon: Users },
  { id: 'finance', label: '财务报表', icon: History },
  { id: 'staff', label: '员工管理', icon: ShieldCheck },
  { id: 'logs', label: '操作日志', icon: Settings },
];

const PRESET_ROLES = ['技师', '发型师', '美容师', '前台', '店长', '经理'];

const App: React.FC = () => {
  // --- 状态管理 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');
  const [logStartDate, setLogStartDate] = useState('');
  const [logEndDate, setLogEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [viewingCustomerProfile, setViewingCustomerProfile] = useState<Customer | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const [isCustomRole, setIsCustomRole] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 数据统计与分析 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString(),
      undoData,
      isRevoked: false
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const todayConsumption = todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      const typeMatches = 
        activeFinanceFilter === 'all' ? true :
        activeFinanceFilter === 'recharge' ? t.type === 'recharge' :
        activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') :
        activeFinanceFilter === 'cash' ? (t.type === 'consume' && t.paymentMethod !== 'balance') : true;
      return tDate >= start && tDate <= end && typeMatches;
    });
  }, [transactions, financeStartDate, financeEndDate, activeFinanceFilter]);

  // --- 业务操作 ---
  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData || revokingLog.isRevoked) return;
    const { type, targetId, secondaryId, amount, paymentMethod, prevStatus } = revokingLog.undoData;
    try {
      if (type === 'recharge' && secondaryId && amount) {
        setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance - amount } : c));
        setTransactions(prev => prev.filter(t => t.id !== targetId));
      } else if (type === 'consume' && secondaryId && amount) {
        if (paymentMethod === 'balance') setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance + amount } : c));
        setTransactions(prev => prev.filter(t => t.id !== targetId));
        if (prevStatus) setAppointments(prev => prev.map(a => a.id === prevStatus ? { ...a, status: 'confirmed' } : a));
      } else if (type === 'add_customer') {
        setCustomers(prev => prev.filter(c => c.id !== targetId));
      } else if (type === 'add_appt') {
        setAppointments(prev => prev.filter(a => a.id !== targetId));
      }
      setLogs(prev => prev.map(l => l.id === revokingLog.id ? { ...l, isRevoked: true } : l));
      addLog('系统撤销', `成功撤销了操作: ${revokingLog.action}`);
      setRevokingLog(null);
    } catch (e) { alert('撤销操作失败'); }
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const report = await analyzeBusinessData({ transactions: transactions.slice(0, 30), stats });
      setAiAnalysis(report);
      addLog('AI 诊断', '生成了经营建议报告');
    } catch (e) { setAiAnalysis("AI 分析暂不可用。"); }
    finally { setIsAnalyzing(false); }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) { setCurrentUser(found); addLog('登录系统', '身份验证通过'); } else { alert('账号或密码错误'); }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('卡内余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName, timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('客户结算', `${cust?.name} 消费 ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const transId = `TRX-${Date.now()}`;
    const cust = customers.find(c => c.id === custId);
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '余额充值', timestamp: new Date().toISOString() }, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
    setIsModalOpen(null);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能店务，数据驱动经营。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 预约提醒</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 消费档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 财务对账</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 bg-white flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">管理员登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
