                        setIsModalOpen(null);
                      }
                   }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-200">提交预约申请</button>
                </div>
             )}

             {/* 结算弹窗 */}
             {isModalOpen?.startsWith('consume_') && (
                <div className="space-y-6 text-center">
                   <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mx-auto"><ReceiptText size={28}/></div>
                   <h3 className="text-2xl font-black text-slate-900 uppercase">服务结算对账单</h3>
                   <div className="space-y-4 text-left">
                      <div className="bg-slate-50 p-4 rounded-2xl"><p className="text-[10px] font-black text-slate-400 uppercase">待结算客户</p><p className="text-xl font-black text-slate-800">{customers.find(c => c.id === isModalOpen.split('_')[1])?.name}</p></div>
                      <input id="cons-amt" type="number" placeholder="请输入最终结算金额" className="w-full p-5 bg-slate-50 rounded-2xl border-none font-black text-2xl text-slate-900 placeholder:text-slate-200" />
                   </div>
                   <div className="flex gap-4">
                      <button onClick={() => {
                        const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                        if (a >= 0) handleConsume(isModalOpen.split('_')[1], a, '店内综合服务', 'balance');
                      }} className="flex-1 py-5 bg-indigo-600 text-white rounded-3xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">卡余额扣除</button>
                      <button onClick={() => {
                        const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                        if (a >= 0) handleConsume(isModalOpen.split('_')[1], a, '店内综合服务', 'cash');
                      }} className="flex-1 py-5 bg-slate-900 text-white rounded-3xl font-black text-[10px] uppercase">现金/微信支付</button>
                   </div>
                </div>
             )}

             {/* 充值弹窗 */}
             {isModalOpen?.startsWith('recharge_') && (
                <div className="space-y-6">
                   <h3 className="text-2xl font-black text-slate-800 text-center uppercase tracking-widest">会员账户充值</h3>
                   <div className="grid grid-cols-2 gap-4">
                      {[500, 1000, 2000, 5000].map(v => (
                         <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v)} className="py-8 border-2 border-slate-50 rounded-3xl font-black text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all flex flex-col items-center justify-center gap-2 group">
                            <span className="text-[10px] opacity-40 uppercase group-hover:opacity-100 transition-all">推荐面额</span>
                            <span className="text-2xl">¥{v}</span>
                         </button>
                      ))}
                   </div>
                </div>
             )}

             {/* 预约详情与操作 */}
             {selectedAppt && (
                <div className="space-y-8">
                   <div className="flex justify-between items-start">
                      <div className="w-16 h-16 bg-indigo-50 rounded-[2rem] flex items-center justify-center text-indigo-600"><Clock size={28}/></div>
                      <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                   </div>
                   <div className="space-y-2">
                      <h4 className="text-3xl font-black text-slate-900">{selectedAppt.customerName}</h4>
                      <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest">{selectedAppt.projectName}</p>
                   </div>
                   <div className="space-y-3">
                      {selectedAppt.status === 'pending' && (
                         <button onClick={() => { 
                            setAppointments(prev => prev.map(a => a.id === selectedAppt.id ? {...a, status: 'confirmed'} : a)); 
                            addLog('确认预约', `已确认并开始受理: ${selectedAppt.id}`);
                            setSelectedAppt(null); 
                         }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100">确认并开始受理</button>
                      )}
                      {selectedAppt.status === 'confirmed' && (
                         <button onClick={() => { setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null); }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase">服务结束去结算</button>
                      )}
                      <button onClick={() => { 
                         setAppointments(prev => prev.filter(a => a.id !== selectedAppt.id)); 
                         addLog('作废预约', `已删除预约单: ${selectedAppt.id}`);
                         setSelectedAppt(null); 
                      }} className="w-full py-4 text-red-500 font-bold text-xs uppercase hover:underline">作废此预约单</button>
                   </div>
                </div>
             )}

          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班/预约', icon: Calendar },
  { id: 'customers', label: '会员管理', icon: Users },
  { id: 'finance', label: '财务报表', icon: History },
  { id: 'staff', label: '员工管理', icon: ShieldCheck },
  { id: 'logs', label: '操作日志', icon: Settings },
];

const PRESET_ROLES = ['技师', '发型师', '美容师', '前台', '店长', '经理'];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  // 筛选器状态
  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');
  const [logStartDate, setLogStartDate] = useState('');
  const [logEndDate, setLogEndDate] = useState('');

  // 数据持久化状态
  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  // 交互状态
  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [viewingCustomerProfile, setViewingCustomerProfile] = useState<Customer | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const [isCustomRole, setIsCustomRole] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 生命周期 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    if (activeTab === 'dashboard' && !aiAnalysis && transactions.length > 0) {
      handleAiAnalyze();
    }
  }, [activeTab]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 辅助计算 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString(),
      undoData,
      isRevoked: false
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: todayTrans.reduce((sum, t) => t.type === 'consume' ? sum + t.amount : sum, 0),
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      const typeMatches = 
        activeFinanceFilter === 'all' ? true :
        activeFinanceFilter === 'recharge' ? t.type === 'recharge' :
        activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') :
        activeFinanceFilter === 'cash' ? (t.type === 'consume' && t.paymentMethod !== 'balance') : true;
      return tDate >= start && tDate <= end && typeMatches;
    });
  }, [transactions, financeStartDate, financeEndDate, activeFinanceFilter]);

  // --- 业务操作 ---
  const handleAiAnalyze = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const data = { transactions: transactions.slice(0, 30), stats };
      const result = await analyzeBusinessData(data);
      setAiAnalysis(result);
      addLog('AI 诊断', '生成了经营建议报告');
    } catch (e) { setAiAnalysis("AI 分析暂不可用。"); }
    finally { setIsAnalyzing(false); }
  };

  const exportTransactionsToCSV = () => {
    const headers = ["流水号", "类型", "客户", "金额", "支付方式", "项目", "时间"];
    const csvContent = [
      headers.join(","),
      ...filteredTransactions.map(t => [
        t.id, 
        t.type === 'recharge' ? '充值' : '结算', 
        t.customerName, 
        t.amount, 
        t.paymentMethod === 'balance' ? '卡余额' : '现金/微信',
        t.itemName,
        new Date(t.timestamp).toLocaleString()
      ].join(","))
    ].join("\n");
    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `BeautyPro_财务报表_${new Date().toLocaleDateString()}.csv`;
    link.click();
  };

  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData || revokingLog.isRevoked) return;
    const { type, targetId, secondaryId, amount, paymentMethod, prevStatus } = revokingLog.undoData;
    try {
      if (type === 'recharge' && secondaryId && amount) {
        setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance - amount } : c));
        setTransactions(prev => prev.filter(t => t.id !== targetId));
      } else if (type === 'consume' && secondaryId && amount) {
        if (paymentMethod === 'balance') setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance + amount } : c));
        setTransactions(prev => prev.filter(t => t.id !== targetId));
        if (prevStatus) setAppointments(prev => prev.map(a => a.id === prevStatus ? { ...a, status: 'confirmed' } : a));
      } else if (type === 'add_customer') {
        setCustomers(prev => prev.filter(c => c.id !== targetId));
      } else if (type === 'add_appt') {
        setAppointments(prev => prev.filter(a => a.id !== targetId));
      }
      setLogs(prev => prev.map(l => l.id === revokingLog.id ? { ...l, isRevoked: true } : l));
      addLog('撤销成功', `已回滚业务: ${revokingLog.action}`);
      setRevokingLog(null);
    } catch (e) { alert('撤销失败'); }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) { setCurrentUser(found); addLog('登录', '成功进入系统'); } else { alert('账号或密码错误'); }
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const transId = `TRX-${Date.now()}`;
    const cust = customers.find(c => c.id === custId);
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '余额充值', timestamp: new Date().toISOString() }, ...prev]);
    addLog('会员充值', `${cust?.name} 充值 ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足，请先充值'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName, timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('结算', `${cust?.name} 消费 ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能店务，数据驱动经营。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 预约提醒</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 消费档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 财务对账</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 bg-white flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">管理员登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <input id="login-user" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="账号 (admin)" />
              <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900" placeholder="密码 (admin)" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold transition-all hover:bg-black">立即进入</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans">
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3 shadow-lg shadow-indigo-100"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 tracking-tighter uppercase">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {AVAILABLE_PERMISSIONS.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center p-4 rounded-2xl transition-all ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <item.icon size={22} className="mr-3" /> <span className="hidden md:block font-bold">{item.label}</span>
            </button>
          ))}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all"><LogOut size={22} className="mr-3" /> <span className="hidden md:block">退出系统</span></button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-widest">{activeTab.toUpperCase()}</h2>
          <div className="flex items-center gap-6">
            <div className="relative" ref={notificationRef}>
              <div className="p-2 hover:bg-slate-50 rounded-xl cursor-pointer relative" onClick={() => setShowNotifications(!showNotifications)}>
                {stats.pendingAppts > 0 && <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
                <Bell className={`${showNotifications ? 'text-indigo-600' : 'text-slate-400'}`} size={20} />
              </div>
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden z-[120] animate-in slide-in-from-top-2">
                  <div className="p-4 bg-slate-50 border-b flex justify-between items-center">
                    <span className="text-xs font-black uppercase tracking-widest">待确认预约动态</span>
                    <span className="text-[10px] bg-indigo-100 text-indigo-600 px-2 py-0.5 rounded-full font-bold">{stats.pendingAppts} 条</span>
                  </div>
                  <div className="max-h-80 overflow-y-auto">
                    {stats.allPendingAppts.length > 0 ? stats.allPendingAppts.map(appt => {
                      const tech = staff.find(s => s.id === appt.staffId);
                      return (
                        <div key={appt.id} className="p-4 border-b hover:bg-indigo-50/30 cursor-pointer" onClick={() => { setActiveTab('appts'); setSelectedDate(new Date(appt.startTime)); setSelectedAppt(appt); setShowNotifications(false); }}>
                          <div className="flex justify-between mb-1"><span className="text-sm font-black">{appt.customerName}</span><span className="text-[10px] text-slate-400 font-bold">{appt.startHour}:00</span></div>
                          <p className="text-xs text-slate-500 truncate">{appt.projectName}</p>
                          <div className="mt-2 flex items-center gap-1.5 text-[9px] font-black text-indigo-500 uppercase">
                            <User size={10}/> 指派技师: <span className="text-indigo-700">{tech?.name || '未分配'}</span>
                          </div>
                        </div>
                      );
                    }) : (
                      <div className="py-12 text-center text-slate-300 font-bold uppercase text-[10px] tracking-widest">暂无新预约消息</div>
                    )}
                  </div>
                </div>
