                   <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">手机号码</label><input id="nc-phone" defaultValue={editingTarget?.phone} placeholder="号码" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                   <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">习惯备注</label><textarea id="nc-remarks" defaultValue={editingTarget?.remarks} placeholder="录入特征/忌口/偏好" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900 h-24 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                </div>
                <button onClick={() => {
                   const n = (document.getElementById('nc-name') as HTMLInputElement).value;
                   const p = (document.getElementById('nc-phone') as HTMLInputElement).value;
                   const r = (document.getElementById('nc-remarks') as HTMLTextAreaElement).value;
                   if (n && p) {
                     if (isModalOpen === 'edit_customer' && editingTarget) {
                       setCustomers(prev => prev.map(c => c.id === editingTarget.id ? { ...c, name: n, phone: p, remarks: r } : c));
                       addLog('修改档案', `更新会员: ${n}`);
                     } else {
                       const cId = `C-${Date.now()}`;
                       setCustomers(prev => [...prev, { id: cId, name: n, phone: p, balance: 0, remarks: r, createdAt: new Date().toISOString() }]);
                       addLog('建档', `新会员: ${n}`, { type: 'add_customer', targetId: cId });
                     }
                     setIsModalOpen(null);
                   }
                }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-black transition-all">保存会员信息</button>
              </div>
            )}

            {/* 员工档案弹窗 */}
            {(isModalOpen === 'new_staff' || isModalOpen === 'edit_staff') && (
               <div className="space-y-6">
                 <h3 className="text-2xl font-black text-slate-800 uppercase tracking-widest">{isModalOpen === 'edit_staff' ? '修改档案' : '入职登记'}</h3>
                 <div className="space-y-4">
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">姓名</label><input id="st-name" defaultValue={editingTarget?.name} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">岗位</label><select id="st-role" defaultValue={editingTarget?.role} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900">{PRESET_ROLES.map(r => <option key={r} value={r}>{r}</option>)}</select></div>
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">密码</label><input id="st-pass" type="password" placeholder="设置登录密码" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                 </div>
                 <button onClick={() => {
                    const n = (document.getElementById('st-name') as HTMLInputElement).value;
                    const r = (document.getElementById('st-role') as HTMLSelectElement).value;
                    const p = (document.getElementById('st-pass') as HTMLInputElement).value;
                    if (n && r) {
                      if (isModalOpen === 'edit_staff' && editingTarget) {
                        setStaff(prev => prev.map(s => s.id === editingTarget.id ? { ...s, name: n, role: r, password: p || s.password } : s));
                        addLog('修改员工', `档案变更: ${n}`);
                      } else {
                        setStaff(prev => [...prev, { id: `S-${Date.now()}`, name: n, role: r, password: p, avatar: n[0].toUpperCase(), permissions: [] }]);
                        addLog('员工入职', `新同事: ${n}`);
                      }
                      setIsModalOpen(null);
                    }
                 }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-lg">确认保存资料</button>
               </div>
            )}

            {/* 结算弹窗 */}
            {isModalOpen?.startsWith('consume_') && (
               <div className="space-y-6 text-center">
                  <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mx-auto shadow-inner"><ReceiptText size={28}/></div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase">服务结算对账单</h3>
                  <div className="bg-slate-50 p-6 rounded-3xl text-left">
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">待结算客户</p>
                     <p className="text-xl font-black text-slate-800">{customers.find(c => c.id === isModalOpen.split('_')[1])?.name}</p>
                  </div>
                  <div className="space-y-1 text-left">
                     <label className="text-[10px] font-black text-slate-400 uppercase ml-2">实收金额 (¥)</label>
                     <input id="cons-amt" type="number" placeholder="0.00" className="w-full p-5 bg-slate-50 rounded-3xl font-black text-3xl text-slate-900 placeholder:text-slate-100 outline-none" />
                  </div>
                  <div className="flex gap-4 pt-4">
                     <button onClick={() => {
                       const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                       if (a >= 0) handleConsume(isModalOpen.split('_')[1], a, '店内综合服务', 'balance', isModalOpen.split('_')[3]);
                     }} className="flex-1 py-5 bg-indigo-600 text-white rounded-[2rem] font-black text-[10px] uppercase shadow-lg shadow-indigo-200">卡余额扣除</button>
                     <button onClick={() => {
                       const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                       if (a >= 0) handleConsume(isModalOpen.split('_')[1], a, '店内综合服务', 'cash', isModalOpen.split('_')[3]);
                     }} className="flex-1 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase">现金结算</button>
                  </div>
               </div>
            )}

            {/* 充值弹窗 */}
            {isModalOpen?.startsWith('recharge_') && (
               <div className="space-y-6">
                  <h3 className="text-2xl font-black text-slate-800 text-center uppercase tracking-widest">会员钱包充值</h3>
                  <div className="grid grid-cols-2 gap-4">
                     {[500, 1000, 2000, 5000].map(v => (
                        <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v)} className="py-8 border-2 border-slate-50 rounded-3xl font-black text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all flex flex-col items-center justify-center gap-1 group">
                           <span className="text-[10px] opacity-40 uppercase group-hover:opacity-100">预设方案</span>
                           <span className="text-2xl font-black">¥{v}</span>
                        </button>
                     ))}
                  </div>
               </div>
            )}

            {/* 预约卡片详情 */}
            {selectedAppt && !revokingLog && (
               <div className="space-y-8 animate-in fade-in">
                  <div className="flex justify-between items-start">
                     <div className="w-16 h-16 bg-indigo-50 rounded-[2rem] flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={28}/></div>
                     <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-3xl font-black text-slate-900">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={12}/> 指派技师: <span className="text-slate-800">{staff.find(s=>s.id === selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status === 'pending' && (
                        <button onClick={() => { setAppointments(prev => prev.map(a => a.id === selectedAppt.id ? {...a, status: 'confirmed'} : a)); setSelectedAppt(null); addLog('受理预约', `确认单号: ${selectedAppt.id}`); }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">开始提供服务</button>
                     )}
                     {selectedAppt.status === 'confirmed' && (
                        <button onClick={() => { setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null); }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase hover:bg-black transition-all">完工结算</button>
                     )}
                     <button onClick={() => { if(confirm('确认作废？')) { setAppointments(prev => prev.filter(a => a.id !== selectedAppt.id)); setSelectedAppt(null); addLog('作废', `废弃预约单: ${selectedAppt.id}`); } }} className="w-full py-4 text-red-500 font-bold text-xs uppercase hover:underline transition-all">作废该任务单</button>
                  </div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班/预约', icon: Calendar },
  { id: 'customers', label: '会员管理', icon: Users },
  { id: 'finance', label: '财务报表', icon: History },
  { id: 'staff', label: '员工管理', icon: ShieldCheck },
  { id: 'logs', label: '操作日志', icon: Settings },
];

const PRESET_ROLES = ['技师', '发型师', '美容师', '前台', '店长', '经理'];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');
  const [logStartDate, setLogStartDate] = useState('');
  const [logEndDate, setLogEndDate] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"管理员","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [viewingCustomerProfile, setViewingCustomerProfile] = useState<Customer | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 数据持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 统计数据 ---
  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    const todayAppts = appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length;

    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: consumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      const typeMatches = 
        activeFinanceFilter === 'all' ? true :
        activeFinanceFilter === 'recharge' ? t.type === 'recharge' :
        activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') :
        activeFinanceFilter === 'cash' ? (t.type === 'consume' && t.paymentMethod !== 'balance') : true;
      return tDate >= start && tDate <= end && typeMatches;
    });
  }, [transactions, financeStartDate, financeEndDate, activeFinanceFilter]);

  // --- 业务操作 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString(),
      undoData,
      isRevoked: false
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const handleAiAnalyze = async () => {
    setIsAnalyzing(true);
    try {
      const report = await analyzeBusinessData({ transactions: transactions.slice(0, 30), stats });
      setAiAnalysis(report);
      addLog('AI 诊断', '生成了经营建议报告');
    } catch (e) { setAiAnalysis("AI 分析暂不可用。"); }
    finally { setIsAnalyzing(false); }
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const transId = `TRX-${Date.now()}`;
    const cust = customers.find(c => c.id === custId);
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '余额充值', timestamp: new Date().toISOString() }, ...prev]);
    addLog('充值', `${cust?.name} 充值 ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName, timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} 消费 ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const togglePermission = (permId: string) => {
    setStaffPermissions(prev => prev.includes(permId) ? prev.filter(p => p !== permId) : [...prev, permId]);
  };

  const handleDeleteStaff = (id: string) => {
    if (confirm('确定要删除此员工吗？')) {
      setStaff(prev => prev.filter(s => s.id !== id));
      addLog('删除员工', `ID: ${id}`);
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-gradient-to-br from-indigo-600 to-violet-800 p-12 text-white flex flex-col justify-center">
            <h1 className="text-5xl font-extrabold mb-4 tracking-tight">BeautyPro</h1>
            <p className="text-indigo-100 text-lg opacity-80 mb-12">智能店务，数据驱动经营。</p>
            <div className="space-y-6">
              <div className="flex items-center gap-4"><CheckCircle className="text-indigo-300" /> 预约提醒</div>
              <div className="flex items-center gap-4"><UserCheck className="text-indigo-300" /> 消费档案</div>
              <div className="flex items-center gap-4"><ShieldCheck className="text-indigo-300" /> 财务对账</div>
            </div>
          </div>
          <div className="md:w-1/2 p-12 bg-white flex flex-col justify-center">
            <h2 className="text-3xl font-bold text-slate-800 mb-8">系统登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <input id="login-user" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900 font-medium" placeholder="账号" />
              <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none text-slate-900 font-medium" placeholder="密码" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold transition-all hover:bg-black">立即进入</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans text-slate-900">
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3 shadow-lg"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 uppercase tracking-tighter">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {AVAILABLE_PERMISSIONS.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center p-4 rounded-2xl transition-all ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <item.icon size={22} className="mr-3" /> <span className="hidden md:block font-bold">{item.label}</span>
            </button>
          ))}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all"><LogOut size={22} className="mr-3" /> <span className="hidden md:block">退出系统</span></button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-widest">{activeTab.toUpperCase()}</h2>
          <div className="flex items-center gap-6">
            <div className="relative" ref={notificationRef}>
              <div className="p-2 hover:bg-slate-50 rounded-xl cursor-pointer relative" onClick={() => setShowNotifications(!showNotifications)}>
                {stats.pendingAppts > 0 && <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
                <Bell className="text-slate-400" size={20} />
