import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2, Eye, History as HistoryIcon
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班/预约', icon: Calendar },
  { id: 'customers', label: '会员管理', icon: Users },
  { id: 'finance', label: '财务报表', icon: History },
  { id: 'staff', label: '员工管理', icon: ShieldCheck },
  { id: 'logs', label: '操作日志', icon: Settings },
];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"总店长","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 数据持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 统计计算 ---
  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    const todayAppts = appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length;

    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: consumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      const typeMatches = 
        activeFinanceFilter === 'all' ? true :
        activeFinanceFilter === 'recharge' ? t.type === 'recharge' :
        activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') :
        activeFinanceFilter === 'cash' ? (t.type === 'consume' && t.paymentMethod !== 'balance') : true;
      return tDate >= start && tDate <= end && typeMatches;
    });
  }, [transactions, financeStartDate, financeEndDate, activeFinanceFilter]);

  // --- 核心业务逻辑 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString(),
      undoData,
      isRevoked: false
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) { setCurrentUser(found); addLog('系统登录', `员工 ${found.name} 登录成功`); } 
    else { alert('账号或密码错误'); }
  };

  const handleRecharge = (custId: string, amount: number, isSilent = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const transId = `TRX-${Date.now()}`;
    const cust = customers.find(c => c.id === custId);
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '余额充值', timestamp: new Date().toISOString() }, ...prev]);
    if (!isSilent) {
      addLog('充值', `${cust?.name} 充值 ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
      setIsModalOpen(null);
    }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName, timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} 消费 ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const exportTransactionsToCSV = () => {
    const headers = ['单号', '类型', '详细分类', '客户', '金额', '项目', '时间'];
    const rows = filteredTransactions.map(t => [
      t.id,
      t.type === 'recharge' ? '充值' : '消费',
      t.type === 'recharge' ? '现金充值' : (t.paymentMethod === 'balance' ? '余额耗卡' : '现金实收'),
      t.customerName,
      t.amount,
      t.itemName,
      new Date(t.timestamp).toLocaleString()
    ]);
    const csvContent = "\ufeff" + [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `BeautyPro_财务报表_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData) return;
    const { type, targetId, secondaryId, amount, prevStatus, paymentMethod } = revokingLog.undoData;
    try {
      if (type === 'add_customer') { setCustomers(prev => prev.filter(c => c.id !== targetId)); } 
      else if (type === 'recharge') {
        setTransactions(prev => prev.filter(t => t.id !== targetId));
        if (secondaryId && amount) setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: Math.max(0, c.balance - amount) } : c));
      } 
      else if (type === 'consume') {
        setTransactions(prev => prev.filter(t => t.id !== targetId));
        if (secondaryId && amount && paymentMethod === 'balance') setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance + amount } : c));
        if (prevStatus) setAppointments(prev => prev.map(a => a.id === prevStatus ? { ...a, status: 'confirmed' } : a));
      }
      setLogs(prev => prev.map(l => l.id === revokingLog.id ? { ...l, isRevoked: true } : l));
      addLog('撤销成功', `已回滚业务: ${revokingLog.action}`);
    } catch (e) { alert('撤销操作失败'); } finally { setRevokingLog(null); }
  };

  const handleDashboardClick = (tab: string, filter?: string) => {
    setActiveTab(tab);
    if (filter) setActiveFinanceFilter(filter as any);
    if (tab === 'appts') {
      setSelectedDate(new Date());
      setViewMode('day');
    }
  };

  const handleMonthDayClick = (dayIndex: number) => {
    const newDate = new Date(selectedDate.getFullYear(), selectedDate.getMonth(), dayIndex + 1);
    setSelectedDate(newDate);
    setViewMode('day');
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans text-slate-900">
      {/* 侧边栏 */}
      <aside className="w-20 md:w-64 bg-white border-r flex flex-col shrink-0 transition-all duration-300">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3 shadow-lg"><Sparkles size={20} /></div>
          <span className="hidden md:block font-black text-xl text-slate-900 uppercase tracking-tighter">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {AVAILABLE_PERMISSIONS.map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center p-4 rounded-2xl transition-all ${activeTab === item.id ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>
              <item.icon size={22} className="mr-3" /> <span className="hidden md:block font-bold">{item.label}</span>
            </button>
          ))}
        </nav>
        <div className="p-4 border-t">
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center p-4 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all"><LogOut size={22} className="mr-3" /> <span className="hidden md:block">退出系统</span></button>
        </div>
      </aside>

      {/* 主视图 */}
      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b px-8 flex items-center justify-between shrink-0">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-widest">{activeTab.toUpperCase()}</h2>
          <div className="flex items-center gap-6">
            <div className="relative" ref={notificationRef}>
              <div className="p-2 hover:bg-slate-50 rounded-xl cursor-pointer relative" onClick={() => setShowNotifications(!showNotifications)}>
                {stats.pendingAppts > 0 && <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>}
                <Bell className="text-slate-400" size={20} />
              </div>
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden z-[120] animate-in slide-in-from-top-2">
                  <div className="p-4 bg-slate-50 border-b flex justify-between items-center">
                    <span className="text-xs font-black uppercase tracking-widest">通知中心</span>
                    <span className="text-[10px] bg-indigo-100 text-indigo-600 px-2 py-0.5 rounded-full font-bold">{stats.pendingAppts} 条新预约待办</span>
                  </div>
                  <div className="max-h-80 overflow-y-auto custom-scroll">
                    {stats.allPendingAppts.length > 0 ? stats.allPendingAppts.map(a => (
                      <div key={a.id} className="p-4 border-b hover:bg-indigo-50 transition-all cursor-pointer" onClick={() => { handleDashboardClick('appts'); setSelectedAppt(a); setShowNotifications(false); }}>
                        <p className="text-sm font-black">{a.customerName}</p>
                        <p className="text-xs text-slate-500">{a.projectName} - {a.startHour}:00</p>
                      </div>
                    )) : <div className="py-8 text-center text-slate-300 font-bold uppercase text-[10px]">暂无通知</div>}
                  </div>
                </div>
              )}
            </div>
            <button onClick={() => { setIsModalOpen('new_appt'); setIsQuickAddCustomer(false); }} className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg flex items-center gap-2 hover:bg-indigo-700 transition-all"><Plus size={18} /> 新增预约</button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scroll">
          {/* Dashboard */}
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                  { label: '今日现金', val: stats.todayCash, icon: Banknote, color: 'text-green-500', tab: 'finance', filter: 'cash' },
                  { label: '今日耗卡', val: stats.todayConsumption, icon: CreditCard, color: 'text-amber-500', tab: 'finance', filter: 'consume' },
                  { label: '今日充值', val: stats.todayRecharge, icon: Wallet, color: 'text-blue-500', tab: 'finance', filter: 'recharge' },
                  { label: '今日实收', val: stats.todayActual, icon: ArrowUpCircle, color: 'text-indigo-600', tab: 'finance', filter: 'all' },
                  { label: '本月营收', val: stats.monthlyRevenue, icon: TrendingUp, color: 'text-emerald-500', tab: 'finance', filter: 'all' },
                  { label: '待确定预约', val: stats.pendingAppts, icon: Bell, color: 'text-pink-500', tab: 'appts' },
                  { label: '今日预约', val: stats.todayAppts, icon: Calendar, color: 'text-orange-500', tab: 'appts' },
                  { label: '会员总数', val: stats.totalMembers, icon: Users, color: 'text-indigo-400', tab: 'customers' },
                ].map((s, i) => (
                  <div key={i} onClick={() => handleDashboardClick(s.tab, s.filter)} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm transition-all hover:scale-[1.03] hover:shadow-md cursor-pointer group">
                    <div className="flex justify-between items-start mb-1">
                      <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{s.label}</p>
                      <s.icon size={18} className={s.color} />
                    </div>
                    <h3 className="text-2xl font-black text-slate-900">{typeof s.val === 'number' && s.label.includes('今日') && !s.label.includes('预约') && !s.label.includes('总数') ? `¥${s.val.toLocaleString()}` : s.val.toLocaleString()}</h3>
                  </div>
                ))}
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                   <h3 className="font-black text-slate-800 uppercase tracking-widest mb-8">本周趋势 (实收)</h3>
                   <div className="h-64">
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={chartData}>
                          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                          <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                          <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                          <Tooltip cursor={{fill: '#f8fafc'}} />
                          <Bar dataKey="income" radius={[10, 10, 10, 10]} barSize={35}>
                            {chartData.map((e, idx) => <Cell key={idx} fill={idx === 6 ? '#4f46e5' : '#e2e8f0'} />)}
                          </Bar>
                        </BarChart>
                      </ResponsiveContainer>
                   </div>
                </div>
                <div className="bg-gradient-to-br from-slate-900 to-indigo-950 p-8 rounded-[3rem] shadow-xl text-white flex flex-col group relative overflow-hidden">
                  <Zap className="absolute -top-4 -right-4 text-white/5 w-32 h-32" />
                  <div className="relative z-10 flex flex-col h-full">
                    <div className="flex items-center gap-3 mb-6"><Sparkles className="text-indigo-400" /><h3 className="font-black uppercase tracking-widest">AI 智能经营顾问</h3></div>
                    <div className="flex-1 text-xs leading-relaxed text-indigo-100 font-medium whitespace-pre-wrap overflow-y-auto custom-scroll pr-2">{aiAnalysis || '正在加载建议...'}</div>
                    <button onClick={() => { setIsAnalyzing(true); handleAiAnalyze(); }} className="mt-6 w-full py-4 bg-white text-indigo-950 rounded-2xl font-black text-[10px] uppercase shadow-lg hover:bg-indigo-50">刷新分析</button>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Appts Tab */}
          {activeTab === 'appts' && (
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col h-full animate-in slide-in-from-bottom-8">
              <div className="p-6 border-b flex justify-between items-center">
                <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setViewMode('day')} className={`px-4 py-2 rounded-lg text-sm font-bold ${viewMode === 'day' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>日排班表</button>
                  <button onClick={() => setViewMode('month')} className={`px-4 py-2 rounded-lg text-sm font-bold ${viewMode === 'month' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>月历总览</button>
                </div>
                <div className="flex items-center gap-4">
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() - 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronLeft/></button>
                  <span className="font-black text-slate-800 uppercase tracking-widest">{selectedDate.getFullYear()}年 {selectedDate.getMonth() + 1}月 {viewMode === 'day' && `${selectedDate.getDate()}日`}</span>
                  <button onClick={() => setSelectedDate(new Date(selectedDate.setMonth(selectedDate.getMonth() + 1)))} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><ChevronRight/></button>
                </div>
              </div>
              <div className="flex-1 overflow-auto p-6 custom-scroll">
                {viewMode === 'day' ? (
                  <div className="min-w-[1300px]">
                    <div className="flex ml-48 border-b mb-4 pb-2">
                      {Array.from({length: 15}, (_, i) => (<div key={i} className="flex-1 text-center text-[10px] font-black text-slate-400 border-r last:border-r-0 uppercase tracking-tighter">{i + 8}:00</div>))}
                    </div>
                    {staff.map(s => (
                      <div key={s.id} className="flex items-center h-24 border-b border-slate-50 group">
                        <div className="w-48 sticky left-0 bg-white z-10 pr-6 flex items-center gap-3">
                          <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center font-black text-indigo-600 border border-indigo-100">{s.avatar}</div>
                          <div><div className="text-xs font-bold text-slate-800">{s.name}</div><div className="text-[10px] text-slate-400">{s.role}</div></div>
                        </div>
                        <div className="flex-1 relative h-full flex" onClick={() => { setPrefillData({staffId: s.id}); setIsModalOpen('new_appt'); }}>
                          {Array.from({length: 15}).map((_, i) => <div key={i} className="flex-1 border-r border-slate-50 h-full pointer-events-none"></div>)}
                          {appointments.filter(a => a.staffId === s.id && new Date(a.startTime).toDateString() === selectedDate.toDateString()).map(a => (
                            <div key={a.id} onClick={(e) => { e.stopPropagation(); setSelectedAppt(a); }} className={`absolute top-2 bottom-2 rounded-xl p-3 shadow-md cursor-pointer hover:scale-[1.02] border-l-4 overflow-hidden ${a.status === 'pending' ? 'bg-amber-50 border-amber-500 animate-pulse' : a.status === 'confirmed' ? 'bg-indigo-50 border-indigo-500' : 'bg-green-50 border-green-500'}`} style={{ left: `${((a.startHour - 8) / 15) * 100}%`, width: `${(a.duration / 15) * 100}%` }}>
                              <div className="text-[11px] font-black text-slate-800 truncate">{a.customerName}</div>
                              <div className="text-[9px] text-slate-500 truncate">{a.projectName}</div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="grid grid-cols-7 gap-4">
                    {['周日','周一','周二','周三','周四','周五','周六'].map(d => <div key={d} className="py-2 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">{d}</div>)}
                    {Array.from({length: new Date(selectedDate.getFullYear(), selectedDate.getMonth() + 1, 0).getDate()}, (_, i) => (
                      <div key={i} onClick={() => handleMonthDayClick(i)} className="bg-white border rounded-[2rem] p-4 min-h-[120px] hover:bg-indigo-50 transition-all cursor-pointer shadow-sm group">
                        <span className="text-xs font-black text-slate-300 group-hover:text-indigo-600">{i + 1}</span>
                        <div className="mt-2 space-y-1">
                          {appointments.filter(a => new Date(a.startTime).getDate() === i + 1 && new Date(a.startTime).getMonth() === selectedDate.getMonth() && new Date(a.startTime).getFullYear() === selectedDate.getFullYear()).slice(0, 3).map(a => (
                            <div key={a.id} className="text-[8px] px-1 py-0.5 bg-indigo-50 text-indigo-700 rounded-md font-bold truncate">{a.customerName}</div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Customers Tab */}
          {activeTab === 'customers' && (
            <div className="space-y-6 animate-in fade-in">
              <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between">
                <div className="flex items-center gap-3 bg-slate-50 px-5 py-3 rounded-2xl w-full max-w-md border border-transparent focus-within:border-indigo-500 transition-all">
                  <Search size={18} className="text-slate-400" />
                  <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="搜索姓名/手机号..." className="bg-transparent outline-none w-full text-sm font-bold text-slate-900" />
                </div>
                <button onClick={() => { setEditingTarget(null); setIsModalOpen('new_customer'); }} className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase flex items-center gap-2 hover:bg-black shadow-lg transition-all"><UserPlus size={16}/> 新增会员</button>
              </div>
              <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <tr><th className="px-8 py-5">客户姓名</th><th className="px-8 py-5">联系电话</th><th className="px-8 py-5">卡内余额</th><th className="px-8 py-5 text-right">操作管理</th></tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {customers.filter(c => c.name.includes(searchTerm) || c.phone.includes(searchTerm)).map(c => (
                      <tr key={c.id} className="hover:bg-slate-50/50 transition-all">
                        <td className="px-8 py-5 font-black text-slate-800">{c.name}</td>
                        <td className="px-8 py-5 font-bold text-slate-500">{c.phone}</td>
                        <td className="px-8 py-5 font-black text-indigo-600 uppercase">¥{c.balance.toLocaleString()}</td>
                        <td className="px-8 py-5 text-right space-x-6">
                          <button onClick={() => setIsModalOpen(`customer_profile_${c.id}`)} className="text-[10px] font-black uppercase text-slate-400 hover:text-indigo-600 underline transition-all">查看档案</button>
                          <button onClick={() => setIsModalOpen(`consume_${c.id}`)} className="text-[10px] font-black uppercase text-indigo-600 underline">结算/耗卡</button>
                          <button onClick={() => setIsModalOpen(`recharge_${c.id}`)} className="text-[10px] font-black uppercase text-slate-400 hover:text-slate-900">充值</button>
