                    const hour = parseInt((document.getElementById('apt-h') as HTMLInputElement).value);
                    const dur = parseInt((document.getElementById('apt-d') as HTMLInputElement).value);
                    if (cId && sId && prj) {
                      const apptId = `APT-${Date.now()}`;
                      setAppointments(prev => [...prev, { id: apptId, customerId: cId, customerName: cName, staffId: sId, projectName: prj, startTime: selectedDate.toISOString(), startHour: hour, duration: dur, status: 'pending' }]);
                      setIsModalOpen(null);
                      addLog('预约排期', `为客户 ${cName} 分派了 ${prj} 任务`);
                    }
                 }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] shadow-lg shadow-indigo-100 transition-all hover:bg-indigo-700">发布调度指令</button>
               </div>
            )}

            {/* 会员档案编辑 */}
            {(isModalOpen === 'new_customer' || isModalOpen === 'edit_customer') && (
              <div className="space-y-6">
                <h3 className="text-2xl font-black text-slate-800 uppercase tracking-widest">{isModalOpen === 'edit_customer' ? '档案更正' : '新会员入籍'}</h3>
                <div className="space-y-4">
                  <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">客户姓名</label><input id="nc-name" defaultValue={editingTarget?.name} placeholder="必填" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-400 outline-none font-bold text-slate-900" /></div>
                  <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">联系电话</label><input id="nc-phone" defaultValue={editingTarget?.phone} placeholder="必填" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-400 outline-none font-bold text-slate-900" /></div>
                  <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">特征备注</label><textarea id="nc-remarks" defaultValue={editingTarget?.remarks} placeholder="如：偏好、忌口等习惯" className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-400 outline-none font-bold text-slate-900 h-24" /></div>
                </div>
                <button onClick={() => {
                  const n = (document.getElementById('nc-name') as HTMLInputElement).value;
                  const p = (document.getElementById('nc-phone') as HTMLInputElement).value;
                  const r = (document.getElementById('nc-remarks') as HTMLTextAreaElement).value;
                  if (n && p) {
                    if (isModalOpen === 'edit_customer' && editingTarget) {
                      setCustomers(prev => prev.map(c => c.id === editingTarget.id ? { ...c, name: n, phone: p, remarks: r } : c));
                    } else {
                      const id = `C-${Date.now()}`;
                      setCustomers(prev => [...prev, { id, name: n, phone: p, balance: 0, remarks: r, createdAt: new Date().toISOString() }]);
                      addLog('建档成功', `新会员 ${n} 已入籍系统`, { type: 'add_customer', targetId: id });
                    }
                    setIsModalOpen(null);
                  }
                }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] shadow-lg transition-all hover:bg-black">保存档案信息</button>
              </div>
            )}

            {/* 员工档案（自定义岗位） */}
            {(isModalOpen === 'new_staff' || isModalOpen === 'edit_staff') && (
               <div className="space-y-6">
                 <h3 className="text-2xl font-black text-slate-800 uppercase tracking-widest">{isModalOpen === 'edit_staff' ? '职员档案更正' : '职员入职登记'}</h3>
                 <div className="space-y-4">
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">职员姓名</label><input id="st-name" defaultValue={editingTarget?.name} className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">自定义岗位名称</label><input id="st-role" defaultValue={editingTarget?.role} placeholder="如：首席造型师" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-2">登录密码</label><input id="st-pass" type="password" placeholder="建议包含字母数字" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                 </div>
                 <div className="space-y-2 pt-4 border-t border-slate-50">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">系统模块访问授权</label>
                    <div className="grid grid-cols-2 gap-3">
                       {AVAILABLE_PERMISSIONS.map(p => (
                          <div key={p.id} onClick={() => setStaffPermissions(prev => prev.includes(p.id) ? prev.filter(x => x !== p.id) : [...prev, p.id])} className={`p-3 rounded-xl border-2 transition-all cursor-pointer flex items-center gap-2 ${staffPermissions.includes(p.id) ? 'bg-indigo-50 border-indigo-500 text-indigo-700' : 'bg-slate-50 border-transparent text-slate-400'}`}>
                             <p.icon size={14}/> <span className="text-[10px] font-bold uppercase">{p.label}</span>
                          </div>
                       ))}
                    </div>
                 </div>
                 <button onClick={() => {
                    const n = (document.getElementById('st-name') as HTMLInputElement).value;
                    const r = (document.getElementById('st-role') as HTMLInputElement).value;
                    const p = (document.getElementById('st-pass') as HTMLInputElement).value;
                    if (n && r) {
                      if (isModalOpen === 'edit_staff' && editingTarget) {
                        setStaff(prev => prev.map(s => s.id === editingTarget.id ? { ...s, name: n, role: r, password: p || s.password, permissions: staffPermissions } : s));
                      } else {
                        setStaff(prev => [...prev, { id: `S-${Date.now()}`, name: n, role: r, password: p, avatar: n[0].toUpperCase(), permissions: staffPermissions }]);
                      }
                      setIsModalOpen(null);
                    }
                 }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] shadow-lg">确认保存资料</button>
               </div>
            )}

            {/* 充值界面 */}
            {isModalOpen?.startsWith('recharge_') && (
               <div className="space-y-6">
                 <h3 className="text-2xl font-black text-slate-800 text-center uppercase tracking-widest">账户钱包充值</h3>
                 <div className="grid grid-cols-2 gap-4">
                    {[500, 1000, 2000, 5000].map(v => (
                       <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v)} className="py-8 border-2 border-slate-50 rounded-3xl font-black text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all flex flex-col items-center">
                          <span className="text-[10px] opacity-40 uppercase">预设额度</span>
                          <span className="text-2xl font-black">¥{v}</span>
                       </button>
                    ))}
                 </div>
                 <div className="space-y-1 pt-4 border-t border-slate-50">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">手动输入金额 (¥)</label>
                    <div className="flex gap-4">
                      <input id="rec-custom" type="number" placeholder="请输入金额" className="flex-1 p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-400 outline-none font-bold text-slate-900" />
                      <button onClick={() => {
                        const v = parseInt((document.getElementById('rec-custom') as HTMLInputElement).value);
                        if (v > 0) handleRecharge(isModalOpen.split('_')[1], v);
                      }} className="px-6 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase">确认充值</button>
                    </div>
                 </div>
               </div>
            )}

            {/* 结算界面 */}
            {isModalOpen?.startsWith('consume_') && (
               <div className="space-y-6 text-center">
                  <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mx-auto shadow-inner"><ReceiptText size={28}/></div>
                  <h3 className="text-2xl font-black text-slate-900 uppercase tracking-widest">财务结算对账</h3>
                  <div className="p-6 bg-slate-50 rounded-3xl text-left">
                     <p className="text-[10px] font-black text-slate-400 uppercase mb-1">正在核算客户</p>
                     <p className="text-xl font-black text-slate-800">{customers.find(c => c.id === isModalOpen.split('_')[1])?.name}</p>
                  </div>
                  <div className="space-y-1 text-left">
                     <label className="text-[10px] font-black text-slate-400 uppercase ml-2">应收账单金额 (¥)</label>
                     <input id="cons-amt" type="number" placeholder="0.00" className="w-full p-5 bg-slate-50 rounded-3xl font-black text-3xl text-slate-900 placeholder:text-slate-200 outline-none" />
                  </div>
                  <div className="flex gap-4 pt-4">
                     <button onClick={() => {
                       const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                       if (a >= 0) handleConsume(isModalOpen.split('_')[1], a, '店内项目消费', 'balance', isModalOpen.split('_')[3]);
                     }} className="flex-1 py-5 bg-indigo-600 text-white rounded-[2rem] font-black text-[10px] uppercase shadow-lg shadow-indigo-100">余额耗卡</button>
                     <button onClick={() => {
                       const a = parseInt((document.getElementById('cons-amt') as HTMLInputElement).value);
                       if (a >= 0) handleConsume(isModalOpen.split('_')[1], a, '店内项目消费', 'cash', isModalOpen.split('_')[3]);
                     }} className="flex-1 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-[10px] uppercase shadow-lg">现金/微信支付</button>
                  </div>
               </div>
            )}

            {/* 预约详情卡 */}
            {selectedAppt && !revokingLog && (
               <div className="space-y-8 animate-in fade-in">
                  <div className="flex justify-between items-start">
                     <div className="w-16 h-16 bg-indigo-50 rounded-[2rem] flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={28}/></div>
                     <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-3xl font-black text-slate-900">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={12}/> 执行技师: <span className="text-slate-800 font-black">{staff.find(s=>s.id === selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status === 'pending' && (
                        <button onClick={() => { setAppointments(prev => prev.map(a => a.id === selectedAppt.id ? {...a, status: 'confirmed'} : a)); setSelectedAppt(null); addLog('开始任务', `确认了 ${selectedAppt.customerName} 的服务申请`); }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700">开始接待受理</button>
                     )}
                     {selectedAppt.status === 'confirmed' && (
                        <button onClick={() => { setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null); }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase hover:bg-black transition-all">完工去结算</button>
                     )}
                     <button onClick={() => { if(confirm('确认废弃该任务单？')) { setAppointments(prev => prev.filter(a => a.id !== selectedAppt.id)); setSelectedAppt(null); addLog('作废单据', `已销毁预约单: ${selectedAppt.id}`); } }} className="w-full py-4 text-red-500 font-bold text-xs uppercase hover:underline">作废此单</button>
                  </div>
               </div>
            )}

            {/* 撤销确认 */}
            {revokingLog && (
               <div className="space-y-8 text-center animate-in zoom-in-95">
                  <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center text-red-600 mx-auto shadow-inner"><AlertTriangle size={32}/></div>
                  <div><h3 className="text-2xl font-black text-slate-900 mb-2">确认执行撤销？</h3><p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed">撤销后关联资产与业务状态将强制回滚，请确保您已知悉风险。</p></div>
                  <div className="flex gap-4"><button onClick={() => setRevokingLog(null)} className="flex-1 py-4 bg-slate-50 rounded-2xl font-black text-xs uppercase text-slate-400">放弃撤销</button><button onClick={handleRevokeConfirm} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-red-100 flex items-center justify-center gap-2"><Undo2 size={16}/> 立即回滚</button></div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2, Eye, History as HistoryIcon,
  ChevronUp, Minimize2, Maximize2
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班/预约', icon: Calendar },
  { id: 'customers', label: '会员管理', icon: Users },
  { id: 'finance', label: '财务报表', icon: History },
  { id: 'staff', label: '员工管理', icon: ShieldCheck },
  { id: 'logs', label: '操作日志', icon: Settings },
];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"总店长","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isAiShrunk, setIsAiShrunk] = useState(false);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 数据持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 统计计算 ---
  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    const todayAppts = appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length;

    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: consumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions
        .filter(t => new Date(t.timestamp).toDateString() === dateStr)
        .reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const start = financeStartDate ? new Date(financeStartDate).getTime() : 0;
      const end = financeEndDate ? new Date(financeEndDate).setHours(23, 59, 59, 999) : Infinity;
      const typeMatches = 
        activeFinanceFilter === 'all' ? true :
        activeFinanceFilter === 'recharge' ? t.type === 'recharge' :
        activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') :
        activeFinanceFilter === 'cash' ? (t.type === 'consume' && t.paymentMethod !== 'balance') : true;
      return tDate >= start && tDate <= end && typeMatches;
    });
  }, [transactions, financeStartDate, financeEndDate, activeFinanceFilter]);

  // --- 核心业务逻辑 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    const newLog: SystemLog = {
      id: `LOG-${Date.now()}`,
      operator: currentUser?.name || '系统',
      action,
      detail,
      timestamp: new Date().toISOString(),
      undoData,
      isRevoked: false
    };
    setLogs(prev => [newLog, ...prev].slice(0, 100));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) { setCurrentUser(found); addLog('系统登录', `员工 ${found.name} 登录成功`); } 
    else { alert('账号或密码错误'); }
  };

  const handleRecharge = (custId: string, amount: number, isSilent = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const transId = `TRX-${Date.now()}`;
    const cust = customers.find(c => c.id === custId);
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '余额充值', timestamp: new Date().toISOString() }, ...prev]);
    if (!isSilent) {
      addLog('充值', `${cust?.name} 充值 ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
      setIsModalOpen(null);
    }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string, remarks?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ 
      id: transId, 
      type: 'consume', 
      customerId: custId, 
      customerName: cust?.name || '未知', 
      amount, 
      paymentMethod: method, 
      itemName: itemName || '店内项目消费', 
      timestamp: new Date().toISOString() 
    }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} ${itemName} ¥${amount}${remarks ? ` (${remarks})` : ''}`, { 
      type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId 
    });
    setIsModalOpen(null);
  };

  const exportTransactionsToCSV = () => {
    const headers = ['单号', '类型', '详细分类', '客户', '金额', '项目', '时间'];
    const rows = filteredTransactions.map(t => [
      t.id,
      t.type === 'recharge' ? '充值' : '消费',
      t.type === 'recharge' ? '现金充值' : (t.paymentMethod === 'balance' ? '余额耗卡' : '现金实收'),
      t.customerName,
      t.amount,
      t.itemName,
      new Date(t.timestamp).toLocaleString()
    ]);
    const csvContent = "\ufeff" + [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `BeautyPro_财务报表_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

