                     <div className="w-16 h-16 bg-indigo-50 rounded-[2rem] flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={28}/></div>
                     <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-3xl font-black text-slate-900 tracking-tight">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-black text-indigo-500 uppercase tracking-widest mt-1">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={12}/> 当前分派职员: <span className="text-slate-800 font-black">{staff.find(s=>s.id === selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status === 'pending' && (
                        <button onClick={() => { setAppointments(prev => prev.map(a => a.id === selectedAppt.id ? {...a, status: 'confirmed'} : a)); setSelectedAppt(null); addLog('开始任务', `已确认并开始服务 ${selectedAppt.customerName}`); }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">确认并开始服务</button>
                     )}
                     {selectedAppt.status === 'confirmed' && (
                        <button onClick={() => { setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null); }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase hover:bg-black transition-all">完工结算</button>
                     )}
                     <button onClick={() => { if(confirm('确定作废此预约？')) { setAppointments(prev => prev.filter(a => a.id !== selectedAppt.id)); setSelectedAppt(null); addLog('作废预约', `已删除预约 ID: ${selectedAppt.id}`); } }} className="w-full py-4 text-red-500 font-black text-xs uppercase hover:underline">作废该任务单</button>
                  </div>
               </div>
            )}

            {/* 日志撤销确认 */}
            {revokingLog && (
               <div className="space-y-8 text-center animate-in zoom-in-95 duration-300">
                  <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center text-red-600 mx-auto shadow-inner"><AlertTriangle size={32}/></div>
                  <div><h3 className="text-2xl font-black text-slate-900 mb-2">确认撤销此笔业务？</h3><p className="text-[10px] text-slate-500 font-black uppercase tracking-widest leading-relaxed px-8">撤销后相关的金额、会员积分及任务状态将尝试回滚到操作前的状态。</p></div>
                  <div className="flex gap-4"><button onClick={() => setRevokingLog(null)} className="flex-1 py-4 bg-slate-50 rounded-2xl font-black text-xs uppercase text-slate-400">放弃撤销</button><button onClick={handleRevokeConfirm} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-red-100 flex items-center justify-center gap-2"><Undo2 size={16}/> 立即执行回滚</button></div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

