                      <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">选择会员</label><select id="apt-c" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900">{customers.map(c => <option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}</select></div>
                    )}
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">执行职员</label><select id="apt-s" defaultValue={prefillData?.staffId} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900 border-2 border-transparent focus:border-indigo-400 outline-none">{staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select></div>
                      <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">项目名称</label><input id="apt-p" placeholder="如：剪发" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-slate-900 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                    </div>
                 </div>
                 <button onClick={() => {
                    let cId = ""; let cName = "";
                    if (isQuickAddCustomer) {
                      const n = (document.getElementById('apt-nc-name') as HTMLInputElement).value;
                      const p = (document.getElementById('apt-nc-phone') as HTMLInputElement).value;
                      const init = parseInt((document.getElementById('apt-nc-init') as HTMLInputElement).value) || 0;
                      if (!n || !p) return alert("基础信息必填");
                      cId = `C-${Date.now()}`; cName = n;
                      setCustomers(prev => [...prev, { id: cId, name: n, phone: p, balance: 0, remarks: '极速录入', createdAt: new Date().toISOString() }]);
                      if (init > 0) handleRecharge(cId, init, true);
                    } else {
                      cId = (document.getElementById('apt-c') as HTMLSelectElement).value;
                      cName = customers.find(c => c.id === cId)?.name || '';
                    }
                    const sId = (document.getElementById('apt-s') as HTMLSelectElement).value;
                    const prj = (document.getElementById('apt-p') as HTMLInputElement).value;
                    if (cId && sId && prj) {
                      setAppointments(prev => [...prev, { id: `APT-${Date.now()}`, customerId: cId, customerName: cName, staffId: sId, projectName: prj, startTime: selectedDate.toISOString(), startHour: 10, duration: 1, status: 'pending' }]);
                      setIsModalOpen(null);
                      addLog('预约排期', cName);
                    }
                 }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] shadow-lg hover:bg-indigo-700 transition-all">发布任务指令</button>
               </div>
            )}

            {/* 会员档案编辑 */}
            {(isModalOpen === 'new_customer' || isModalOpen === 'edit_customer') && (
              <div className="space-y-6 animate-in slide-in-from-bottom-4">
                <h3 className="text-2xl font-black text-slate-800 uppercase tracking-widest">{isModalOpen === 'edit_customer' ? '档案更正' : '入籍新会员'}</h3>
                <div className="space-y-4">
                  <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">客户姓名 *</label><input id="nc-name" defaultValue={editingTarget?.name} placeholder="必填" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" /></div>
                  <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">联系电话 *</label><input id="nc-phone" defaultValue={editingTarget?.phone} placeholder="必填" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" /></div>
                  <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">详细特征/喜好</label><textarea id="nc-remarks" defaultValue={editingTarget?.remarks} className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900 h-24" /></div>
                </div>
                <button onClick={() => {
                  const n = (document.getElementById('nc-name') as HTMLInputElement).value;
                  const p = (document.getElementById('nc-phone') as HTMLInputElement).value;
                  const r = (document.getElementById('nc-remarks') as HTMLTextAreaElement).value;
                  if (n && p) {
                    if (isModalOpen === 'edit_customer' && editingTarget) {
                      setCustomers(prev => prev.map(c => c.id === editingTarget.id ? { ...c, name: n, phone: p, remarks: r } : c));
                    } else {
                      const id = `C-${Date.now()}`;
                      setCustomers(prev => [...prev, { id, name: n, phone: p, balance: 0, remarks: r, createdAt: new Date().toISOString() }]);
                      addLog('新增会员', n);
                    }
                    setIsModalOpen(null);
                  }
                }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] shadow-lg transition-all">确认并保存</button>
              </div>
            )}

            {/* 员工档案 */}
            {(isModalOpen === 'new_staff' || isModalOpen === 'edit_staff') && (
               <div className="space-y-6">
                 <h3 className="text-2xl font-black text-slate-800 uppercase tracking-widest">{isModalOpen === 'edit_staff' ? '职员档案更正' : '入职登记'}</h3>
                 <div className="space-y-4">
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">姓名 *</label><input id="st-name" defaultValue={editingTarget?.name} className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" /></div>
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">自定义岗位 *</label><input id="st-role" defaultValue={editingTarget?.role} placeholder="如：首席技师" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" /></div>
                    <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">系统密码</label><input id="st-pass" type="password" placeholder="不修改请留空" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" /></div>
                 </div>
                 <div className="space-y-2 pt-4 border-t border-slate-50">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">模块授权</label>
                    <div className="grid grid-cols-2 gap-3">
                       {AVAILABLE_PERMISSIONS.map(p => (
                          <div key={p.id} onClick={() => setStaffPermissions(prev => prev.includes(p.id) ? prev.filter(x => x !== p.id) : [...prev, p.id])} className={`p-3 rounded-xl border-2 transition-all cursor-pointer flex items-center gap-2 ${staffPermissions.includes(p.id) ? 'bg-indigo-50 border-indigo-500 text-indigo-700' : 'bg-slate-50 border-transparent text-slate-400 hover:bg-slate-100'}`}>
                             <p.icon size={14}/> <span className="text-[10px] font-bold uppercase">{p.label}</span>
                          </div>
                       ))}
                    </div>
                 </div>
                 <button onClick={() => {
                    const n = (document.getElementById('st-name') as HTMLInputElement).value;
                    const r = (document.getElementById('st-role') as HTMLInputElement).value;
                    const p = (document.getElementById('st-pass') as HTMLInputElement).value;
                    if (n && r) {
                      if (isModalOpen === 'edit_staff' && editingTarget) {
                        setStaff(prev => prev.map(s => s.id === editingTarget.id ? { ...s, name: n, role: r, password: p || s.password, permissions: staffPermissions } : s));
                      } else {
                        setStaff(prev => [...prev, { id: `S-${Date.now()}`, name: n, role: r, password: p, avatar: n[0].toUpperCase(), permissions: staffPermissions }]);
                      }
                      setIsModalOpen(null);
                    }
                 }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px] shadow-lg tracking-widest">确认保存</button>
               </div>
            )}

            {/* 充值界面 */}
            {isModalOpen?.startsWith('recharge_') && (
               <div className="space-y-6">
                 <h3 className="text-2xl font-black text-slate-800 text-center uppercase tracking-widest">钱包充值</h3>
                 <div className="grid grid-cols-2 gap-4">
                    {[500, 1000, 2000, 5000].map(v => (
                       <button key={v} onClick={() => handleRecharge(isModalOpen.split('_')[1], v)} className="py-8 border-2 border-slate-100 rounded-3xl font-black text-slate-600 hover:border-indigo-600 hover:text-indigo-600 transition-all flex flex-col items-center">
                          <span className="text-[10px] opacity-40 uppercase tracking-widest font-black">特惠额度</span>
                          <span className="text-2xl font-black">¥{v}</span>
                       </button>
                    ))}
                 </div>
                 <div className="space-y-1 pt-4 border-t border-slate-100">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">手动输入金额 (¥)</label>
                    <div className="flex gap-4">
                      <input id="rec-custom" type="number" placeholder="金额" className="flex-1 p-4 bg-slate-50 rounded-2xl font-black border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" />
                      <button onClick={() => {
                        const v = parseInt((document.getElementById('rec-custom') as HTMLInputElement).value);
                        if (v > 0) handleRecharge(isModalOpen.split('_')[1], v);
                      }} className="px-6 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg">确认入账</button>
                    </div>
                 </div>
               </div>
            )}

            {/* 预约卡片详情 */}
            {selectedAppt && !revokingLog && (
               <div className="space-y-8 animate-in fade-in">
                  <div className="flex justify-between items-start">
                     <div className="w-16 h-16 bg-indigo-50 rounded-[2rem] flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={28}/></div>
                     <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${selectedAppt.status === 'pending' ? 'bg-amber-100 text-amber-600' : 'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-3xl font-bold text-slate-900">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={12}/> 当前执行: <span className="text-slate-800 font-bold">{staff.find(s=>s.id === selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status === 'pending' && (
                        <button onClick={() => { setAppointments(prev => prev.map(a => a.id === selectedAppt.id ? {...a, status: 'confirmed'} : a)); setSelectedAppt(null); addLog('开始任务', selectedAppt.customerName); }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">开始受理</button>
                     )}
                     {selectedAppt.status === 'confirmed' && (
                        <button onClick={() => { setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null); }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase hover:bg-black transition-all">确认完工</button>
                     )}
                     <button onClick={() => { if(confirm('废弃此预约？')) { setAppointments(prev => prev.filter(a => a.id !== selectedAppt.id)); setSelectedAppt(null); } }} className="w-full py-4 text-red-500 font-bold text-xs uppercase hover:underline">作废单据</button>
                  </div>
               </div>
            )}

            {/* 回滚确认 */}
            {revokingLog && (
               <div className="space-y-8 text-center animate-in zoom-in-95 duration-300">
                  <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center text-red-600 mx-auto shadow-inner"><AlertTriangle size={32}/></div>
                  <div><h3 className="text-2xl font-black text-slate-900 mb-2">确认撤销该业务？</h3><p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed">此操作将强制回退金额与状态，请确保已人工核对流水。</p></div>
                  <div className="flex gap-4"><button onClick={() => setRevokingLog(null)} className="flex-1 py-4 bg-slate-50 rounded-2xl font-black text-xs uppercase text-slate-400">取消</button><button onClick={handleRevokeConfirm} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-red-100 flex items-center justify-center gap-2"><Undo2 size={16}/> 立即执行回滚</button></div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2, Eye, History as HistoryIcon,
  Minimize2, Maximize2, MousePointer2, MessageSquareText
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班', icon: Calendar },
  { id: 'customers', label: '会员', icon: Users },
  { id: 'finance', label: '流水', icon: History },
  { id: 'staff', label: '员工', icon: ShieldCheck },
  { id: 'logs', label: '日志', icon: Settings },
];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"总店长","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isAiShrunk, setIsAiShrunk] = useState(true); // 默认缩小
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const notificationRef = useRef<HTMLDivElement>(null);

  // 拖拽移动排班表
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  // --- 持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 统计 ---
  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: consumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts: appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions.filter(t => new Date(t.timestamp).toDateString() === dateStr).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const typeMatches = activeFinanceFilter === 'all' ? true : activeFinanceFilter === 'recharge' ? t.type === 'recharge' : activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') : t.type === 'consume' && t.paymentMethod !== 'balance';
      return typeMatches;
    });
  }, [transactions, activeFinanceFilter]);

  // --- 逻辑函数 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    setLogs(prev => [{ id: `LOG-${Date.now()}`, operator: currentUser?.name || '系统', action, detail, timestamp: new Date().toISOString(), undoData, isRevoked: false }, ...prev].slice(0, 100));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) { setCurrentUser(found); addLog('登录', found.name); } 
    else alert('登录失败');
  };

  const handleRecharge = (custId: string, amount: number, isSilent = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '充值', timestamp: new Date().toISOString() }, ...prev]);
    if (!isSilent) { addLog('充值', `${cust?.name} ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount }); setIsModalOpen(null); }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string, remarks?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName: itemName || '服务', timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} ${itemName} ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData) return;
    const { type, targetId, secondaryId, amount, prevStatus, paymentMethod } = revokingLog.undoData;
    if (type === 'recharge') {
      setTransactions(prev => prev.filter(t => t.id !== targetId));
      if (secondaryId) setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: Math.max(0, c.balance - (amount || 0)) } : c));
    } else if (type === 'consume') {
      setTransactions(prev => prev.filter(t => t.id !== targetId));
      if (secondaryId && paymentMethod === 'balance') setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance + (amount || 0) } : c));
      if (prevStatus) setAppointments(prev => prev.map(a => a.id === prevStatus ? { ...a, status: 'confirmed' } : a));
    }
    setLogs(prev => prev.map(l => l.id === revokingLog.id ? { ...l, isRevoked: true } : l));
    addLog('撤销', revokingLog.action);
    setRevokingLog(null);
  };

  const handleAiAnalyze = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const result = await analyzeBusinessData({ summary: stats });
      setAiAnalysis(result);
      setIsAiShrunk(false);
    } catch (e) { setAiAnalysis("分析受阻"); } finally { setIsAnalyzing(false); }
  };

  useEffect(() => {
    if (activeTab === 'dashboard' && !aiAnalysis) handleAiAnalyze();
  }, [activeTab]);

  // 排班拖拽
  const handleMouseDown = (e: React.MouseEvent) => {
    if (!scrollContainerRef.current) return;
    setIsDragging(true);
    setStartX(e.pageX - scrollContainerRef.current.offsetLeft);
    setScrollLeft(scrollContainerRef.current.scrollLeft);
  };
  const onMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !scrollContainerRef.current) return;
    e.preventDefault();
    const walk = (e.pageX - scrollContainerRef.current.offsetLeft - startX) * 2;
    scrollContainerRef.current.scrollLeft = scrollLeft - walk;
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white rounded-[3rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
