              <input id="login-pass" type="password" required className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" placeholder="密码" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest">进入系统</button>
