          <div className="relative z-10 bg-white w-full max-w-lg rounded-t-[3rem] md:rounded-[3rem] p-8 md:p-10 shadow-2xl overflow-y-auto max-h-[90vh] custom-scroll animate-in slide-in-from-bottom-10 md:zoom-in-95">

            {isModalOpen?.startsWith('customer_profile_') && (() => {
               const custId = isModalOpen.split('_')[2];
               const cust = customers.find(c => c.id === custId);
               if (!cust) return null;
               const histTrans = transactions.filter(t => t.customerId === custId).sort((a,b)=>new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
               return (
                  <div className="space-y-8">
                     <div className="flex justify-between items-start">
                        <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 text-2xl font-black">{cust.name[0]}</div>
                        <div className="flex gap-2">
                          <button onClick={()=>{setEditingTarget(cust);setIsModalOpen('edit_customer');}} className="p-3 bg-slate-50 rounded-xl text-slate-400 hover:text-indigo-600 transition-all"><Edit3 size={18}/></button>
                          <button onClick={()=>setIsModalOpen(null)} className="p-3 bg-slate-50 rounded-xl text-slate-400 hover:text-red-500"><X size={18}/></button>
                        </div>
                     </div>
                     <div>
                        <h3 className="text-2xl font-black text-slate-900">{cust.name}</h3>
                        <p className="text-slate-400 font-bold mt-1 tracking-widest text-sm">{cust.phone}</p>
                        <div className="mt-4 flex gap-4">
                           <div className="bg-indigo-50 p-4 rounded-3xl flex-1 text-center"><p className="text-[9px] font-black uppercase text-indigo-400 mb-1">当前余额</p><p className="text-lg font-black text-indigo-600">¥{cust.balance.toLocaleString()}</p></div>
                           <div className="bg-slate-50 p-4 rounded-3xl flex-1 text-center"><p className="text-[9px] font-black uppercase text-slate-400 mb-1">建档日期</p><p className="text-xs font-bold text-slate-800">{new Date(cust.createdAt).toLocaleDateString()}</p></div>
                        </div>
                     </div>
                     <div className="space-y-4">
                        <h4 className="font-black uppercase tracking-widest text-[10px] text-indigo-600 flex items-center gap-2"><HistoryIcon size={14}/> 全部消费轨迹 ({histTrans.length})</h4>
                        <div className="space-y-2 max-h-48 overflow-y-auto custom-scroll pr-1">
                           {histTrans.map(t=>(
                              <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-2xl flex justify-between items-center text-xs">
                                 <div><p className="font-bold text-slate-800">{t.itemName}</p><p className="text-[9px] text-slate-300 font-bold">{new Date(t.timestamp).toLocaleDateString()}</p></div>
                                 <p className={`font-black ${t.type==='recharge'?'text-green-600':'text-slate-900'}`}>{t.type==='recharge'?'+':'-'}¥{t.amount}</p>
                              </div>
                           ))}
                        </div>
                     </div>
                  </div>
               );
            })()}

            {isModalOpen?.startsWith('consume_') && (
               <div className="space-y-6 text-center">
                  <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mx-auto shadow-inner"><ReceiptText size={24}/></div>
                  <h3 className="text-xl font-black text-slate-900 uppercase">单据结算</h3>
                  <div className="p-5 bg-slate-50 rounded-3xl text-left border"><p className="text-[9px] font-black uppercase text-slate-400 mb-1">核算客户</p><p className="text-lg font-bold text-slate-800">{customers.find(c=>c.id===isModalOpen.split('_')[1])?.name}</p></div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1 text-left"><label className="text-[9px] font-black text-slate-400 uppercase ml-2">金额 *</label><input id="cons-amt" type="number" placeholder="¥ 0.00" className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xl text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" /></div>
                    <div className="space-y-1 text-left"><label className="text-[9px] font-black text-slate-400 uppercase ml-2">项目 *</label><input id="cons-item" placeholder="项目名" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" defaultValue={selectedAppt?.projectName || "标准服务"} /></div>
                  </div>
                  <div className="space-y-1 text-left"><label className="text-[9px] font-black text-slate-400 uppercase ml-2">备注</label><input id="cons-note" placeholder="选填备注" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" /></div>
                  <div className="flex gap-4 pt-4">
                     <button onClick={()=>{const a=parseInt((document.getElementById('cons-amt')as any).value);const i=(document.getElementById('cons-item')as any).value;if(a>=0&&i)handleConsume(isModalOpen.split('_')[1],a,i,'balance',isModalOpen.split('_')[3]);else alert('补全信息');}} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-indigo-100">余额耗卡</button>
                     <button onClick={()=>{const a=parseInt((document.getElementById('cons-amt')as any).value);const i=(document.getElementById('cons-item')as any).value;if(a>=0&&i)handleConsume(isModalOpen.split('_')[1],a,i,'cash',isModalOpen.split('_')[3]);else alert('补全信息');}} className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase shadow-lg">现金结算</button>
                  </div>
               </div>
            )}

            {isModalOpen === 'new_appt' && (
               <div className="space-y-6">
                 <h3 className="text-xl font-black text-slate-800 uppercase text-center">排期调度</h3>
                 <div className="flex p-1 bg-slate-100 rounded-2xl">
                    <button onClick={()=>setIsQuickAddCustomer(false)} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${!isQuickAddCustomer?'bg-white shadow-sm text-indigo-600':'text-slate-400'}`}>会员库</button>
                    <button onClick={()=>setIsQuickAddCustomer(true)} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${isQuickAddCustomer?'bg-white shadow-sm text-indigo-600':'text-slate-400'}`}>快速录入</button>
                 </div>
                 <div className="space-y-4">
                    {isQuickAddCustomer ? (
                      <div className="grid grid-cols-2 gap-4">
                        <input id="apt-nc-name" placeholder="姓名 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none" />
                        <input id="apt-nc-phone" placeholder="手机 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none" />
                        <div className="col-span-2"><input id="apt-nc-init" type="number" placeholder="首笔充值金额 (选填)" className="w-full p-4 bg-indigo-50/50 rounded-2xl font-black text-indigo-600 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                      </div>
                    ) : (
                      <select id="apt-c" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none">{customers.map(c=><option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}</select>
                    )}
                    <div className="grid grid-cols-2 gap-4">
                      <select id="apt-s" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none">{staff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select>
                      <input id="apt-p" placeholder="服务项目 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none" />
                    </div>
                 </div>
                 <button onClick={()=>{
                    let cId="",cName="";
                    if(isQuickAddCustomer){const n=(document.getElementById('apt-nc-name')as any).value,p=(document.getElementById('apt-nc-phone')as any).value,init=parseInt((document.getElementById('apt-nc-init')as any).value)||0;if(!n||!p)return alert('补全信息');cId=`C-${Date.now()}`;cName=n;setCustomers(prev=>[...prev,{id:cId,name:n,phone:p,balance:0,remarks:'极速录入',createdAt:new Date().toISOString()}]);if(init>0)handleRecharge(cId,init,true);}
                    else{cId=(document.getElementById('apt-c')as any).value;cName=customers.find(c=>c.id===cId)?.name||"";}
                    const sId=(document.getElementById('apt-s')as any).value,prj=(document.getElementById('apt-p')as any).value;
                    if(cId&&sId&&prj){setAppointments(prev=>[...prev,{id:`APT-${Date.now()}`,customerId:cId,customerName:cName,staffId:sId,projectName:prj,startTime:selectedDate.toISOString(),startHour:10,duration:1,status:'pending'}]);setIsModalOpen(null);addLog('排期',cName);}
                 }} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg">确认排期</button>
               </div>
            )}

            {revokingLog && (
               <div className="space-y-6 text-center animate-in zoom-in-95">
                  <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center text-red-600 mx-auto"><AlertTriangle size={28}/></div>
                  <div><h3 className="text-xl font-black text-slate-900 mb-2">确认撤销该笔业务？</h3><p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest px-8">撤销后对应的金额及预约状态将尝试回滚，不可再次恢复。</p></div>
                  <div className="flex gap-4"><button onClick={()=>setRevokingLog(null)} className="flex-1 py-4 bg-slate-50 rounded-2xl font-black text-xs uppercase text-slate-400">取消</button><button onClick={handleRevokeConfirm} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg">立即回滚</button></div>
               </div>
            )}

            {selectedAppt && !revokingLog && (
               <div className="space-y-8">
                  <div className="flex justify-between items-start">
                     <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={24}/></div>
                     <span className={`text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${selectedAppt.status==='pending'?'bg-amber-100 text-amber-600':'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-2xl font-black text-slate-900">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={14}/> 执行技师: <span className="text-slate-800">{staff.find(s=>s.id===selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status==='pending' && <button onClick={()=>{setAppointments(prev=>prev.map(a=>a.id===selectedAppt.id?{...a,status:'confirmed'}:a));setSelectedAppt(null);addLog('开始受理',selectedAppt.customerName);}} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg">确认开始受理</button>}
                     {selectedAppt.status==='confirmed' && <button onClick={()=>{setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`);setSelectedAppt(null);}} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase">完工结算</button>}
                     <button onClick={()=>{if(confirm('删除此单？')){setAppointments(prev=>prev.filter(a=>a.id!==selectedAppt.id));setSelectedAppt(null);}}} className="w-full py-3 text-red-500 font-bold text-xs uppercase underline">作废该任务单</button>
                  </div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2, Eye, History as HistoryIcon,
  Minimize2, Maximize2, MousePointer2, MessageSquareText
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班', icon: Calendar },
  { id: 'customers', label: '会员', icon: Users },
  { id: 'finance', label: '流水', icon: History },
  { id: 'staff', label: '员工', icon: ShieldCheck },
  { id: 'logs', label: '日志', icon: Settings },
];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [financeStartDate, setFinanceStartDate] = useState('');
  const [financeEndDate, setFinanceEndDate] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"总店长","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [editingTarget, setEditingTarget] = useState<any>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isAiShrunk, setIsAiShrunk] = useState(true); // 默认缩小
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);

  const [prefillData, setPrefillData] = useState<{ staffId?: string; hour?: number } | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const [staffPermissions, setStaffPermissions] = useState<string[]>([]);
  const notificationRef = useRef<HTMLDivElement>(null);

  // 拖拽移动排班表
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  // --- 持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationRef.current && !notificationRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // --- 统计 ---
  const stats = useMemo(() => {
    const today = new Date();
    const todayStr = today.toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => {
      const d = new Date(t.timestamp);
      return d.getMonth() === today.getMonth() && d.getFullYear() === today.getFullYear();
    }).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: consumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts: appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toDateString();
      const income = transactions.filter(t => new Date(t.timestamp).toDateString() === dateStr).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      const tDate = new Date(t.timestamp).getTime();
      const typeMatches = activeFinanceFilter === 'all' ? true : activeFinanceFilter === 'recharge' ? t.type === 'recharge' : activeFinanceFilter === 'consume' ? (t.type === 'consume' && t.paymentMethod === 'balance') : t.type === 'consume' && t.paymentMethod !== 'balance';
      return typeMatches;
    });
  }, [transactions, activeFinanceFilter]);

  // --- 逻辑函数 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    setLogs(prev => [{ id: `LOG-${Date.now()}`, operator: currentUser?.name || '系统', action, detail, timestamp: new Date().toISOString(), undoData, isRevoked: false }, ...prev].slice(0, 100));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = (document.getElementById('login-user') as HTMLInputElement).value;
    const pass = (document.getElementById('login-pass') as HTMLInputElement).value;
    const found = staff.find(s => s.name === user && s.password === pass);
    if (found) { setCurrentUser(found); addLog('登录', found.name); } 
    else alert('登录失败');
  };

  const handleRecharge = (custId: string, amount: number, isSilent = false) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '充值', timestamp: new Date().toISOString() }, ...prev]);
    if (!isSilent) { addLog('充值', `${cust?.name} ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount }); setIsModalOpen(null); }
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string, remarks?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName: itemName || '服务', timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} ${itemName} ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData) return;
    const { type, targetId, secondaryId, amount, prevStatus, paymentMethod } = revokingLog.undoData;
    if (type === 'recharge') {
      setTransactions(prev => prev.filter(t => t.id !== targetId));
      if (secondaryId) setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: Math.max(0, c.balance - (amount || 0)) } : c));
    } else if (type === 'consume') {
      setTransactions(prev => prev.filter(t => t.id !== targetId));
      if (secondaryId && paymentMethod === 'balance') setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance + (amount || 0) } : c));
      if (prevStatus) setAppointments(prev => prev.map(a => a.id === prevStatus ? { ...a, status: 'confirmed' } : a));
    }
    setLogs(prev => prev.map(l => l.id === revokingLog.id ? { ...l, isRevoked: true } : l));
    addLog('撤销', revokingLog.action);
    setRevokingLog(null);
  };

  const handleAiAnalyze = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const result = await analyzeBusinessData({ summary: stats });
      setAiAnalysis(result);
      setIsAiShrunk(false);
    } catch (e) { setAiAnalysis("分析受阻"); } finally { setIsAnalyzing(false); }
  };

  useEffect(() => {
    if (activeTab === 'dashboard' && !aiAnalysis) handleAiAnalyze();
  }, [activeTab]);

  // 排班拖拽
  const handleMouseDown = (e: React.MouseEvent) => {
    if (!scrollContainerRef.current) return;
    setIsDragging(true);
    setStartX(e.pageX - scrollContainerRef.current.offsetLeft);
    setScrollLeft(scrollContainerRef.current.scrollLeft);
  };
  const onMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !scrollContainerRef.current) return;
    e.preventDefault();
    const walk = (e.pageX - scrollContainerRef.current.offsetLeft - startX) * 2;
    scrollContainerRef.current.scrollLeft = scrollLeft - walk;
  };

  // --- Missing Handlers ---

