    const headers = ['单号', '类型', '客户', '金额', '支付方式', '项目', '时间'];
    const csvContent = filteredTransactions.map(t => [
      t.id,
      t.type === 'recharge' ? '充值' : (t.paymentMethod === 'balance' ? '耗卡' : '实收'),
      t.customerName,
      t.amount,
      t.paymentMethod,
      t.itemName,
      new Date(t.timestamp).toLocaleString()
    ]);
    const csvFile = "\uFEFF" + [headers, ...csvContent].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvFile], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `BeautyPro_Finance_${new Date().toLocaleDateString()}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
