               );
            })()}

            {/* 结算耗卡 - 受控组件 */}
            {isModalOpen?.startsWith('consume_') && (
               <div className="space-y-6 text-center">
                  <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mx-auto shadow-inner"><ReceiptText size={24}/></div>
                  <h3 className="text-xl font-black text-slate-900 uppercase">业务结算核销</h3>
                  <div className="p-5 bg-slate-50 rounded-3xl text-left border"><p className="text-[9px] font-black uppercase text-slate-400 mb-1">正在核算客户</p><p className="text-lg font-bold text-slate-800">{customers.find(c=>c.id===isModalOpen.split('_')[1])?.name}</p></div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1 text-left">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-2">结算金额 *</label>
                       <input value={formState.amount} onChange={e=>setFormState({...formState, amount: e.target.value})} type="number" placeholder="¥ 0.00" className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xl text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" />
                    </div>
                    <div className="space-y-1 text-left">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-2">消费项目 *</label>
                       <input value={formState.itemName} onChange={e=>setFormState({...formState, itemName: e.target.value})} placeholder="请输入项目" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" />
                    </div>
                  </div>
                  <div className="space-y-1 text-left">
                     <label className="text-[9px] font-black text-slate-400 uppercase ml-2">内部备注 (选填)</label>
                     <input value={formState.note} onChange={e=>setFormState({...formState, note: e.target.value})} placeholder="添加核销备注" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" />
                  </div>
                  <div className="flex gap-4 pt-4">
                     <button onClick={()=>handleConsume(isModalOpen.split('_')[1], parseInt(formState.amount), formState.itemName, 'balance', isModalOpen.split('_')[3], formState.note)} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">余额扣除</button>
                     <button onClick={()=>handleConsume(isModalOpen.split('_')[1], parseInt(formState.amount), formState.itemName, 'cash', isModalOpen.split('_')[3], formState.note)} className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase shadow-lg hover:bg-black transition-all">现金收款</button>
                  </div>
               </div>
            )}

            {/* 新预约与极速建档 - 受控组件 */}
            {isModalOpen === 'new_appt' && (
               <div className="space-y-6">
                 <h3 className="text-xl font-black text-slate-800 uppercase text-center tracking-widest">排期调度</h3>
                 <div className="flex p-1 bg-slate-100 rounded-2xl">
                    <button onClick={()=>setIsQuickAddCustomer(false)} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${!isQuickAddCustomer?'bg-white shadow-sm text-indigo-600':'text-slate-400'}`}>会员库</button>
                    <button onClick={()=>setIsQuickAddCustomer(true)} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${isQuickAddCustomer?'bg-white shadow-sm text-indigo-600':'text-slate-400'}`}>极速录入</button>
                 </div>
                 <div className="space-y-4">
                    {isQuickAddCustomer ? (
                      <div className="grid grid-cols-2 gap-4">
                        <input value={formState.name} onChange={e=>setFormState({...formState, name: e.target.value})} placeholder="新客姓名 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" />
                        <input value={formState.phone} onChange={e=>setFormState({...formState, phone: e.target.value})} placeholder="手机号 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" />
                        <div className="col-span-2"><input value={formState.amount} onChange={e=>setFormState({...formState, amount: e.target.value})} type="number" placeholder="初始充值 (选填)" className="w-full p-4 bg-indigo-50/50 rounded-2xl font-black text-indigo-600 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                      </div>
                    ) : (
                      <select value={formState.customerId} onChange={e=>setFormState({...formState, customerId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900">{customers.map(c=><option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}</select>
                    )}
                    <div className="grid grid-cols-2 gap-4">
                      <select value={formState.staffId} onChange={e=>setFormState({...formState, staffId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900">{staff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select>
                      <input value={formState.itemName} onChange={e=>setFormState({...formState, itemName: e.target.value})} placeholder="服务项目 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900" />
                    </div>
                 </div>
                 <button onClick={()=>{
                    let cId = formState.customerId, cName = customers.find(c=>c.id===cId)?.name || "";
                    if(isQuickAddCustomer){
                      if(!formState.name || !formState.phone) return alert('补全资料');
                      cId=`C-${Date.now()}`; cName=formState.name;
                      setCustomers(prev=>[...prev,{id:cId, name:cName, phone:formState.phone, balance:0, remarks:'极速录入', createdAt:new Date().toISOString()}]);
                      if(parseInt(formState.amount)>0) handleRecharge(cId, parseInt(formState.amount));
                    }
                    if(cId && formState.staffId && formState.itemName){
                      setAppointments(prev=>[...prev,{id:`APT-${Date.now()}`, customerId:cId, customerName:cName, staffId:formState.staffId, projectName:formState.itemName, startTime:selectedDate.toISOString(), startHour:10, duration:1, status:'pending'}]);
                      setIsModalOpen(null); addLog('新增预约', cName);
                    }
                 }} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg hover:bg-indigo-700 transition-all">发布任务指令</button>
               </div>
            )}

            {selectedAppt && !revokingLog && (
               <div className="space-y-8">
                  <div className="flex justify-between items-start">
                     <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={24}/></div>
                     <span className={`text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${selectedAppt.status==='pending'?'bg-amber-100 text-amber-600':'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-2xl font-black text-slate-900 tracking-tight">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={14}/> 执行技师: <span className="text-slate-800 font-bold">{staff.find(s=>s.id===selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status==='pending' && <button onClick={()=>{setAppointments(prev=>prev.map(a=>a.id===selectedAppt.id?{...a,status:'confirmed'}:a));setSelectedAppt(null);addLog('开始受理',selectedAppt.customerName);}} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg transition-all hover:bg-indigo-700">确认接待</button>}
                     {selectedAppt.status==='confirmed' && <button onClick={()=>{setFormState({...formState, itemName: selectedAppt.projectName, amount: '', note: ''}); setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null);}} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase transition-all hover:bg-black">完工去结算</button>}
                     <button onClick={()=>{if(confirm('作废此预约？')){setAppointments(prev=>prev.filter(a=>a.id!==selectedAppt.id));setSelectedAppt(null);}}} className="w-full py-3 text-red-500 font-bold text-xs uppercase underline">作废该任务单</button>
                  </div>
               </div>
            )}

            {/* 撤销确认 */}
            {revokingLog && (
               <div className="space-y-6 text-center animate-in zoom-in-95">
                  <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center text-red-600 mx-auto"><AlertTriangle size={28}/></div>
                  <div><h3 className="text-xl font-black text-slate-900 mb-2">确认撤销此笔业务？</h3><p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest px-8">撤销后关联的财务金额与任务状态将强制回滚。</p></div>
                  <div className="flex gap-4"><button onClick={()=>setRevokingLog(null)} className="flex-1 py-4 bg-slate-50 rounded-2xl font-black text-xs uppercase text-slate-400 hover:bg-slate-100 transition-all">放弃撤销</button><button onClick={handleRevokeConfirm} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg hover:bg-red-700 transition-all">立即执行</button></div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2, Eye, History as HistoryIcon,
  Minimize2, Maximize2, MousePointer2, MessageSquareText
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班', icon: Calendar },
  { id: 'customers', label: '会员', icon: Users },
  { id: 'finance', label: '流水', icon: History },
  { id: 'staff', label: '员工', icon: ShieldCheck },
  { id: 'logs', label: '日志', icon: Settings },
];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  // Fix: Added activeFinanceFilter state to resolve "Cannot find name 'activeFinanceFilter'" error.
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'consume' | 'recharge'>('all');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"总店长","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isAiShrunk, setIsAiShrunk] = useState(true);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 表单受控状态 (修复文字不显示 Bug) ---
  const [formState, setFormState] = useState<any>({
    name: '', phone: '', remarks: '', amount: '', itemName: '', note: '', password: '', role: '', hour: 10, duration: 1, staffId: ''
  });

  // 拖拽排班表
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  // --- 持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- 统计计算 ---
  const stats = useMemo(() => {
    const todayStr = new Date().toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);
    return {
      todayCash: todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0),
      todayConsumption: todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0),
      monthlyRevenue: transactions.filter(t => new Date(t.timestamp).getMonth() === new Date().getMonth()).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0),
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a,b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date(); d.setDate(d.getDate() - (6 - i));
      const income = transactions.filter(t => new Date(t.timestamp).toDateString() === d.toDateString()).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  // Fix: Added filteredTransactions memoized property to resolve the "Cannot find name 'filteredTransactions'" error.
  const filteredTransactions = useMemo(() => {
    if (activeFinanceFilter === 'all') return transactions;
    if (activeFinanceFilter === 'cash') return transactions.filter(t => t.type === 'consume' && t.paymentMethod !== 'balance');
    if (activeFinanceFilter === 'consume') return transactions.filter(t => t.type === 'consume' && t.paymentMethod === 'balance');
    if (activeFinanceFilter === 'recharge') return transactions.filter(t => t.type === 'recharge');
    return transactions;
  }, [transactions, activeFinanceFilter]);

  // --- 逻辑函数 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    setLogs(prev => [{ id: `LOG-${Date.now()}`, operator: currentUser?.name || '系统', action, detail, timestamp: new Date().toISOString(), undoData, isRevoked: false }, ...prev].slice(0, 100));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = staff.find(s => s.name === formState.loginUser && s.password === formState.loginPass);
    if (found) { setCurrentUser(found); addLog('登录', found.name); } 
    else alert('账号或密码错误');
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '充值', timestamp: new Date().toISOString() }, ...prev]);
    addLog('充值', `${cust?.name} ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string, note?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName: itemName || '项目', timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} ${itemName} ¥${amount}${note ? `(${note})` : ''}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const handleAiAnalyze = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);
    try {
      const result = await analyzeBusinessData({ summary: stats });
      setAiAnalysis(result);
      setIsAiShrunk(false);
    } catch (e) { setAiAnalysis("AI 分析暂时不可用"); } finally { setIsAnalyzing(false); }
  };

  // Fix: Added handleRevokeConfirm function to resolve the "Cannot find name 'handleRevokeConfirm'" error.
  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData) return;
    const { undoData } = revokingLog;

    if (undoData.type === 'recharge') {
      // 撤销充值：删除交易流水，扣除客户余额
      setTransactions(prev => prev.filter(t => t.id !== undoData.targetId));
      setCustomers(prev => prev.map(c => c.id === undoData.secondaryId ? { ...c, balance: Math.max(0, c.balance - (undoData.amount || 0)) } : c));
    } else if (undoData.type === 'consume') {
      // 撤销消费：删除交易流水，如果是余额支付则返还余额，并尝试回滚预约状态
      setTransactions(prev => prev.filter(t => t.id !== undoData.targetId));
      if (undoData.paymentMethod === 'balance') {
        setCustomers(prev => prev.map(c => c.id === undoData.secondaryId ? { ...c, balance: c.balance + (undoData.amount || 0) } : c));
      }
      if (undoData.prevStatus) {
        setAppointments(prev => prev.map(a => a.id === undoData.prevStatus ? { ...a, status: 'confirmed' } : a));
      }
    }

    setLogs(prev => prev.map(l => l.id === revokingLog.id ? { ...l, isRevoked: true } : l));
    addLog('撤销操作', `撤销了: ${revokingLog.action}`);
    setRevokingLog(null);
  };

  // 拖拽逻辑
  const handleMouseDown = (e: React.MouseEvent) => {
    if (!scrollContainerRef.current) return;
    setIsDragging(true);
    setStartX(e.pageX - scrollContainerRef.current.offsetLeft);
    setScrollLeft(scrollContainerRef.current.scrollLeft);
  };
  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !scrollContainerRef.current) return;
    e.preventDefault();
    const walk = (e.pageX - scrollContainerRef.current.offsetLeft - startX) * 2;
    scrollContainerRef.current.scrollLeft = scrollLeft - walk;
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row max-w-4xl w-full">
          <div className="md:w-1/2 bg-indigo-600 p-10 md:p-12 text-white flex flex-col justify-center">
            <h1 className="text-4xl font-black mb-2 tracking-tight">BeautyPro</h1>
            <p className="opacity-70 font-bold mb-8">智慧美业·数字化管理专家</p>
            <div className="space-y-4">
              <div className="flex items-center gap-3"><CheckCircle size={20}/> 智能预约排班</div>
              <div className="flex items-center gap-3"><UserCheck size={20}/> 会员消费轨迹</div>
              <div className="flex items-center gap-3"><History size={20}/> 资金对账看板</div>
            </div>
          </div>
          <div className="md:w-1/2 p-10 md:p-12 bg-white flex flex-col justify-center">
            <h2 className="text-2xl font-black mb-8">职员登录</h2>
            <form onSubmit={handleLogin} className="space-y-6">
              <input value={formState.loginUser || ''} onChange={e=>setFormState({...formState, loginUser: e.target.value})} className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none font-bold text-slate-900" placeholder="账号" />
              <input type="password" value={formState.loginPass || ''} onChange={e=>setFormState({...formState, loginPass: e.target.value})} className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-indigo-500 rounded-2xl outline-none font-bold text-slate-900" placeholder="密码" />
              <button type="submit" className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-black transition-all">确认登录</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden font-sans text-slate-900">
      {/* 侧边栏 (桌面端) */}
      <aside className="hidden md:flex w-20 lg:w-64 bg-white border-r flex-col shrink-0 transition-all duration-300">
        <div className="h-20 flex items-center px-6 border-b">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white mr-3 shadow-lg"><Sparkles size={20} /></div>
          <span className="hidden lg:block font-black text-xl uppercase tracking-tighter">BeautyPro</span>
        </div>
        <nav className="flex-1 py-8 px-4 space-y-2">
          {AVAILABLE_PERMISSIONS.map(item => (
