               const histTrans = transactions.filter(t => t.customerId === custId).sort((a,b)=>new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
               return (
                  <div className="space-y-8">
                     <div className="flex justify-between items-start">
                        <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 text-2xl font-black shadow-inner">{cust.name[0]}</div>
                        <button onClick={()=>setIsModalOpen(null)} className="p-3 bg-slate-50 rounded-xl text-slate-400 hover:text-red-500 transition-all active:scale-90"><X size={18}/></button>
                     </div>
                     <div><h3 className="text-2xl font-black text-slate-900 tracking-tight">{cust.name}</h3><p className="text-slate-400 font-bold mt-1 tracking-widest text-sm italic">{cust.phone}</p></div>
                     <div className="space-y-4 pt-4 border-t">
                        <h4 className="font-black uppercase tracking-widest text-[10px] text-indigo-600 flex items-center gap-2"><HistoryIcon size={14}/> 消费轨迹 ({histTrans.length})</h4>
                        <div className="space-y-2 max-h-64 overflow-y-auto custom-scroll pr-1">
                           {histTrans.length > 0 ? histTrans.map(t=>(
                              <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-2xl flex justify-between items-center text-xs">
                                 <div className="truncate pr-2"><p className="font-bold text-slate-800 truncate">{t.itemName}</p><p className="text-[10px] text-slate-300 font-bold">{new Date(t.timestamp).toLocaleDateString()}</p></div>
                                 <p className={`font-black shrink-0 ${t.type==='recharge'?'text-green-600':'text-slate-900'}`}>{t.type==='recharge'?'+':'-'}¥{t.amount}</p>
                              </div>
                           )) : <p className="text-center py-8 text-slate-300 font-bold italic">暂无流水记录</p>}
                        </div>
                     </div>
                  </div>
               );
            })()}

            {isModalOpen?.startsWith('consume_') && (
               <div className="space-y-6 text-center">
                  <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 mx-auto shadow-inner"><ReceiptText size={24}/></div>
                  <h3 className="text-xl font-black text-slate-900 uppercase tracking-widest">单据结算</h3>
                  <div className="p-5 bg-slate-50 rounded-3xl text-left border"><p className="text-[9px] font-black uppercase text-slate-400 mb-1">正在核算客户</p><p className="text-lg font-bold text-slate-800">{customers.find(c=>c.id===isModalOpen.split('_')[1])?.name}</p></div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1 text-left">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-2">结算金额 (¥) *</label>
                       <input value={formState.amount} onChange={e=>setFormState({...formState, amount: e.target.value})} type="number" placeholder="0.00" className="w-full p-4 bg-slate-50 rounded-2xl font-black text-xl text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" />
                    </div>
                    <div className="space-y-1 text-left">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-2">服务项目 *</label>
                       <input value={formState.itemName} onChange={e=>setFormState({...formState, itemName: e.target.value})} placeholder="例如：首席洗发" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" />
                    </div>
                  </div>
                  <div className="space-y-1 text-left">
                     <label className="text-[9px] font-black text-slate-400 uppercase ml-2">业务备注</label>
                     <input value={formState.note} onChange={e=>setFormState({...formState, note: e.target.value})} placeholder="添加核销备注 (选填)" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm text-slate-900 outline-none border-2 border-transparent focus:border-indigo-400" />
                  </div>
                  <div className="flex gap-4 pt-4">
                     <button onClick={()=>handleConsume(isModalOpen.split('_')[1], parseInt(formState.amount), formState.itemName, 'balance', isModalOpen.split('_')[3])} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg shadow-indigo-100 active:scale-95 transition-all">余额核销</button>
                     <button onClick={()=>handleConsume(isModalOpen.split('_')[1], parseInt(formState.amount), formState.itemName, 'cash', isModalOpen.split('_')[3])} className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase shadow-lg active:scale-95 transition-all">现金收款</button>
                  </div>
               </div>
            )}

            {isModalOpen === 'new_appt' && (
               <div className="space-y-6">
                 <h3 className="text-xl font-black text-slate-800 uppercase text-center tracking-widest">排期调度中心</h3>
                 <div className="flex p-1 bg-slate-100 rounded-2xl">
                    <button onClick={()=>setIsQuickAddCustomer(false)} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${!isQuickAddCustomer?'bg-white shadow-sm text-indigo-600':'text-slate-400'}`}>常客库</button>
                    <button onClick={()=>setIsQuickAddCustomer(true)} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase transition-all ${isQuickAddCustomer?'bg-white shadow-sm text-indigo-600':'text-slate-400'}`}>极速录入</button>
                 </div>
                 <div className="space-y-4">
                    {isQuickAddCustomer ? (
                      <div className="grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
                        <input value={formState.custName} onChange={e=>setFormState({...formState, custName: e.target.value})} placeholder="新客姓名 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm outline-none border-2 border-transparent focus:border-indigo-400 text-slate-900" />
                        <input value={formState.custPhone} onChange={e=>setFormState({...formState, custPhone: e.target.value})} placeholder="联系手机 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm outline-none border-2 border-transparent focus:border-indigo-400 text-slate-900" />
                        <div className="col-span-2"><input value={formState.amount} onChange={e=>setFormState({...formState, amount: e.target.value})} type="number" placeholder="初始充值金额 (选填)" className="w-full p-4 bg-indigo-50/50 rounded-2xl font-black text-indigo-600 border-2 border-transparent focus:border-indigo-400 outline-none" /></div>
                      </div>
                    ) : (
                      <select value={formState.apptCustId} onChange={e=>setFormState({...formState, apptCustId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900">
                        <option value="">选择会员...</option>
                        {customers.map(c=><option key={c.id} value={c.id}>{c.name} ({c.phone})</option>)}
                      </select>
                    )}
                    <div className="grid grid-cols-2 gap-4">
                      <select value={formState.apptStaffId} onChange={e=>setFormState({...formState, apptStaffId: e.target.value})} className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm border-2 border-transparent focus:border-indigo-400 outline-none text-slate-900">
                        {staff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
                      </select>
                      <input value={formState.apptProject} onChange={e=>setFormState({...formState, apptProject: e.target.value})} placeholder="预定项目 *" className="w-full p-4 bg-slate-50 rounded-2xl font-bold text-sm outline-none border-2 border-transparent focus:border-indigo-400 text-slate-900" />
                    </div>
                 </div>
                 <button onClick={()=>{
                    let finalCustId = formState.apptCustId;
                    let finalCustName = customers.find(c=>c.id===finalCustId)?.name || '';
                    if(isQuickAddCustomer){
                      if(!formState.custName || !formState.custPhone) return alert('请补全会员资料');
                      finalCustId=`C-${Date.now()}`; finalCustName=formState.custName;
                      setCustomers(prev=>[...prev,{id:finalCustId, name:finalCustName, phone:formState.custPhone, balance:0, remarks:'极速录入', createdAt:new Date().toISOString()}]);
                      if(parseInt(formState.amount)>0) handleRecharge(finalCustId, parseInt(formState.amount));
                    }
                    if(finalCustId && formState.apptStaffId && formState.apptProject){
                      setAppointments(prev=>[...prev,{id:`APT-${Date.now()}`, customerId:finalCustId, customerName:finalCustName, staffId:formState.apptStaffId, projectName:formState.apptProject, startTime:selectedDate.toISOString(), startHour:10, duration:1, status:'pending'}]);
                      setIsModalOpen(null); addLog('新增预约', finalCustName);
                    }
                 }} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg tracking-widest active:scale-95 transition-all">发布任务指令</button>
               </div>
            )}

            {selectedAppt && !revokingLog && (
               <div className="space-y-8 animate-in fade-in">
                  <div className="flex justify-between items-start">
                     <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 shadow-sm"><Clock size={24}/></div>
                     <span className={`text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${selectedAppt.status==='pending'?'bg-amber-100 text-amber-600':'bg-indigo-100 text-indigo-600'}`}>{selectedAppt.status}</span>
                  </div>
                  <div>
                     <h4 className="text-2xl font-black text-slate-900 tracking-tight">{selectedAppt.customerName}</h4>
                     <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1 italic">{selectedAppt.projectName}</p>
                     <p className="text-xs text-slate-400 mt-4 font-bold flex items-center gap-2"><User size={14}/> 技师: <span className="text-slate-800 font-bold">{staff.find(s=>s.id===selectedAppt.staffId)?.name}</span></p>
                  </div>
                  <div className="space-y-3">
                     {selectedAppt.status==='pending' && <button onClick={()=>{setAppointments(prev=>prev.map(a=>a.id===selectedAppt.id?{...a,status:'confirmed'}:a));setSelectedAppt(null);addLog('开始受理',selectedAppt.customerName);}} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg active:scale-95 transition-all">确认开始受理</button>}
                     {selectedAppt.status==='confirmed' && <button onClick={()=>{setFormState({...formState, itemName: selectedAppt.projectName, amount:''}); setIsModalOpen(`consume_${selectedAppt.customerId}_appt_${selectedAppt.id}`); setSelectedAppt(null);}} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase shadow-lg active:scale-95 transition-all">完工结算指令</button>}
                     <button onClick={()=>{if(confirm('确认作废此预约单？')){setAppointments(prev=>prev.filter(a=>a.id!==selectedAppt.id));setSelectedAppt(null);}}} className="w-full py-3 text-red-500 font-bold text-xs uppercase underline">作废单据</button>
                  </div>
               </div>
            )}

            {!isAiShrunk && (
               <div className="space-y-6 animate-in zoom-in-95">
                  <div className="flex items-center justify-between">
                     <div className="flex items-center gap-2 text-indigo-600"><Sparkles size={20}/><h3 className="text-xl font-black uppercase tracking-widest">智能经营诊断报告</h3></div>
                     <button onClick={()=>setIsAiShrunk(true)} className="p-2 hover:bg-slate-100 rounded-xl transition-all"><Maximize2 size={16}/></button>
                  </div>
                  <div className="bg-slate-50 p-6 rounded-[2rem] border max-h-80 overflow-y-auto custom-scroll">
                     <p className="text-xs leading-relaxed text-slate-600 font-medium whitespace-pre-wrap">{isAnalyzing ? '大数据模型诊断中...' : (aiAnalysis || '点击下方按钮，激活 AI 报告。')}</p>
                  </div>
                  <button onClick={handleAiAnalyze} className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg active:scale-95 transition-all">重新分析数据</button>
               </div>
            )}

            {revokingLog && (
               <div className="space-y-6 text-center animate-in zoom-in-95">
                  <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center text-red-600 mx-auto"><AlertTriangle size={28}/></div>
                  <div><h3 className="text-xl font-black text-slate-900 mb-2">确认撤销流水？</h3><p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest px-8">撤销后对应的财务与预约状态将强制回滚，请谨慎操作。</p></div>
                  <div className="flex gap-4"><button onClick={()=>setRevokingLog(null)} className="flex-1 py-4 bg-slate-50 rounded-2xl font-black text-xs uppercase text-slate-400">放弃</button><button onClick={handleRevokeConfirm} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black text-xs uppercase shadow-lg active:scale-95 transition-all">立即执行</button></div>
               </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell 
} from 'recharts';
import { 
  LayoutDashboard, Calendar, Users, History, Settings, LogOut, Plus, 
  Search, Bell, Trash2, CheckCircle, Smartphone, UserPlus, Sparkles,
  ArrowUpCircle, ArrowDownCircle, CreditCard, Banknote, ShieldCheck,
  ChevronLeft, ChevronRight, Info, UserCheck, X, Filter, PlayCircle, PlusCircle,
  Edit3, Download, UserCircle, ReceiptText, Clock, Wallet, Shield, PlusSquare, ChevronDown, Undo2, AlertTriangle, User, Zap, TrendingUp, UserPlus2, Eye, History as HistoryIcon,
  Minimize2, Maximize2, MousePointer2, MessageSquareText
} from 'lucide-react';
import { Staff, Customer, Appointment, Transaction, SystemLog, Role } from './types';
import { analyzeBusinessData } from './services/geminiService';

const AVAILABLE_PERMISSIONS = [
  { id: 'dashboard', label: '概览', icon: LayoutDashboard },
  { id: 'appts', label: '排班', icon: Calendar },
  { id: 'customers', label: '会员', icon: Users },
  { id: 'finance', label: '流水', icon: History },
  { id: 'staff', label: '员工', icon: ShieldCheck },
  { id: 'logs', label: '日志', icon: Settings },
];

const App: React.FC = () => {
  // --- 核心状态 ---
  const [currentUser, setCurrentUser] = useState<Staff | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [viewMode, setViewMode] = useState<'month' | 'day'>('day');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [searchTerm, setSearchTerm] = useState('');
  const [activeFinanceFilter, setActiveFinanceFilter] = useState<'all' | 'cash' | 'recharge' | 'consume'>('all');

  const [customers, setCustomers] = useState<Customer[]>(JSON.parse(localStorage.getItem('bp_customers') || '[]'));
  const [staff, setStaff] = useState<Staff[]>(JSON.parse(localStorage.getItem('bp_staff') || '[{"id":"1","name":"admin","role":"总店长","avatar":"A","password":"admin","permissions":["all"]}]'));
  const [appointments, setAppointments] = useState<Appointment[]>(JSON.parse(localStorage.getItem('bp_appts') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(JSON.parse(localStorage.getItem('bp_trans') || '[]'));
  const [logs, setLogs] = useState<SystemLog[]>(JSON.parse(localStorage.getItem('bp_logs') || '[]'));

  const [isModalOpen, setIsModalOpen] = useState<string | null>(null);
  const [selectedAppt, setSelectedAppt] = useState<Appointment | null>(null);
  const [editingTarget, setEditingTarget] = useState<Staff | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isAiShrunk, setIsAiShrunk] = useState(true);
  const [isQuickAddCustomer, setIsQuickAddCustomer] = useState(false);
  const [revokingLog, setRevokingLog] = useState<SystemLog | null>(null);
  const [showNotifications, setShowNotifications] = useState(false);
  const notificationRef = useRef<HTMLDivElement>(null);

  // --- 表单受控状态 (统一所有业务输入) ---
  const [formState, setFormState] = useState<any>({
    loginUser: '',
    loginPass: '',
    custName: '',
    custPhone: '',
    custRemarks: '',
    amount: '',
    itemName: '',
    note: '',
    apptCustId: '',
    apptStaffId: '',
    apptProject: '',
    staffName: '',
    staffRole: '',
    staffPass: ''
  });

  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  // --- 持久化 ---
  useEffect(() => {
    localStorage.setItem('bp_customers', JSON.stringify(customers));
    localStorage.setItem('bp_staff', JSON.stringify(staff));
    localStorage.setItem('bp_appts', JSON.stringify(appointments));
    localStorage.setItem('bp_trans', JSON.stringify(transactions));
    localStorage.setItem('bp_logs', JSON.stringify(logs));
  }, [customers, staff, appointments, transactions, logs]);

  // --- 统计计算 ---
  const stats = useMemo(() => {
    const todayStr = new Date().toDateString();
    const todayTrans = transactions.filter(t => new Date(t.timestamp).toDateString() === todayStr);

    const cashIncome = todayTrans.reduce((sum, t) => (t.type === 'consume' && t.paymentMethod !== 'balance') ? sum + t.amount : sum, 0);
    const rechargeIncome = todayTrans.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum, 0);
    const consumption = todayTrans.reduce((sum, t) => t.type === 'consume' && t.paymentMethod === 'balance' ? sum + t.amount : sum, 0);
    const monthlyRevenue = transactions.filter(t => new Date(t.timestamp).getMonth() === new Date().getMonth()).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);

    return {
      todayActual: cashIncome + rechargeIncome,
      todayCash: cashIncome,
      todayRecharge: rechargeIncome,
      todayConsumption: consumption,
      monthlyRevenue,
      totalMembers: customers.length,
      pendingAppts: appointments.filter(a => a.status === 'pending').length,
      todayAppts: appointments.filter(a => new Date(a.startTime).toDateString() === todayStr).length,
      allPendingAppts: appointments.filter(a => a.status === 'pending').sort((a,b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime())
    };
  }, [transactions, customers, appointments]);

  const chartData = useMemo(() => {
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date(); d.setDate(d.getDate() - (6 - i));
      const income = transactions.filter(t => new Date(t.timestamp).toDateString() === d.toDateString()).reduce((sum, t) => (t.type === 'recharge' || (t.type === 'consume' && t.paymentMethod !== 'balance')) ? sum + t.amount : sum, 0);
      return { name: `${d.getMonth() + 1}/${d.getDate()}`, income };
    });
  }, [transactions]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => {
      if (activeFinanceFilter === 'all') return true;
      if (activeFinanceFilter === 'recharge') return t.type === 'recharge';
      if (activeFinanceFilter === 'consume') return t.type === 'consume' && t.paymentMethod === 'balance';
      if (activeFinanceFilter === 'cash') return t.type === 'consume' && t.paymentMethod !== 'balance';
      return true;
    });
  }, [transactions, activeFinanceFilter]);

  // --- 逻辑函数 ---
  const addLog = (action: string, detail: string, undoData?: SystemLog['undoData']) => {
    setLogs(prev => [{ id: `LOG-${Date.now()}`, operator: currentUser?.name || '系统', action, detail, timestamp: new Date().toISOString(), undoData, isRevoked: false }, ...prev].slice(0, 100));
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = staff.find(s => s.name === formState.loginUser && s.password === formState.loginPass);
    if (found) { setCurrentUser(found); addLog('登录', found.name); } 
    else alert('账号或密码错误');
  };

  const handleSaveStaff = () => {
    if (!formState.staffName || !formState.staffRole) return alert('请补全职员资料');
    if (editingTarget) {
      setStaff(prev => prev.map(s => s.id === editingTarget.id ? { 
        ...s, 
        name: formState.staffName, 
        role: formState.staffRole, 
        password: formState.staffPass || s.password,
        avatar: formState.staffName[0]
      } : s));
      addLog('修改职员资料', formState.staffName);
    } else {
      if (!formState.staffPass) return alert('请设置登录密码');
      setStaff(prev => [...prev, {
        id: `STF-${Date.now()}`,
        name: formState.staffName,
        role: formState.staffRole,
        password: formState.staffPass,
        avatar: formState.staffName[0],
        permissions: ['all']
      }]);
      addLog('职员入职', formState.staffName);
    }
    setIsModalOpen(null);
    setEditingTarget(null);
  };

  const handleRecharge = (custId: string, amount: number) => {
    setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance + amount } : c));
    const cust = customers.find(c => c.id === custId);
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'recharge', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: 'cash', itemName: '充值', timestamp: new Date().toISOString() }, ...prev]);
    addLog('充值', `${cust?.name} ¥${amount}`, { type: 'recharge', targetId: transId, secondaryId: custId, amount });
    setIsModalOpen(null);
  };

  const handleConsume = (custId: string, amount: number, itemName: string, method: 'balance' | 'cash', apptId?: string) => {
    const cust = customers.find(c => c.id === custId);
    if (method === 'balance' && (cust?.balance || 0) < amount) { alert('余额不足'); return; }
    if (method === 'balance') setCustomers(prev => prev.map(c => c.id === custId ? { ...c, balance: c.balance - amount } : c));
    const transId = `TRX-${Date.now()}`;
    setTransactions(prev => [{ id: transId, type: 'consume', customerId: custId, customerName: cust?.name || '未知', amount, paymentMethod: method, itemName, timestamp: new Date().toISOString() }, ...prev]);
    if (apptId) setAppointments(prev => prev.map(a => a.id === apptId ? { ...a, status: 'completed' } : a));
    addLog('消费', `${cust?.name} ${itemName} ¥${amount}`, { type: 'consume', targetId: transId, secondaryId: custId, amount, paymentMethod: method, prevStatus: apptId });
    setIsModalOpen(null);
  };

  const handleRevokeConfirm = () => {
    if (!revokingLog || !revokingLog.undoData) return;
    const { type, targetId, secondaryId, amount, prevStatus, paymentMethod } = revokingLog.undoData;
    if (type === 'recharge') {
      setTransactions(prev => prev.filter(t => t.id !== targetId));
      if (secondaryId) setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: Math.max(0, c.balance - (amount || 0)) } : c));
    } else if (type === 'consume') {
      setTransactions(prev => prev.filter(t => t.id !== targetId));
      if (secondaryId && paymentMethod === 'balance') setCustomers(prev => prev.map(c => c.id === secondaryId ? { ...c, balance: c.balance + (amount || 0) } : c));
      if (prevStatus) setAppointments(prev => prev.map(a => a.id === prevStatus ? { ...a, status: 'confirmed' } : a));
    }
